insert into unit_enemy_data values (200100, '长耳猴', 200100, 0, 0, 270, 800, 1, 3.5, 0, 0, 0, '【物理】远距离攻击\\n会投掷巨大的岩石，能从远处\\n进动攻击的猴类魔物。');
insert into unit_enemy_data values (200200, '气球鸟', 200200, 0, 0, 270, 800, 1, 3.0, 0, 0, 0, '【回复】范围回复\\n将腹部积攒的满满魔力\\n变为治愈波动的鸟类魔物。');
insert into unit_enemy_data values (200300, '魔界守门人', 200300, 0, 0, 270, 200, 2, 3.5, 0, 0, 0, '【魔法】范围攻击\\n打开地狱之门，吐出\\n伴随灼伤的火焰的魔界守门人。');
insert into unit_enemy_data values (200400, '狼人', 200400, 0, 0, 270, 350, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n用尖锐的利爪撕碎敌人，\\n狼之魔物。');
insert into unit_enemy_data values (200500, '野性角鹿', 200500, 0, 16, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n用大犄角进行攻击和\\n防御，鹿之魔物。');
insert into unit_enemy_data values (200501, '雪原山羊', 200501, 0, 16, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n住在高山上，厚实的毛皮之下\\n拥有强韧的身体，驯鹿魔物。');
insert into unit_enemy_data values (200503, '野性角鹿', 200503, 0, 16, 750, 580, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (200504, '野性角鹿', 200503, 0, 16, 750, 350, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (200505, '野性角鹿', 200503, 0, 16, 600, 120, 1, 3.0, 0, 0, 0, '');
insert into unit_enemy_data values (200600, '敏捷鼠妖', 200600, 0, 11, 270, 250, 1, 1.5, 0, 0, 0, '【物理】近身攻击\\n虽然威力很小，但会灵活地\\n反复进行攻击，老鼠魔物。');
insert into unit_enemy_data values (200700, '木魂', 200700, 0, 17, 270, 400, 2, 3.0, 0, 0, 0, '【魔法】中距离攻击\\n投掷魔力弹，\\n攻击偏后方的朽木魔物。');
insert into unit_enemy_data values (200701, '岩魂', 200701, 0, 17, 270, 400, 2, 3.0, 0, 0, 0, '【魔法】中距离攻击\\n投掷燃烧的火焰，\\n施加附加灼烧伤害的诅咒石像。');
insert into unit_enemy_data values (200800, '食岩精灵', 200800, 0, 15, 270, 1080, 1, 3.5, 0, 0, 0, '【物理】远距离攻击\\n拥有能够咀嚼岩石的\\n坚硬牙齿的山之精灵。');
insert into unit_enemy_data values (200801, '食冰精灵', 200801, 0, 15, 270, 1080, 1, 3.5, 0, 0, 0, '【物理】远距离攻击\\n将冰块作为武器和\\n食物的雪山精灵。');
insert into unit_enemy_data values (200900, '树妖', 200900, 0, 15, 270, 200, 1, 2.5, 0, 0, 0, '【物理】前卫·近身攻击\\n将柔软的枝条作为\\n鞭子来进行攻击的树之魔物。');
insert into unit_enemy_data values (200901, '蜷旋金合欢', 200901, 0, 15, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n用弯曲盘错的枝条将冒险者\\n引入森林深处的\\n豆科植物的树妖。');
insert into unit_enemy_data values (200902, '树精', 200902, 0, 15, 270, 200, 1, 0.5, 0, 0, 0, '【物理】中距离攻击\\n自由自在地伸展枝杈，用熟练的技巧\\n攻击弱点的朽木魔物。');
insert into unit_enemy_data values (200903, '树精', 200902, 0, 15, 270, 3000, 1, 0.5, 0, 0, 0, '【物理】中距离攻击\\n能自由自在地伸展枝杈，用熟练的技巧\\n攻击弱点的朽木魔物。');
insert into unit_enemy_data values (200904, '树精', 200904, 0, 15, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】中距离攻击\\n自由自在地伸展枝杈，用熟练的技巧\\n攻击弱点的朽木魔物。');
insert into unit_enemy_data values (200905, '树精', 200905, 0, 15, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】中距离攻击\\n自由自在地伸展枝杈，用熟练的技巧\\n攻击弱点的朽木魔物。');
insert into unit_enemy_data values (201000, '狱火骷髅', 201000, 0, 17, 270, 1080, 2, 3.0, 0, 0, 0, '【魔法】中距离攻击\\n地狱之火缠身，\\n袭击生者的怨念集合体。');
insert into unit_enemy_data values (201100, '狗头人', 201100, 0, 15, 270, 650, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n投掷回旋镖似的骨头\\n进行攻击的山犬魔物。');
insert into unit_enemy_data values (201101, '狗头人暗杀者', 201101, 0, 15, 270, 650, 1, 0.5, 0, 0, 0, '【物理】中距离攻击\\n用迅捷的移动玩弄敌人，\\n瞅准转瞬之机射出飞刀的山犬魔物。');
insert into unit_enemy_data values (201200, '魔像', 201200, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】近身攻击\\n用结实的身体\\n进行攻守的岩石魔物。');
insert into unit_enemy_data values (201201, '蓝色魔像', 201201, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防御】近身攻击\\n从蕴藏魔力的岩石中诞生的，\\n具有魔法耐性的石头人。');
insert into unit_enemy_data values (201202, '蓝色魔像', 201202, 0, 16, 270, 150, 1, 5.0, 0, 0, 0, '【物理】【魔法防御】近身攻击\\n从蕴藏魔力的岩石中诞生的，\\n具有魔法耐性的石头人。');
insert into unit_enemy_data values (201300, '岩之花', 201300, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n将小石子当做子弹扔出\\n进行攻击，用岩石做成的会动的花。');
insert into unit_enemy_data values (201301, '狂乱花', 201301, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n尾部的花释放恶臭，\\n但闻惯了似乎会上瘾。');
insert into unit_enemy_data values (201302, '仙人掌花', 201302, 0, 15, 270, 800, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n触碰后，可以无限释放\\n会让人麻痹的针的行走的仙人掌。');
insert into unit_enemy_data values (201400, '雷云长老', 201400, 0, 0, 270, 1080, 2, 3.0, 0, 0, 0, '【魔法】【辅助】范围攻击\\n自由操纵天气，\\n降下落雷的云之魔物。');
insert into unit_enemy_data values (201500, '潜水水母', 201500, 0, 0, 270, 780, 2, 3.0, 0, 0, 0, '【回复】范围回复\\n将捡到的潜水服里装满水，\\n即使在陆地也能战斗的水母魔物。');
insert into unit_enemy_data values (201600, '森林妖精', 201600, 0, 15, 270, 800, 2, 2.5, 0, 0, 0, '【魔法】【召唤】近身攻击\\n利用大地的魔力自由蕴生\\n蘑菇魔物的森之精灵。');
insert into unit_enemy_data values (201602, '宁芙', 201602, 0, 15, 270, 800, 2, 2.5, 0, 0, 0, '【魔法】中距离攻击\\n如果发现了能一起玩耍的目标，\\n就会不分青红皂白地进行恶作剧的林中精灵。');
insert into unit_enemy_data values (201700, '会动的战士雕像', 201700, 0, 16, 270, 150, 1, 4.0, 0, 0, 0, '【物理】【魔法防御】近身攻击\\n拥有防御所有魔法攻击的\\n盾牌，有生命的石像。');
insert into unit_enemy_data values (201800, '会动的剑士雕像', 201800, 0, 5, 270, 150, 1, 4.0, 0, 0, 0, '【物理】【物理防御】近身攻击\\n用剑将所有物理攻击\\n反弹回去，有生命的石像。');
insert into unit_enemy_data values (201900, '毒蝾螈', 201900, 0, 0, 270, 1080, 1, 3.0, 0, 0, 0, '【物理】远距离攻击\\n栖息在泥沼里，\\n口中吐出剧毒的山椒鱼魔物。');
insert into unit_enemy_data values (201901, '熔岩蝾螈', 201901, 0, 0, 270, 1080, 1, 3.0, 0, 0, 0, '【物理】远距离攻击\\n潜居于熔岩之海，对靠近自己的一切\\n吐出灼热的体液的蝾螈魔物。');
insert into unit_enemy_data values (202000, '暴君巨龟', 202000, 0, 16, 270, 150, 1, 5.5, 0, 0, 0, '【物理】【物理防御】近身攻击\\n用甲壳将所有物理攻击\\n弹开的巨龟魔物。');
insert into unit_enemy_data values (202100, '发光蘑菇', 202100, 0, 14, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近身攻击\\n响应树妖的召唤，\\n无限生长的蘑菇精灵。');
insert into unit_enemy_data values (202101, '红菇', 202101, 0, 14, 270, 200, 1, 2.0, 0, 0, 0, '【物理】近身攻击\\n炖煮后意外美味\\n传说中的行走的蘑菇。');
insert into unit_enemy_data values (202200, '垂耳翼兔', 202200, 0, 15, 270, 650, 2, 3.5, 0, 0, 0, '【魔法】近身攻击\\n扇动巨大的耳朵\\n猛地腾空而起的兔子魔物。');
insert into unit_enemy_data values (202300, '火焰法师', 202300, 0, 17, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】远距离攻击\\n用从地狱召唤来的火焰\\n释放魔法的上级恶魔。');
insert into unit_enemy_data values (202400, '洞穴猿人', 202400, 0, 12, 270, 750, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n用强韧的手臂和肌肉抓住\\n钟乳石并扔出的大型猿类魔物。');
insert into unit_enemy_data values (202500, '洞穴蝙蝠', 202500, 0, 15, 270, 550, 2, 3.5, 0, 0, 0, '【魔法】近身攻击\\n栖息在洞窟中，听到猎物的脚步声便\\n发动攻击的蝙蝠魔物。');
insert into unit_enemy_data values (202600, '洞穴蜗牛', 202600, 0, 0, 270, 750, 2, 4.0, 0, 0, 0, '【回复】范围回复\\n分泌出的黏滑液体，据说\\n利于美容，蜗牛魔物。');
insert into unit_enemy_data values (202700, '寄居蟹骑士', 202700, 0, 6, 270, 350, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n用倒下的骑士的头盔\\n替代贝壳扛在身上的寄居蟹战士。');
insert into unit_enemy_data values (202800, '流浪乌鸦', 202800, 0, 4, 270, 650, 1, 3.0, 0, 0, 0, '【物理】范围攻击\\n打倒阿斯特朗里的强大魔物的\\n放浪乌鸦。');
insert into unit_enemy_data values (202802, '候鹰', 202802, 0, 4, 270, 650, 1, 2.6, 0, 0, 0, '【物理】范围攻击\\n憧憬生于荒野、死于荒野\\n的生存方式而进行独自旅行的老鹰。');
insert into unit_enemy_data values (202900, '毒液蜥蜴', 202900, 0, 14, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n用尖锐的獠牙咬噬\\n留下致命伤的毒巨蜥魔物。');
insert into unit_enemy_data values (202901, '岩盔蜥蜴', 202901, 0, 14, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n头部皮肤变硬\\n变得像铠甲一样的岩蜥魔物。');
insert into unit_enemy_data values (202902, '时髦草蜥', 202902, 0, 14, 270, 200, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n叶子围巾十分鲜艳\\n蜥蜴魔物界的时尚达人。');
insert into unit_enemy_data values (202903, '岩盔蜥蜴', 202903, 0, 14, 270, 2050, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n头部皮肤变硬\\n变得像铠甲一样的岩蜥魔物。');
insert into unit_enemy_data values (202904, '火蜥蜴', 202904, 0, 14, 270, 200, 1, 0.5, 0, 0, 0, '【物理】近身攻击\\n通过持续燃烧尾尖的火焰\\n来温暖身体。会发出二连击的\\n蜥蜴魔物。');
insert into unit_enemy_data values (202905, '矿甲蜥蜴', 202905, 0, 14, 270, 100, 1, 3.0, 0, 0, 0, '【物理】近身攻击\\n靠高等食尸兽吃剩的东西果腹的岩蜥蜴。借助露娜的魔力，表皮变成了更加坚固的矿石。');
insert into unit_enemy_data values (203000, '啫喱怪', 203000, 0, 15, 270, 200, 2, 2.0, 0, 0, 0, '【魔法】近身攻击\\n物理攻击很难击中\\n十分黏滑的胶状魔物。');
insert into unit_enemy_data values (203001, '火焰啫喱怪', 203001, 0, 15, 270, 200, 2, 2.0, 0, 0, 0, '【魔法】近身攻击\\n被卷入山火中，身上着火，\\n变得十分凶暴的啫喱怪。');
insert into unit_enemy_data values (203100, '巨蜥幼崽', 203100, 0, 17, 270, 800, 2, 3.5, 0, 0, 0, '【魔法】近身攻击\\n虽然体积小却能吐出强力火焰的\\n小蜥蜴。');
insert into unit_enemy_data values (203200, '淘气恶魔', 203200, 0, 12, 270, 650, 2, 3.5, 0, 0, 0, '【魔法】近身攻击\\n以不符体型的大勾爪\\n进行抓挠攻击的见习恶魔。');
insert into unit_enemy_data values (203300, '持盾哥布林', 203300, 0, 15, 270, 150, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n用与体型等大的巨型盾\\n来保护同伴的见习哥布林。');
insert into unit_enemy_data values (203301, '丛林守护者', 203301, 0, 15, 270, 150, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n用看上去像一张脸的大盾威吓敌人\\n阻挡侵入者的丛林守护人。');
insert into unit_enemy_data values (203302, '持盾哥布林', 203300, 0, 15, 270, 50, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n用与身长相近的巨大盾牌\\n保护同伴的见习哥布林士兵。');
insert into unit_enemy_data values (203400, '鬼灯草虫', 203400, 0, 0, 270, 800, 2, 4.0, 0, 0, 0, '【回复】单体回复\\n屁股上残留的蜜液会成为\\n魔物的营养源，不可思议的萤火虫。');
insert into unit_enemy_data values (203402, '鬼灯草虫', 203400, 0, 0, 270, 3000, 2, 4.0, 0, 0, 0, '【回复】单体回复\\n屁股上残留的蜜液能成为\\n魔物的营养源，是一种不可思议的萤火虫。');
insert into unit_enemy_data values (203500, '钻地鼠', 203500, 0, 16, 270, 750, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n将手从地下伸向地面，从脚边\\n进行攻击的鼹鼠魔物。');
insert into unit_enemy_data values (203501, '冰地鼠', 203501, 0, 16, 270, 750, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n使用发达的利爪敲碎冰块进行攻击的\\n雪鼹鼠魔物。');
insert into unit_enemy_data values (203700, '坚果射手', 203700, 0, 15, 270, 350, 1, 2.5, 0, 0, 0, '【物理】范围攻击\\n将吃剩的坚果壳扔向对方\\n坏心眼的松鼠魔物。');
insert into unit_enemy_data values (203702, '熏天臭鼬', 203702, 0, 15, 270, 350, 1, 2.5, 0, 0, 0, '【物理】范围攻击\\n随心所欲地使用能刺痛眼睛的臭气弹的\\n臭鼬魔物。');
insert into unit_enemy_data values (203703, '熏天臭鼬', 203702, 0, 15, 270, 100, 1, 2.5, 0, 0, 0, '【物理】范围攻击\\n随心所欲地使用能刺痛眼睛的臭气弹的\\n臭鼬魔物。');
insert into unit_enemy_data values (203800, '兽人', 203800, 0, 13, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n身披倒下的冒险者的铠甲\\n挥舞斧头的凶暴森之兽人。');
insert into unit_enemy_data values (203801, '上位兽人', 203801, 0, 13, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n不断进行严苛的锻炼，\\n获得了强韧肉体的上等兽人。');
insert into unit_enemy_data values (203803, '上位兽人', 203801, 0, 13, 270, 300, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n不断进行严苛的锻炼，\\n获得了强韧肉体的上等兽人。');
insert into unit_enemy_data values (203900, '恶魔加农炮', 203900, 0, 16, 270, 1080, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n在长年被使用的过程中\\n寄宿了恶魔的灵魂，有生命的炮台。');
insert into unit_enemy_data values (204000, '幼年狮鹫', 204000, 0, 15, 270, 650, 1, 3.5, 0, 0, 0, '【物理】近身攻击\\n翅膀很小，还暂时无法飞行的\\n狮鹫幼崽。');
insert into unit_enemy_data values (204200, '女低音鸟', 204200, 0, 0, 270, 450, 2, 4.0, 0, 0, 0, '【回复】范围回复\\n治愈的歌声能传到很远的地方\\n鸟类魔物界的知名歌手。');
insert into unit_enemy_data values (204300, '毒食花', 204300, 0, 15, 270, 750, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n用大大张开的嘴里积攒的\\n溶解液来吞噬猎物。');
insert into unit_enemy_data values (204301, '毒食花', 204300, 0, 15, 270, 3000, 1, 2.5, 0, 0, 0, '【物理】近距离攻击\\n会利用大大张开的嘴里积攒的\\n溶解液来吞噬猎物。');
insert into unit_enemy_data values (204400, '小恶魔', 204400, 0, 0, 270, 750, 2, 3.5, 0, 0, 0, '【魔法】中距离攻击\\n用刚学会的魔法随手\\n进行攻击的婴儿恶魔。');
insert into unit_enemy_data values (204500, '锤钳蟹', 204500, 0, 0, 270, 200, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n有着巨大的爪子与坚固的壳，不论面对多高大的对手\\n都会勇往直前的螃蟹魔物。');
insert into unit_enemy_data values (204501, '锤钳蟹', 204501, 0, 0, 270, 50, 1, 2.5, 0, 0, 0, '【物理】近距离攻击\\n有着巨大的爪子与坚固的壳，不论面对多高大的对手\\n都会勇往直前的蟹类魔物。');
insert into unit_enemy_data values (204502, '尖刺大螃蟹', 204502, 0, 0, 270, 80, 1, 2.0, 0, 0, 0, '【物理】近距离攻击\\n以巨大的钳子与坚硬的壳为傲的\\n蟹类魔物。其潜入沙中，耐心等待猎物的模样\\n莫名的有些可爱。');
insert into unit_enemy_data values (204503, '尖刺大螃蟹', 204502, 0, 0, 270, 20, 1, 2.0, 0, 0, 0, '【物理】近距离攻击\\n以巨大的钳子与坚硬的壳为傲的\\n蟹类魔物。其潜入沙中，耐心等待猎物的模样\\n莫名的有些可爱。');
insert into unit_enemy_data values (204600, '魔法魔鬼鱼', 204600, 0, 0, 270, 1080, 2, 3.5, 0, 0, 0, '【魔法】范围攻击\\n用从头部的石头发出的超声波\\n巧妙地进行狩猎的鱼类魔物。');
insert into unit_enemy_data values (204700, '覆叶野猪', 204700, 0, 0, 270, 200, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n将坚硬树叶当做铠甲穿在身上，\\n给予对方剧痛的冲撞的大型野猪。\\n然而，毕竟只是叶子，无法防御魔法。');
insert into unit_enemy_data values (204701, '沙铠野猪', 204701, 0, 0, 270, 200, 1, 4.0, 0, 0, 0, '【物理】近距离攻击\\n身着用沙子强化的盔甲，\\n是不惧丧命的一族的战士的证明。\\n但说到底也只是沙子。无法抵抗魔法。');
insert into unit_enemy_data values (204702, '野猪', 204702, 0, 0, 270, 170, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n生活于热带的原始大野猪。\\n总是不停冲撞熔岩，\\n最终习得了一招连铠甲都能咬碎的獠牙攻击。');
insert into unit_enemy_data values (204800, '废墟人偶', 204800, 0, 0, 270, 150, 1, 1.8, 0, 0, 0, '【物理】近身攻击\\n跟随古代机械兵的古代机器人偶。\\n没有自我意识，会不断战斗，直到自身崩解。');
insert into unit_enemy_data values (204900, '小型哥布林', 204900, 0, 0, 270, 100, 1, 0.5, 0, 0, 0, '【物理】近距离攻击\\n年幼而勇猛的见习哥布林。\\n以灵敏的动作弥补力量的不足，奔走于前线。');
insert into unit_enemy_data values (205000, '剧毒蟾蜍', 205000, 0, 0, 270, 500, 1, 2.5, 0, 0, 0, '【物理】近距离攻击\\n拟态成宝石来欺骗猎物\\n并将其捕食，是有着带毒舌头的蛙类魔物。');
insert into unit_enemy_data values (205001, '剧毒蟾蜍', 205000, 0, 0, 270, 500, 1, 2.5, 0, 0, 0, '【物理】近距离攻击\\n拟态成宝石来欺骗猎物\\n并将其捕食，是有着带毒舌头的蛙类魔物。');
insert into unit_enemy_data values (205100, '槌子蛇', 205100, 0, 13, 270, 550, 1, 2.5, 0, 0, 0, '【物理】中距离攻击\\n会从暗处扑上来，吸取魔力\\n以填满肚子。是魔物蛇的变种。\\n魔力越高则越容易被盯上。');
insert into unit_enemy_data values (205200, '海马骑士', 205200, 0, 0, 270, 650, 1, 2.0, 0, 0, 0, '【物理】中距离攻击\\n夺去在海中溺水的骑士的长矛，\\n警戒地盘的海马战士。');
insert into unit_enemy_data values (205300, '寒冰雏鸟', 205300, 0, 0, 270, 550, 2, 3.0, 0, 0, 0, '【魔法】中距离攻击\\n发射结冰的尾羽\\n进行攻击的鸟类魔物。');
insert into unit_enemy_data values (205400, '寒冰魔鱼', 205400, 0, 12, 270, 550, 1, 2.6, 0, 0, 0, '【物理】近身攻击\\n凿开冰河筑巢，会无差别袭击\\n靠近自己的一切的鱼之魔物。');
insert into unit_enemy_data values (205401, '熔岩魔鱼', 205401, 0, 12, 270, 550, 1, 2.4, 0, 0, 0, '【物理】近身攻击\\n使用足以咬碎岩石的强韧下颚\\n啃食破坏周围一切的鱼之魔物。');
insert into unit_enemy_data values (205500, '陆生魔蛇', 205500, 0, 14, 270, 550, 1, 3.0, 0, 0, 0, '【物理】中距离攻击\\n挖洞静候猎物，\\n用毒牙解决猎物的蛇的魔物。');
insert into unit_enemy_data values (205600, '改造狂犬', 205600, 0, 0, 270, 100, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n与主人一起被创造出来的凶暴的改造犬。\\n拼命想要支撑起硕大的脑袋，所以表情狰狞，显得特别可怕。');
insert into unit_enemy_data values (205700, '波尼', 205700, 0, 15, 270, 50, 1, 0.4, 0, 0, 0, '用于召唤地狱犬的怪物');
insert into unit_enemy_data values (205800, '小雾精前卫', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '用于召唤雾精的怪物（弱）');
insert into unit_enemy_data values (205801, '小雾精中卫', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '用于召唤雾精的怪物（弱）');
insert into unit_enemy_data values (205802, '小雾精后卫', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '用于召唤雾精的怪物（弱）');
insert into unit_enemy_data values (205803, '小雾精前卫', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '用于召唤雾精的怪物（强）');
insert into unit_enemy_data values (205804, '小雾精中卫', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '用于召唤雾精的怪物（强）');
insert into unit_enemy_data values (205805, '小雾精后卫', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '用于召唤雾精的怪物（强）');
insert into unit_enemy_data values (205806, '小雾精前卫', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '雾精召唤的怪物（弱）');
insert into unit_enemy_data values (205807, '小雾精中卫', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '雾精召唤的怪物（弱）');
insert into unit_enemy_data values (205808, '小雾精后卫', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '雾精召唤的怪物（弱）');
insert into unit_enemy_data values (205809, '小雾精前卫', 205800, 0, 0, 270, 50, 1, 1.8, 0, 0, 0, '雾精召唤的怪物（强）');
insert into unit_enemy_data values (205810, '小雾精中卫', 205801, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '雾精召唤的怪物（强）');
insert into unit_enemy_data values (205811, '小雾精后卫', 205802, 0, 0, 270, 200, 1, 1.8, 0, 0, 0, '雾精召唤的怪物（强）');
insert into unit_enemy_data values (205900, '愤怒章鱼', 205900, 0, 0, 270, 200, 0, 2.5, 0, 0, 0, '【物理】中距离攻击\\n怒气冲冲的章鱼魔物。金属质的锚\\n硬度极高，但也很重\\n容易因此失去平衡而翻过来。');
insert into unit_enemy_data values (206000, '北海狮首领', 206000, 0, 1, 270, 100, 1, 4.0, 0, 0, 0, '【物理】近身攻击\\n身体庞大，态度也很傲慢的北海首领。\\n身上的厚重脂肪可以抵御\\n敌人的物理攻击。');
insert into unit_enemy_data values (206100, '魔杖智螺', 206100, 0, 7, 270, 1080, 2, 4.5, 0, 0, 0, '【魔法】远距离攻击\\n拥有冷气之魔法，一旦被吹到就会冻僵，\\n令人丧失战意的鹦鹉螺型魔物。');
insert into unit_enemy_data values (206200, '水獭混混', 206200, 0, 1, 270, 650, 1, 3.5, 0, 0, 0, '【物理】中距离攻击\\n扔出贝壳，趁人不备而攻击，\\n坏心眼的北海小混混。');
insert into unit_enemy_data values (206201, '淘气海狸', 206201, 0, 1, 270, 650, 1, 0.5, 0, 0, 0, '【物理】中距离攻击\\n会在一端把树砍倒的海狸。\\n削下来的木片不仅会被拿去做成房子，\\n还会被制成保护房屋的飞行道具。');
insert into unit_enemy_data values (206300, '露娜支援舱', 206300, 0, 0, 270, 1110, 0, 10.0, 0, 0, 0, '【回复】回复单体技能值\\n建造露娜之塔时一起被制造出来的能量增幅器。\\n将萦绕的魔力浓缩后提供给守护者，使其得到强化。');
insert into unit_enemy_data values (206400, '独眼小佣', 206400, 0, 0, 270, 100, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n侍奉独眼族国王的小仆从。\\n非常喜欢国王陛下赏赐的金灿灿的装备。');
insert into unit_enemy_data values (206500, '长耳猴统帅', 206500, 0, 0, 300, 100, 1, 2.5, 0, 0, 0, '【物理】近身攻击\\n长耳猴进一步成长后的模样。自幼便不断投掷巨大岩石，\\n粗壮的手臂可以使出威力巨大的打击技。');
insert into unit_enemy_data values (206700, '日和莉（新年）的暗影', 206700, 0, 1, 270, 200, 1, 2.295, 0, 0, 0, '拥有日和莉（新年）外貌的特殊魔物\\n\\n·对前方一名敌人造成物理伤害（大），\\n\u3000同时对周围小范围内所有敌人\\n\u3000造成物理伤害（中）。\\n·对前方一名敌人造成物理\\n\u3000伤害（中）。\\n·对前方一名敌人造成物理伤害（小），\\n\u3000并中幅提升自己的物理攻击力。');
insert into unit_enemy_data values (206701, '怜（新年）的暗影', 206701, 0, 4, 270, 400, 1, 1.965, 0, 0, 0, '拥有怜（新年）外貌的特殊魔物\\n\\n·对敌方全体造成物理伤害（中），\\n\u3000并眩晕对象。\\n·【嘲讽】对敌方全体发出嘲讽。\\n\u3000嘲讽后的动作期间受到攻击时，\\n\u3000对范围内的所有敌人造成物理伤害（中），\\n\u3000并小幅降低其物理防御力。\\n·对自己周围的所有同伴\\n\u3000展开魔法免疫屏障，\\n\u3000并中幅提升自己的魔法防御力。');
insert into unit_enemy_data values (206702, '优衣（新年）的暗影', 206702, 0, 7, 270, 600, 2, 2.27, 0, 0, 0, '拥有优衣（新年）外貌的特殊魔物\\n\\n·对己方全体赋予物理/魔法免疫屏障，\\n\u3000及生命值持续回复状态，\\n\u3000但会大幅降低自身魔法攻击力。\\n·大幅降低前方第二个敌人的\\n\u3000物理攻击力和魔法攻击力。\\n·大幅提升所有进行魔法攻击的己方角色的\\n\u3000魔法攻击力。');
insert into unit_enemy_data values (206800, '烦恼屏障1', 206800, 0, 0, 20, 0, 0, 999.0, 0, 0, 0, '暂定');
insert into unit_enemy_data values (206801, '烦恼屏障2', 206801, 0, 0, 20, 0, 0, 999.0, 0, 0, 0, '暂定');
insert into unit_enemy_data values (206802, '烦恼屏障3', 206802, 0, 0, 20, 0, 0, 999.0, 0, 0, 0, '暂定');
