insert into unit_enemy_data values (206804, '定时炸弹年糕', 206803, 0, 0, 0, 1080, 0, 0.0, 0, 0, 0, '暂定');
insert into unit_enemy_data values (206900, '嗜睡猫头鹰', 206900, 0, 0, 270, 645, 2, 3.5, 0, 0, 0, '【魔法】中距离攻击\\n因睡眠不足而有些倦怠的猫头鹰魔物。\\n瞪着敌人，对其施加法术，令对方动弹不得。');
insert into unit_enemy_data values (207000, '淘气豆狸', 207000, 0, 0, 100, 120, 2, 0.5, 0, 0, 0, '【魔法】一定时间内无敌·中距离攻击\\n虽然年幼，但会利用灵巧的变身术\\n拼命兼顾攻守的豆狸魔物。');
insert into unit_enemy_data values (207001, '淘气豆狸', 207000, 0, 0, 100, 120, 2, 0.5, 0, 0, 0, '【魔法】一定时间内无敌·中距离攻击\\n虽然年幼，但会利用灵巧的变身术\\n拼命兼顾攻守的豆狸魔物。');
insert into unit_enemy_data values (207100, '杀人蜂B', 207100, 0, 0, 270, 550, 1, 0.9, 0, 0, 0, '【物理】远距离攻击\\n能迅速察觉到有威胁的敌人，\\n并准确穿刺目标的蜂类魔物。');
insert into unit_enemy_data values (207101, '杀人蜂B', 207100, 0, 0, 270, 650, 1, 1.2, 0, 0, 0, '【物理】远距离攻击\\n能迅速察觉到有威胁的敌人，\\n并准确穿刺目标的蜂类魔物。');
insert into unit_enemy_data values (207102, '杀人蜂B', 207100, 0, 0, 270, 750, 1, 1.5, 0, 0, 0, '【物理】远距离攻击\\n能迅速察觉到有威胁的敌人，\\n并准确穿刺目标的蜂类魔物。');
insert into unit_enemy_data values (207200, '快乐兽人', 207200, 0, 0, 270, 360, 1, 2.5, 0, 0, 0, '【物理】近距离攻击\\n模仿大人敲打乐器，\\n是喜欢恶作剧的兽人孩子。');
insert into unit_enemy_data values (207201, '快乐兽人', 207200, 0, 0, 270, 120, 1, 5.0, 0, 0, 0, '【物理】近距离攻击\\n模仿大人敲打乐器，\\n是喜欢恶作剧的兽人孩子。');
insert into unit_enemy_data values (207300, '洗石熊', 207300, 0, 0, 270, 550, 0, 2.5, 0, 0, 0, '【物理】中距离攻击\\n过于爱干净的浣熊。\\n用特制的蛤蟆油肥皂清洁完后，\\n就会很难握住自己的武器。');
