insert into unit_enemy_data values (209800, '真阳（游骑兵）的暗影', 209800, 0, 6, 450, 395, 1, 2.34, 0, 0, 0, '拥有真阳（游骑兵）外貌的特殊魔物\\n\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000并使其眩晕。\\n·对眼前一名敌人造成物理伤害（小），\\n\u3000并将其小幅度击飞。\\n·对眼前一名敌人造成物理伤害（中），\\n\u3000并小幅度提升自身的物理攻击力。');
