insert into unit_enemy_data values (210512, '爆炸·遗物', 210500, 0, 0, 270, 750, 1, 3.6, 0, 0, 0, '【物理】物理·魔法范围攻击\\n与暗影一同守护圣域，是记忆的守门人。\\n对于想要真正力量的人，会给予相应的试炼。');
insert into unit_enemy_data values (210600, '魔法阵效果', 210600, 0, 0, 0, 2160, 2, 2.0, 0, 0, 0, '');
insert into unit_enemy_data values (300100, '弥诺陶洛斯', 300100, 0, 3, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】获得强大力量的金牛座魔星兽。\\n其战斧的攻击超越了力量的极限，能将一切粉碎。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据弥诺陶洛斯的物理攻击力\\n\u3000造成一定比例的物理伤害。\\n\u3000同时使其陷入烧伤状态，中幅度降低其技能值。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对魔法攻击力最高的一名敌人造成物理伤害\\n\u3000（大），将其击退的同时使其眩晕。\\n\u3000\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方三名角色造成魔法伤害（中），\\n并使其麻痹。');
insert into unit_enemy_data values (300101, '弥诺陶洛斯', 300101, 0, 3, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】获得强大力量的金牛座魔星兽。\\n其战斧的攻击超越了力量的极限，能将一切粉碎。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据弥诺陶洛斯的物理攻击力\\n\u3000造成一定比例的物理伤害。\\n\u3000同时使其陷入烧伤状态，中幅度降低其技能值。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对魔法攻击力最高的一名敌人造成物理伤害（大），\\n\u3000将其击退的同时\\n\u3000使其眩晕。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方三名角色造成魔法伤害（中），\\n并使其麻痹。\\n·中幅度提升自身物理攻击力，大幅度提升\\n\u3000魔法攻击力，对前方第一、第二名角色\\n\u3000造成物理伤害（大）。\\n\u3000技能发动后，小幅度降低自身的物理防御力，\\n\u3000中幅度降低魔法防御力。');
insert into unit_enemy_data values (300102, '弥诺陶洛斯', 300102, 0, 3, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】获得强大力量的金牛座魔星兽。\\n其战斧的攻击超越了力量的极限，能将一切粉碎。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据弥诺陶洛斯的物理攻击力\\n\u3000造成一定比例的物理伤害。\\n\u3000同时使其陷入烧伤状态，中幅度降低其技能值。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对魔法攻击力最高的一名敌人造成物理伤害\\n\u3000（大），将其击退的同时使其眩晕。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方三名角色造成魔法伤害（中），\\n并使其麻痹。\\n·中幅度提升自身物理攻击力，大幅度提升\\n\u3000魔法攻击力，对前方第一、第二名角色\\n\u3000造成物理伤害（大）。\\n\u3000技能发动后，小幅度降低自身的物理防御力，\\n\u3000中幅度降低魔法防御力。\\n·展开战斗领域。\\n\u3000【战斗领域效果】\\n领域整体被火焰包围，并发动\\n以下效果。\\n·无视挑衅，并将物理攻击力或魔法攻击力\\n\u3000最高的一名我方角色的物理攻击力和魔法攻击力\\n\u3000降至0。\\n·特大幅度降低弥诺陶洛斯的物理防御力和\\n\u3000魔法防御力。');
insert into unit_enemy_data values (300200, '利蝎巴鲁托', 300200, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '使用猛毒的尾棘散播灾厄的天蝎座魔星兽。\\n守护沙漠的神虫失去信仰后，变成了邪神。\\n\\n·对敌方全体造成大量物理伤害。\\n\u3000BOSS每次使用必杀技能，\\n\u3000都会提升对敌人造成的伤害。\\n\u3000这个效果最多可以累积三次。\\n·对前方范围内的敌人造成中等物理伤害，\\n\u3000并赋予中毒状态。\\n·解除自身的属性值降低效果，\\n\u3000并提升自己的物理防御力。');
insert into unit_enemy_data values (300201, '利蝎巴鲁托', 300201, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被遗留在失去信仰了的神殿里的天蝎座魔星兽。\\n忘却了曾经获得过的虔诚祈祷，如今将带来毁灭。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（中）。使用此技能后，每次攻击\\n\u3000敌人，利蝎巴鲁托对该名敌人\\n\u3000造成的伤害都会提高。\\n\u3000这个效果最多可以累积3次。\\n·以前方一名角色为中心，对小范围内的敌人\\n\u3000造成物理伤害（中），并使其陷入毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·解除自身的属性值降低效果，\\n\u3000并中幅度提升自身的物理防御力。');
insert into unit_enemy_data values (300202, '利蝎巴鲁托', 300202, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被遗留在失去信仰了的神殿里的天蝎座魔星兽。\\n忘却了曾经获得过的虔诚祈祷，如今将带来毁灭。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（中）。使用此技能后，每次攻击\\n\u3000敌人，利蝎巴鲁托对该名敌人\\n\u3000造成的伤害都会提高。\\n\u3000这个效果最多可以累积3次。\\n·以前方一名角色为中心，对小范围内的敌人\\n\u3000造成物理伤害（中），并使其陷入毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·解除自身的属性值降低效果，\\n\u3000并中幅度提升自身的物理防御力。\\n·召唤1只利蝎守护者。\\n\u3000在召唤时，所有已召唤的利蝎守护者\\n\u3000都将被赋予1秒的无敌状态。\\n·召唤第3只利蝎守护者时，将根据角色的最大生\\n\u3000命值，对敌方全体造成一定比例的魔法伤害，\\n\u3000并使其眩晕。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·当利蝎守护者的生命值低于一定值时，\\n\u3000对利蝎巴鲁托造成魔法固定伤害，\\n\u3000并中幅度降低其物理攻击力，将其消灭。');
insert into unit_enemy_data values (300203, '利蝎巴鲁托', 300203, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被遗留在失去信仰了的神殿里的天蝎座魔星兽。\\n忘却了曾经获得过的虔诚祈祷，如今将带来毁灭。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（中）。使用此技能后，每次攻击\\n\u3000敌人，利蝎巴鲁托对该名敌人\\n\u3000造成的伤害都会提高。\\n\u3000这个效果最多可以累积3次。\\n·以前方一名角色为中心，对小范围内的敌人\\n\u3000造成物理伤害（中），并使其陷入毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·解除自身的属性值降低效果，\\n\u3000并中幅度提升自身的物理防御力。');
insert into unit_enemy_data values (300204, '利蝎巴鲁托', 300204, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被遗留在失去信仰了的神殿里的天蝎座魔星兽。\\n忘却了曾经获得过的虔诚祈祷，如今将带来毁灭。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（中）。使用此技能后，每次攻击\\n\u3000敌人，利蝎巴鲁托对该名敌人\\n\u3000造成的伤害都会提高。\\n\u3000这个效果最多可以累积3次。\\n·以前方一名角色为中心，对小范围内的敌人\\n\u3000造成物理伤害（中），并使其陷入毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·解除自身的属性值降低效果，\\n\u3000并中幅度提升自身的物理防御力。\\n·召唤1只利蝎守护者。\\n\u3000在召唤时，所有已召唤的利蝎守护者\\n\u3000都将被赋予1秒的无敌状态。\\n·召唤第3只利蝎守护者时，将根据角色的最大生\\n\u3000命值，对敌方全体造成一定比例的魔法伤害，\\n\u3000并使其眩晕。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·当利蝎守护者的生命值低于一定值时，\\n\u3000对利蝎巴鲁托造成魔法固定伤害，\\n\u3000并中幅度降低其物理攻击力，将其消灭。');
insert into unit_enemy_data values (300205, '利蝎巴鲁托', 300205, 0, 6, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】被遗留在失去信仰了的神殿里的天蝎座魔星兽。\\n忘却了曾经获得过的虔诚祈祷，如今将带来毁灭。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（中）。使用此技能后，每次攻击\\n\u3000敌人，利蝎巴鲁托对该名敌人\\n\u3000造成的伤害都会提高。\\n\u3000这个效果最多可以累积3次。\\n·以前方一名角色为中心，对小范围内的敌人\\n\u3000造成物理伤害（中），并使其陷入毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·解除自身的属性值降低效果，\\n\u3000并中幅度提升自身的物理防御力。\\n·召唤1只利蝎守护者。\\n\u3000在召唤时，所有已召唤的利蝎守护者\\n\u3000都将被赋予1秒的无敌状态。\\n·召唤第3只利蝎守护者时，将根据角色的最大生\\n\u3000命值，对敌方全体造成一定比例的魔法伤害，\\n\u3000并使其眩晕。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·利蝎守护者将根据角色的\\n\u3000最大生命值，对敌方全体造成一定比例的魔法伤害，\\n\u3000并使其眩晕。\\n·利蝎守护者将中幅提升利蝎巴鲁托的\\n\u3000物理防御力和魔法防御力。\\n·当利蝎守护者的生命值低于一定值时，\\n\u3000对利蝎巴鲁托造成魔法固定伤害，\\n\u3000并中幅度降低其物理攻击力，将其消灭。');
insert into unit_enemy_data values (300300, '梦魇牡羊', 300300, 0, 7, 270, 1000, 2, 2.5, 0, 0, 0, '【魔法】获得强大力量的白羊座魔星兽。\\n在阴暗的沉睡监牢中将冒险者的灵魂吞噬殆尽。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000并对无法行动的敌人\\n\u3000造成一定比例的追加魔法伤害。\\n·对前方范围内的敌人造成魔法伤害（中）。\\n·并使剩余生命值最低的一名敌人陷入束缚状态。');
insert into unit_enemy_data values (300301, '梦魇牡羊', 300301, 0, 7, 270, 1000, 2, 2.5, 0, 0, 0, '【魔法】获得强大力量的白羊座魔星兽。\\n在阴暗的沉睡监牢中将冒险者的灵魂吞噬殆尽。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000并对无法行动的敌人\\n\u3000造成一定比例的追加魔法伤害。\\n·对前方范围内的敌人造成魔法伤害（中）。\\n·并使剩余生命值最低的一名敌人陷入束缚状态。\\n·对敌方全体造成魔法伤害（小）。\\n\u3000角色的生命值低于70％时，\\n\u3000使其陷入束缚状态。');
insert into unit_enemy_data values (300302, '梦魇牡羊', 300302, 0, 7, 270, 1000, 2, 2.5, 0, 0, 0, '【魔法】获得强大力量的白羊座魔星兽。\\n在阴暗的沉睡监牢中将冒险者的灵魂吞噬殆尽。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000同时，对无法行动的敌人\\n\u3000造成一定比例的追加魔法伤害，并大幅度降低其技能值。\\n·对前方范围内的敌人造成魔法伤害（中）。\\n·并使剩余生命值最低的一名敌人陷入束缚状态。\\n·对敌方全体造成魔法伤害（小）。\\n\u3000角色的生命值低于70％时，\\n\u3000使其陷入束缚状态。\\n·使魔法攻击力最高的两名角色陷入束缚状态，\\n\u3000并小幅度降低自身的物理防御力和魔法防御力。');
insert into unit_enemy_data values (300400, '摩羯教主', 300400, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '企图利用可疑邪教支配世界的摩羯座魔星兽。\\n会引诱沙漠里的迷途之人，用恶魔之仪式将其变为俘虏。\\n\\n·必杀技能对敌方全体造成魔法伤害（大）\\n\u3000另外降低物理攻击角色的物理攻击力\\n\u3000降低魔法攻击角色的魔法防御力。\\n·对物理攻击力最高的一名角色造成魔法伤害（特大），\\n\u3000并降低其技能值。\\n·对前方两名敌人造成魔法伤害（小），并\\n\u3000赋予沉默状态。\\n\u3000并对敌方全体造成魔法伤害（中）。');
insert into unit_enemy_data values (300401, '摩羯教主', 300401, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】在邪教秘术的领域登峰造极的摩羯座魔星兽。\\n能随心所欲地操纵其庞大的魔力，剥夺敌人的自由。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000并大幅度降低物理攻击角色的物理攻击力、\\n\u3000魔法攻击角色的魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方一名角色造成魔法伤害（大），\\n并赋予沉默状态。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n·对物理攻击力最高的一名角色造成魔法伤害（大），\\n\u3000并中幅度降低其技能值。');
insert into unit_enemy_data values (300402, '摩羯教主', 300402, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】在邪教秘术的领域登峰造极的摩羯座魔星兽。\\n能随心所欲地操纵其庞大的魔力，剥夺敌人的自由。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000并大幅度降低物理攻击角色的物理攻击力、\\n\u3000魔法攻击角色的魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方一名角色造成魔法伤害（大），\\n并赋予沉默状态。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n·对物理攻击力最高的一名角色造成魔法伤害（大），\\n\u3000并中幅度降低其技能值。\\n·同时对敌方全体造成魔法伤害（大）。\\n\u3000角色的生命值低于80％时，\\n\u3000赋予沉默状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (300403, '摩羯教主', 300403, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】在邪教秘术的领域登峰造极的摩羯座魔星兽。\\n能随心所欲地操纵其庞大的魔力，剥夺敌人的自由。\\n\\n·必杀技能对敌方全体造成魔法伤害（大）\\n\u3000并降低使用物理攻击角色的物理攻击力\\n\u3000降低使用魔法攻击角色的魔法攻击力。\\n·对前方一名敌人造成魔法伤害（特大）\\n\u3000并赋予沉默状态。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n·对物理攻击力最高的一名敌人\\n\u3000造成魔法伤害（大），并降低其技能值。\\n·当摩羯教主获得毒、猛毒、诅咒、烧伤\\n\u3000效果时，赋予自身陷入沉默状态，\\n\u3000并受到魔法伤害（大）。\\n\u3000没有获得上述效果时，则对敌方全体\\n\u3000赋予沉默状态，\\n\u3000并造成魔法伤害（大）。');
insert into unit_enemy_data values (300404, '摩羯教主', 300404, 0, 7, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】在邪教秘术的领域登峰造极的摩羯座魔星兽。\\n能随心所欲地操纵其庞大的魔力，剥夺敌人的自由。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000并大幅度降低物理攻击角色的物理攻击力、\\n\u3000魔法攻击角色的魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方一名角色造成魔法伤害（大），\\n并赋予沉默状态。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n·对物理攻击力最高的一名角色造成魔法伤害（大），\\n\u3000并中幅度降低其技能值。\\n·同时对敌方全体造成魔法伤害（大）。\\n\u3000角色的生命值低于80％时，\\n\u3000赋予沉默状态，并解除属性值提升效果。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (300500, '蜥蜴怪人', 300500, 0, 4, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】自由操纵双刀，\\n用烟雾弹遮蔽\\n对方双眼的\\n巨蜥战士。\\n\\n·随机对一名角色给予\\n\u3000中等物理伤害。\\n\\n·以随机的敌人为中心，给予小范围\\n\u3000低等物理伤害，\\n\u3000并赋予黑暗状态。');
insert into unit_enemy_data values (300600, '攀缘花', 300600, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】从头上释放剧毒攻击\\n并用爬山虎进行范围物理攻击\\n一口气夺去靠近的冒险者体力的\\n恶魔之花。\\n\\n·对前方两名角色给予\\n\u3000中等物理伤害。\\n\\n·降低前方三名角色的物理防御力，\\n\u3000并赋予中毒状态。');
insert into unit_enemy_data values (300601, '针刺攀缘花', 300601, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】受到异常力量影响而变异的攀缘花。\\n使用带有无数尖刺的藤蔓缠绕敌人，令其动弹不得。\\n\\n·对前方范围内的敌人造成中等物理伤害，\\n\u3000并施加束缚状态。\\n·降低前方范围内的敌人的物理防御力，\\n\u3000并施加中毒状态。');
insert into unit_enemy_data values (300602, '针刺攀缘花', 300602, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】受到异常力量影响而变异的攀缘花。\\n使用带有无数尖刺的藤蔓缠绕敌人，令其动弹不得。\\n\\n·连结爆发时，对前方两名角色造成\\n\u3000物理伤害（中），并赋予束缚状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅度降低前方三名角色的物理防御力，\\n\u3000并赋予毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。');
insert into unit_enemy_data values (300603, '针刺攀缘花', 300603, 0, 2, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】受到异常力量影响而变异的攀缘花。\\n使用带有无数尖刺的藤蔓缠绕敌人，令其动弹不得。\\n\\n·连结爆发时，对前方两名角色造成\\n\u3000物理伤害（中），并赋予束缚状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅度降低前方三名角色的物理防御力，\\n\u3000并赋予毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。');
insert into unit_enemy_data values (300700, '兽人首领', 300700, 0, 13, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】身为族长鼓舞群落，\\n用足以粉碎大地的连击\\n给敌人施加大量伤害的\\n顶级兽人。\\n\\n·以随机敌人为中心，\\n\u3000对三名角色造成物理伤害（中），\\n\u3000并提升物理防御力。\\n\\n·提升己方全体的物理攻击力。');
insert into unit_enemy_data values (300701, '兽人头目', 300701, 0, 13, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】受到异常力量影响而变异的兽人首领。\\n用巨大的盾牌发出攻防一体的一击。\\n\\n·连结爆发时，对前方三名角色造成\\n\u3000物理伤害（大），并使其眩晕。\\n·大幅度降低前方两名角色的物理防御力。');
insert into unit_enemy_data values (300702, '兽人头目', 300702, 0, 13, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】受到异常力量影响而变异的兽人首领。\\n用巨大的盾牌发出攻防一体的一击。\\n\\n·连结爆发时，对前方三名角色造成\\n\u3000物理伤害（大），并使其眩晕。\\n·大幅度降低前方两名角色的物理防御力，\\n\u3000并中幅度降低其技能值。');
insert into unit_enemy_data values (300800, '长老角鹿', 300800, 0, 1, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】一旦爆发便无法对付，其嘶吼声据说能传到天际，传说中的狂野角鹿。\\n\\n·对敌方全体造成物理伤害（中），并小幅度击飞。\\n\\n·对前方三名角色造成物理伤害（中），并降低敌人的物理攻击力和物理防御力。');
insert into unit_enemy_data values (300801, '灵魂角鹿', 300801, 0, 1, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】受到异常力量影响而变异的长老角鹿。\\n在犄角中注入魔力，释放比打击更强力的一击。\\n\\n·对前方三名角色造成魔法伤害（大），\\n\u3000将其击退的同时使其眩晕。\\n·对前方三名角色造成魔法伤害（小），\\n并大幅度降低其魔法防御力和行动速度。');
insert into unit_enemy_data values (300802, '灵魂角鹿', 300802, 0, 1, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】受到异常力量影响而变异的长老角鹿。\\n在犄角中注入魔力，释放比打击更强力的一击。\\n\\n·对前方三名角色造成魔法伤害（大），\\n\u3000将其击退的同时使其眩晕。\\n\u3000同时为自身展开物理/魔法无效化\\n\u3000屏障。\\n·对前方三名角色造成魔法伤害（小），\\n并大幅度降低其魔法防御力和行动速度。');
insert into unit_enemy_data values (300900, '暴君寿龟', 300900, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】进化成如岩山般的巨大老龟。\\n强力无比的头槌可以毫不费力地撞碎大地。\\n\\n·连结爆发时，对前方范围造成\\n\u3000物理伤害，并使范围内的敌人陷入麻痹状态。\\n·降低前方三名角色的物理防御力。');
insert into unit_enemy_data values (301000, '海龙', 301000, 0, 14, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】用强大的冰之吐息瞬间将前卫冰封并咬碎其身体的凶猛深海龙。\\n\\n·对前三名敌人造成物理伤害（中）。\\n\\n·对前两名敌人造成物理伤害（中），并赋予冻结状态。');
insert into unit_enemy_data values (301001, '海龙', 301001, 0, 14, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】用强大的冰之吐息瞬间将前卫冰封并咬碎其身体的凶猛深海龙。\\n\\n·对前方三名敌人造成物理伤害（中）。\\n·对前方一名角色造成物理伤害（中），并赋予冻结状态。');
insert into unit_enemy_data values (301002, '海龙', 301002, 0, 14, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】用强大的冰之吐息瞬间将前卫冰封并咬碎其身体的凶猛深海龙。\\n\\n·对前方三名敌人造成物理伤害（中）。\\n·对前方两名角色造成物理伤害（中），并赋予冻结状态。');
insert into unit_enemy_data values (301100, '野蛮魔熊', 301100, 0, 13, 270, 1000, 1, 1.7, 0, 0, 0, '【物理】用不符体格的敏捷与咬噬攻击夺走对方的体力，用巨大的利爪撕裂敌人。残忍的森之统治者。\\n\\n·对前方四名角色造成物理伤害（大）。\\n\\n·对前方一名角色造成物理伤害（小），并降低其物理攻击力。');
insert into unit_enemy_data values (301101, '狂乱魔熊', 301101, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】受到异常力量影响而变异的野蛮魔熊。\\n充满愤怒的臂膀将敌人连同地面一齐撕裂。\\n\\n·对前方三名角色造成物理伤害（大），\\n\u3000并使其眩晕。\\n·以前方第一名敌人为中心，对其小范围内的最多三名敌人\\n\u3000造成物理伤害（大），并特大幅度降低其\\n\u3000物理攻击力，大幅度降低魔法攻击力。');
insert into unit_enemy_data values (301102, '狂乱魔熊', 301102, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】受到异常力量影响而变异的野蛮魔熊。\\n充满愤怒的臂膀将敌人连同地面一齐撕裂。\\n\\n·对前方三名角色造成物理伤害（大），\\n\u3000并使其眩晕。\\n·以前方第一名敌人为中心，对其小范围内的最多三名敌人\\n\u3000造成物理伤害（大），并特大幅度降低其\\n\u3000物理攻击力，大幅度降低魔法攻击力。');
insert into unit_enemy_data values (301200, '巨型魔像', 301200, 0, 13, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】能召唤出无限的魔像，以岩针同时削减敌人的体力与精神。并能以魔力将无数的魔像残骸重构起来的巨大魔像。\\n\\n·对前方四名敌人造成物理伤害（中），并降低其技能值。\\n\\n·召唤魔像。');
insert into unit_enemy_data values (301201, '水晶魔像', 301201, 0, 13, 270, 1000, 1, 1.3, 0, 0, 0, '【物理】以月神魔力的结晶包裹全身的巨大魔像。\\n附着于全身的结晶既如坚实的盾牌，又如可穿刺一切的锐矛。\\n·当水晶魔像获得毒、猛毒、诅咒、烧伤状态时，\\n\u3000行动速度将大幅降低。\\n·解除自身所有的减益效果，\\n\u3000并大幅提升物理防御力与魔法防御力。\\n\u3000此外，中幅提升我方除自身以外同伴的\\n\u3000物理防御力与魔法防御力。\\n·对敌方全体造成物理伤害（中），使其眩晕。\\n·对前方范围内的敌人造成物理伤害（大），\\n\u3000并小幅提升我方全体的\\n\u3000物理攻击力与魔法攻击力。\\n\u3000同时中幅回复自身技能值。');
insert into unit_enemy_data values (301202, '寒冰魔像', 301202, 0, 13, 270, 1000, 1, 1.3, 0, 0, 0, '【物理】潜伏在冰封大地的洞穴里的\\n巨大魔像。附着于全身的结晶\\n既如坚实的盾牌，又如可穿刺一切的锐矛。\\n\\n·寒冰魔像受到毒、猛毒、\\n\u3000诅咒、烧伤效果时，\\n\u3000行动速度大幅度降低。\\n\\n·同时解除自身所有的减益效果，\\n\u3000并中幅度提升物理防御力和\\n\u3000魔法防御力。\\n\\n·对敌方全体造成\\n\u3000物理伤害（中）。\\n\\n·并对前方范围内的敌人造成\\n\u3000物理伤害（大）。');
insert into unit_enemy_data values (301203, '寒冰魔像', 301202, 0, 13, 270, 1000, 1, 1.3, 0, 0, 0, '【物理】潜伏在冰封大地的洞穴里的\\n巨大魔像。附着于全身的结晶\\n既如坚实的盾牌，又如可穿刺一切的锐矛。\\n\\n·寒冰魔像受到毒、猛毒、\\n\u3000诅咒、烧伤效果时，\\n\u3000行动速度大幅度降低。\\n\\n·同时解除自身所有的减益效果，\\n\u3000并中幅度提升物理防御力和\\n\u3000魔法防御力。\\n\\n·对敌方全体造成\\n\u3000物理伤害（中）。\\n\\n·并对前方范围内的敌人造成\\n\u3000物理伤害（大）。');
insert into unit_enemy_data values (301300, '暴食魔兽', 301300, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '天秤座魔星兽是恶名昭彰的暴食凶兽。\\n衡量夺走的灵魂的善恶，喜欢享受其味道的差异。\\n\\n·对来自敌人的攻击而造成的麻痹、眩晕、束缚、\\n\u3000降低行动速度等效果没有抗性。\\n·对敌方全体造成魔法伤害（大），并\\n\u3000特大幅度提升自身的物理攻击力与魔法攻击力。\\n·对后方范围内的敌人造成魔法伤害（中）。\\n·对前方范围内的敌人造成魔法伤害（中），\\n\u3000并小幅降低其技能值。\u3000同时中幅回复\\n\u3000自身技能值。');
insert into unit_enemy_data values (301301, '暴食魔兽', 301301, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】吞噬一切灵魂的天秤座魔星兽。\\n其天秤与严正公平相距甚远，更加倾向于暴食兽的食欲。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（大），\\n\u3000并大幅度提升自身的\\n\u3000物理攻击力和魔法攻击力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对后方两名角色造成魔法伤害（中）。\\n·对前方三名角色造成魔法伤害（小），\\n并小幅度降低其技能值。\\n\u3000同时中幅度提升自身技能值。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。\\n·中央目标处于击破状态时，\\n\u3000魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。');
insert into unit_enemy_data values (301302, '暴食魔兽', 301302, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】吞噬一切灵魂的天秤座魔星兽。\\n其天秤与严正公平相距甚远，更加倾向于暴食兽的食欲。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（大），\\n\u3000并大幅度提升自身的\\n\u3000物理攻击力和魔法攻击力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对后方两名角色造成魔法伤害（中）。\\n·对前方三名角色造成魔法伤害（小），\\n并小幅度降低其技能值。\\n\u3000同时中幅度提升自身技能值。\\n·使前方三名角色陷入束缚状态，并对其造成\\n\u3000魔法伤害（大）。\\n\u3000若自身的目标处于击破状态，\\n\u3000则特大幅度提升自身的魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。\\n·中央目标处于击破状态时，\\n\u3000魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。');
insert into unit_enemy_data values (301303, '暴食魔兽', 301303, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】吞噬一切灵魂的天秤座魔星兽。\\n其天秤与严正公平相距甚远，更加倾向于暴食兽的食欲。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（大），\\n\u3000并大幅度提升自身的\\n\u3000物理攻击力和魔法攻击力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对后方两名角色造成魔法伤害（中）。\\n·对前方三名角色造成魔法伤害（小），\\n并小幅度降低其技能值。\\n\u3000同时中幅度提升自身技能值。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。\\n·中央目标处于击破状态时，\\n\u3000魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。');
insert into unit_enemy_data values (301304, '暴食魔兽', 301304, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】吞噬一切灵魂的天秤座魔星兽。\\n其天秤与严正公平相距甚远，更加倾向于暴食兽的食欲。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（大），\\n\u3000并大幅度提升自身的\\n\u3000物理攻击力和魔法攻击力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对后方两名角色造成魔法伤害（中）。\\n·对前方三名角色造成魔法伤害（小），\\n并小幅度降低其技能值。\\n\u3000同时中幅度提升自身技能值。\\n·使前方三名角色陷入束缚状态，并对其造成\\n\u3000魔法伤害（大）。\\n\u3000若自身的目标处于击破状态，\\n\u3000则特大幅度提升自身的魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。\\n·中央目标处于击破状态时，\\n\u3000魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。');
insert into unit_enemy_data values (301305, '暴食魔兽', 301305, 0, 4, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】吞噬一切灵魂的天秤座魔星兽。\\n其天秤与严正公平相距甚远，更加倾向于暴食兽的食欲。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（大），\\n\u3000并大幅度提升自身的\\n\u3000物理攻击力和魔法攻击力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对后方两名角色造成魔法伤害（中）。\\n·对前方三名角色造成魔法伤害（小），\\n并小幅度降低其技能值。\\n\u3000同时中幅度提升自身技能值。\\n·使前方三名角色陷入束缚状态，并对其造成\\n\u3000魔法伤害（大）。\\n\u3000若自身的目标处于击破状态，\\n\u3000则特大幅度提升自身的魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对敌方全体每秒造成魔法伤害（小）。\\n\u3000若自身的目标没有处于击破状态，\\n\u3000则每秒小幅降低敌方全体的技能值。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。\\n·中央目标处于击破状态时，\\n\u3000魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅降低。');
insert into unit_enemy_data values (301400, '美杜莎', 301400, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '头发由无数毒蛇构成的处女座魔星兽。\\n悲恋的痛苦使其拒绝一切，并将眼前的敌人都变成石头。\\n\\n·对敌方全体造成魔法伤害（大），并对\\n\u3000前方范围内的敌人赋予石化状态。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000大幅降低石化状态敌人的技能值。\\n·对物理攻击力最高的一名敌人造成魔法伤害（大），\\n\u3000并赋予中毒状态。');
insert into unit_enemy_data values (301401, '美杜莎', 301401, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因无止境的爱憎而疯狂的处女座魔星兽。\\n以惊人的嫉妒与抗拒心，让所见的一切全部石化。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并使前方范围内的全部敌人陷入石化状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方范围内的敌人造成物理伤害（大），\\n\u3000如果是无法行动的敌人，则特大幅度降低其技能值。\\n·以后方第两名敌人为中心，对其小范围内的敌人\\n\u3000造成魔法伤害（小），并赋予毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。');
insert into unit_enemy_data values (301402, '美杜莎', 301402, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因无止境的爱憎而疯狂的处女座魔星兽。\\n以惊人的嫉妒与抗拒心，让所见的一切全部石化。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并使前方范围内的全部敌人陷入石化状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方范围内的敌人造成物理伤害（大），\\n\u3000如果是无法行动的敌人，则特大幅度降低其技能值。\\n·以后方第两名敌人为中心，对其小范围内的敌人\\n\u3000造成魔法伤害（小），并赋予毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·以后方第两名敌人为中心，对其小范围内的敌人\\n\u3000造成魔法伤害（小）。\\n\u3000角色的生命值低于60％时，\\n\u3000赋予石化状态。');
insert into unit_enemy_data values (301403, '美杜莎', 301403, 0, 3, 270, 1000, 1, 2.5, 0, 0, 0, '【物理】因无止境的爱憎而疯狂的处女座魔星兽。\\n以惊人的嫉妒与抗拒心，让所见的一切全部石化。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并使前方范围内的全部敌人陷入石化状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方范围内的敌人造成物理伤害（大），\\n\u3000如果是无法行动的敌人，则特大幅度降低其技能值。\\n·以后方第两名敌人为中心，对其小范围内的敌人\\n\u3000造成魔法伤害（小），并赋予毒状态。\\n\u3000该技能所造成的毒伤害\\n\u3000无法回复技能值。\\n·以后方第两名敌人为中心，对其小范围内的敌人\\n\u3000造成魔法伤害（小）。\\n\u3000角色的生命值低于60％时，\\n\u3000赋予石化状态。\\n·召唤一名仆人，并中幅度降低自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000仆人对前方一名角色造成物理伤害（中），\\n\u3000并赋予石化状态。\\n\u3000若仆人的生命值降至0，则对美杜莎\\n\u3000造成物理固定伤害。');
insert into unit_enemy_data values (301500, '魔界人狼', 301500, 0, 12, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以远吠麻痹猎物，趁其畏惧时以爪子撕裂对方。阻断了不计其数的冒险者的去路，是穷凶极恶的魔界之狼。\\n\\n·随机对两名敌人造成物理伤害（大）。\\n\\n·对前方三名敌人造成魔法伤害（小），并赋予麻痹状态。');
insert into unit_enemy_data values (301501, '魔界人狼', 301501, 0, 12, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以远吠威吓猎物，趁其畏惧时以爪子撕裂。\\n顺从自身的欲望，极尽残暴之事的魔狼。\\n\\n·连结爆发时，对前方两名角色造成\\n\u3000物理伤害（大），并中幅度降低其技能值。\\n·根据角色最大生命值，对敌方全体造成\\n\u3000一定比例的魔法伤害，并使物理攻击力最高的两名角色\\n\u3000陷入麻痹状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (301600, '基兹', 301600, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】卷起暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·对敌方全体施加与角色最大生命值对应的\\n\u3000大幅伤害。\\n·\\n\u3000对前方范围内的敌人施加中幅物理伤害，\\n\u3000并令其眩晕。');
insert into unit_enemy_data values (301601, '基兹', 301600, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】卷起暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·给敌方全体施加与角色最大生命值对应的\\n\u3000大幅伤害。\\n·\\n\u3000给前方范围内的敌人施加中等物理伤害，\\n\u3000并令其眩晕。\\n·给前方范围内的敌人施加与角色最大生命值对应的\\n\u3000中幅伤害，降低其物理防御力。\\n·基兹剩余生命值低于50%时\\n\u3000攻击会更加凶猛。');
insert into unit_enemy_data values (301700, '炸脖龙', 301700, 0, 3, 270, 1000, 1, 2.6, 0, 0, 0, '【物理】栖身于毒瘴的暗棱之顶的丑恶狂兽。\\n以猛毒的瘴气杀生于无形，以尸体为食来获取力量。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000魔法伤害（大）并赋予毒状态，同时将其击退。\\n·对前方两名角色造成物理伤害，\\n\u3000并降低其物理攻击力和技能值。\\n·炸脖龙自身剩余的生命值低于40%时，\\n\u3000攻击会变得更为残暴，并召唤\\n\u30003只怪物。\\n·剩余时间少于20秒时，赋予敌方全体\\n\u3000强力的毒状态，并特大幅度降低自身的技能值。');
insert into unit_enemy_data values (301800, '人马射手', 301800, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '射手座的魔星兽，射杀众多翱翔于天空中的目标。\\n身怀绝技，缠绕着雷光的箭可在刹那间穿透一切。\\n\\n·必杀技能根据敌方全体的最大生命值，\\n\u3000造成魔法伤害。\\n\u3000对处于黑暗状态的敌人造成3倍伤害。\\n·对敌方全体造成魔法伤害（中），同时，\\n\u3000对剩余生命值比例最少的一名敌方角色赋予强力的黑暗状态。\\n·对前方的三名敌方角色造成物理伤害。');
insert into unit_enemy_data values (301801, '人马射手', 301801, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】守护星穹神殿的射手座魔星兽。\\n其能够射穿万物的一闪，是紫电闪烁的神域绝技。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000此外，如果敌人处于黑暗状态，\\n\u3000则受到的伤害和魔法攻击力下降量会增加。\\n·对敌方全体造成魔法伤害（小），\\n\u3000并赋予强力的黑暗状态。\\n·对前方三名角色造成物理伤害（中）。');
insert into unit_enemy_data values (301802, '人马射手', 301802, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】守护星穹神殿的射手座魔星兽。\\n其能够射穿万物的一闪，是紫电闪烁的神域绝技。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000此外，如果敌人处于黑暗状态，\\n\u3000则受到的伤害和魔法攻击力下降量会增加。\\n·对敌方全体造成魔法伤害（小），\\n\u3000并赋予强力的黑暗状态。\\n·对前方三名角色造成物理伤害（中）。\\n·对敌方全体造成魔法伤害（中）。\\n\u3000若自身的目标没有处于击破状态，\\n\u3000则在自己的箭矢上增加一颗“黑星”。\\n\u3000当“黑星”的数量为3时，赋予敌方全体\\n\u3000强力的黑暗状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (301803, '人马射手', 301803, 0, 3, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】守护星穹神殿的射手座魔星兽。\\n其能够射穿万物的一闪，是紫电闪烁的神域绝技。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000此外，如果敌人处于黑暗状态，\\n\u3000则受到的伤害和魔法攻击力下降量会增加。\\n·对敌方全体造成魔法伤害（小），\\n\u3000并赋予强力的黑暗状态。\\n·对前方三名角色造成物理伤害（中）。\\n·对敌方全体造成魔法伤害（中）。\\n\u3000若自身的目标没有处于击破状态，\\n\u3000则在自己的箭矢上增加一颗“黑星”。\\n\u3000当“黑星”的数量为3时，赋予敌方全体\\n\u3000强力的黑暗状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (301900, '虎鲸猎手', 301900, 0, 11, 270, 1000, 1, 1.7, 0, 0, 0, '【物理】用敏锐的眼神搜寻\\n猎物与海浪的海之猎手。\\n用魔力产生无限的潮水\\n削弱敌人的武器与气力。 \\n\\n·对前方四名角色造成少量物理伤害\\n\u3000并降低物理攻击力。\\n\\n·对前方两名角色造成少量魔法伤害\\n\u3000并削减其技能值。');
insert into unit_enemy_data values (301901, '鲸王猎手', 301901, 0, 11, 270, 1000, 1, 1.5, 0, 0, 0, '【物理】因月神魔力而变得凶恶的大海猎手。\\n其千锤百炼的身体能将水流化为刀刃进行攻击。\\n\\n·对前方四名敌人造成物理伤害（大）\\n\u3000并中幅降低其物理攻击力。同时，\\n\u3000小幅提升我方全体的技能值。\\n·对前方小范围的敌方造成魔法伤害（中），\\n\u3000并大幅降低其技能值。\\n·以后方第二名敌人为中心，造成\\n\u3000小范围的物理伤害（中），\\n\u3000并大幅降低其魔法攻击力。');
insert into unit_enemy_data values (302000, '野性狮鹫', 302000, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '在残酷环境中成长进化的狮鹫。\\n使用龙卷风将猎物卷起到空中进行狩猎。\\n\\n·对前方范围内的敌人造成魔法伤害（中）。');
insert into unit_enemy_data values (302001, '野性狮鹫', 302001, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '在残酷环境中成长进化的狮鹫。\\n使用龙卷风将猎物卷起到空中进行狩猎。\\n\\n·对前方范围内的敌人造成魔法伤害（中）。');
insert into unit_enemy_data values (302002, '野性狮鹫', 302002, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】在严酷的环境中进化而来的小型狮鹫。\\n能以龙卷风卷起猎物，在空中进行狩猎。\\n\\n·对前方三名角色造成魔法伤害（中），\\n\u3000并将其击退。\\n\u3000角色的生命值低于40％时，\\n\u3000赋予眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (302100, '双足飞龙', 302100, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '张开巨大的飞翼翱翔天空的翼龙。\\n能够喷射巨大的火球，阻挡侵入者。\\n\\n·对前方范围内的敌人造成中等物理伤害。');
insert into unit_enemy_data values (302101, '双足飞龙', 302101, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '张开巨大的飞翼翱翔天空的翼龙。\\n能够喷射巨大的火球，阻挡侵入者。\\n\\n·对前方范围内的敌人造成中等物理伤害。');
insert into unit_enemy_data values (302102, '双足飞龙', 302102, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】利用巨大的皮翼在空中飞行的翼龙。\\n吐出巨大的火球会阻挡入侵者的去路。\\n·以前方第一名敌人为中心，对其小范围内的三名敌人\\n\u3000造成物理伤害（中）。');
insert into unit_enemy_data values (302200, '依科托·格拉迪恩', 302200, 0, 16, 270, 1000, 2, 1.6, 0, 0, 0, '【魔法】借由露娜魔力而觉醒的古代机械兵器。\\n毫不留情地释放出魔力来阻止入侵者。\\n\\n·对敌方全体造成特大魔法伤害\\n\u3000并大幅度降低敌人的魔法防御力。\\n·对前方范围内的敌人造成大量物理伤害\\n·对前方范围内的敌人造成大量魔法伤害\\n\u3000并赋予麻痹状态。');
insert into unit_enemy_data values (302300, '聪慧猫头鹰', 302300, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】栖身于大树之顶的聪明巨鸟。\\n凝聚了森林万物的智慧，能巧妙地操纵魔法。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000魔法伤害。\\n·随机对一名角色造成物理伤害，\\n\u3000并使其陷入麻痹状态。');
insert into unit_enemy_data values (302400, '方舟守护者', 302400, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】自古以来一直保护着遗迹的人工生命体。\\n通过造物主的秘术，拥有可一直运转的无限动力。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000魔法伤害（大）。\\n·对前方范围内的敌人造成物理伤害。\\n·对敌方全体造成魔法伤害，\\n\u3000并使其沉默。');
insert into unit_enemy_data values (302500, '奇美拉', 302500, 0, 16, 270, 1000, 1, 1.4, 0, 0, 0, '【物理】镇坐孤塔之顶的暴虐混种魔兽。\\n以千变万化的猛攻，屠戮过众多挑战者。\\n\\n·连结爆发时，对前方范围内的敌人造成\\n\u3000物理伤害（大），并将其击退。\\n\\n·对前方三名角色造成物理伤害，\\n\u3000并使其陷入烧伤状态。\\n·对敌方全体造成魔法伤害，\\n\u3000并降低其行动速度、物理防御力和魔法防御力。\\n·剩余时间少于10秒时，对敌方全体\\n\u3000造成魔法伤害（极大），并特大幅度降低自身的技能值。');
insert into unit_enemy_data values (302600, '双子魔猪', 302600, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】获得强大力量的双子座魔星兽。\\n一边在前方防御，一边以登峰造极的招数进行攻击。\\n\\n·根据角色的最大生命值，对敌方全体造成物理伤害（大）。\\n·对后方两名角色造成物理伤害（中），\\n并降低其行动速度。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (302601, '双子魔猪', 302601, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】获得强大力量的双子座魔星兽。\\n一边在前方防御，一边以登峰造极的招数进行攻击。\\n\\n·根据角色的最大生命值，对敌方全体造成物理伤害（大）。\\n·对后方两名角色造成物理伤害（中），\\n并降低其行动速度。\\n·对敌方全体造成物理伤害（中）。\\n·暴食中，特大幅度降低自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000随后特大幅度提升自身的技能值上升量和物理暴击率，\\n\u3000并对敌方全体造成物理伤害（大）。');
insert into unit_enemy_data values (302602, '双子魔猪', 302602, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】获得强大力量的双子座魔星兽。\\n一边在前方防御，一边以登峰造极的招数进行攻击。\\n\\n·根据角色的最大生命值，对敌方全体造成物理伤害（大）。\\n·对后方两名角色造成物理伤害（中），\\n并降低其行动速度。\\n·对敌方全体造成物理伤害（中）。\\n·暴食中，特大幅度降低自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000随后特大幅度提升自身的技能值上升量和物理暴击率，\\n\u3000并对敌方全体造成物理伤害（大）。\\n·烹调中，特大幅度降低自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000随后每秒小幅度降低敌方全体的技能值。');
insert into unit_enemy_data values (302700, '巨钳魔蟹', 302700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在船墓的入海口筑巢的巨蟹座魔星兽。\\n其巨大钳子造成的一击，击沉过无数船只。\\n\\n·对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力。\\n·对前方范围内的所有敌人造成物理伤害（中）\\n\u3000并赋予眩晕状态。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (302701, '巨钳魔蟹', 302701, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】击沉过无数船只的巨蟹座魔星兽。\\n大海的霸者可斩断、压垮、歼灭万物。\\n·对敌方全体造成魔法伤害（大），\\n\u3000并小幅度降低其魔法防御力。\\n·以前方第一名敌人为中心，对其小范围内的所有敌人\\n\u3000造成物理伤害（中），\\n\u3000并使其眩晕。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (302702, '巨钳魔蟹', 302702, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】击沉过无数船只的巨蟹座魔星兽。\\n大海的霸者可斩断、压垮、歼灭万物。\\n·对敌方全体造成魔法伤害（大），\\n\u3000并小幅度降低其魔法防御力。\\n·以前方第一名敌人为中心，对其小范围内的所有敌人\\n\u3000造成物理伤害（中），\\n\u3000并使其眩晕。\\n·对敌方全体造成物理伤害（中）。\\n·在一定时间内改变形态，特大幅度提升自身的魔法攻击力\\n\u3000和行动速度，并把所有技能\\n\u3000转变为魔法攻击。\\n\u3000在此期间，特大幅度降低自身的物理防御力\\n和魔法防御力。');
insert into unit_enemy_data values (302703, '巨钳魔蟹', 302703, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】击沉过无数船只的巨蟹座魔星兽。\\n大海的霸者可斩断、压垮、歼灭万物。\\n·对敌方全体造成魔法伤害（大），\\n\u3000并小幅度降低其魔法防御力。\\n\u3000此技能的攻击对象越多，\\n\u3000造成的伤害则越大。\\n·以前方第一名敌人为中心，对其小范围内的所有敌人\\n\u3000造成物理伤害（中），\\n\u3000并使其眩晕。\\n·对敌方全体造成物理伤害（中）。\\n·在一定时间内改变形态，特大幅度提升自身的魔法攻击力、\\n\u3000魔法暴击和行动速度，并把所有技能\\n\u3000转变为魔法攻击。\\n\u3000在此期间，特大幅度降低自身的物理防御力\\n和魔法防御力。');
insert into unit_enemy_data values (302800, '炎吼狮王', 302800, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '以草原霸主闻名四方的狮子座魔星兽。\\n灼热的咆哮能够燃尽一切向其举起刀刃的敌人。\\n\\n·无视防御力，对敌方全体造成与其最大生命值相应的\\n\u3000物理伤害（大），并对剩余生命值较低的敌人\\n\u3000赋予烧伤状态。\\n·对一名敌人造成物理伤害（大），\\n\u3000当目标处于烧伤状态时，追加伤害。\\n·对前方范围内的敌人造成物理伤害（中），\u3000当目标处于烧伤状态时，追加伤害。');
insert into unit_enemy_data values (302801, '炎吼狮王', 302801, 0, 16, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】君临于荒凉原野上的狮子座魔星兽。\\n其利爪可切裂空气，喷出业火的咆哮可烧灼大地。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n\u3000角色的生命值低于80％时，\\n\u3000赋予烧伤状态。\\n\u3000该技能所造成的烧伤伤害\\n\u3000无法回复技能值。\\n·对前方一名敌人造成物理伤害（大）。\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n·对前方范围内的敌人造成物理伤害（大）。\\n\u3000若处于烧伤状态，则赋予追加伤害。');
insert into unit_enemy_data values (302802, '炎吼狮王', 302802, 0, 16, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】君临于荒凉原野上的狮子座魔星兽。\\n其利爪可切裂空气，喷出业火的咆哮可烧灼大地。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n\u3000角色的生命值低于80％时，\\n\u3000赋予烧伤状态。\\n\u3000该技能所造成的烧伤伤害\\n\u3000无法回复技能值。\\n·对前方一名敌人造成物理伤害（大）。\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n·对前方范围内的敌人造成物理伤害（大）。\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的魔法伤害，并使其眩晕。\\n\u3000角色的生命值低于40％时，\\n\u3000使其陷入长时间的眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (302803, '炎吼狮王', 302803, 0, 16, 270, 1000, 1, 3.0, 0, 0, 0, '【物理】君临于荒凉原野上的狮子座魔星兽。\\n其利爪可切裂空气，喷出业火的咆哮可烧灼大地。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n\u3000角色的生命值低于80％时，\\n\u3000赋予烧伤状态。\\n\u3000该技能所造成的烧伤伤害\\n\u3000无法回复技能值。\\n·对前方一名敌人造成物理伤害（大）。\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n·对前方范围内的敌人造成物理伤害（大）。\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的魔法伤害，并使其眩晕。\\n\u3000角色的生命值低于40％时，\\n\u3000使其陷入长时间的眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对后方一名角色造成魔法伤害（中），\\n将其抛起再拉近，并使其眩晕。');
insert into unit_enemy_data values (302900, '阿克艾利欧斯', 302900, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '被寄宿在神瓶中的魔力所吸收的水瓶座魔星兽。\\n沉溺于强大的力量，为了支配大海而肆虐。\\n\\n·必杀技能对敌方全体造成共计6次的\\n\u3000魔法伤害（小）。\\n\u3000当角色的生命值低于80%时造成击退效果，\\n\u3000当低于40%时进一步击退并\\n\u3000赋予眩晕状态。\\n·对眼前的三名敌方角色造成物理伤害（中）。\\n·解除自身的属性值降低效果和敌方全体的\\n\u3000属性值提升效果，并提升自身的技能值。');
insert into unit_enemy_data values (302901, '阿克艾利欧斯', 302901, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操纵着寄宿在神瓶中魔力的水瓶座魔星兽。\\n喷射的激流可吞没万物，它作为苍海支配者统治着一切。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000若角色的生命值在80％以下，则将其击退，\\n\u3000若在50%以下，则增加击退强度，\\n\u3000并赋予眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·解除敌方全体的属性值提升效果，\\n\u3000并小幅度提升自身的技能值、物理防御力和魔法防御力。\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000对前方第二、第三名角色造成物理伤害（大）。');
insert into unit_enemy_data values (302902, '阿克艾利欧斯', 302902, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操纵着寄宿在神瓶中魔力的水瓶座魔星兽。\\n喷射的激流可吞没万物，它作为苍海支配者统治着一切。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000若角色的生命值在80％以下，则将其击退，\\n\u3000若在50%以下，则增加击退强度，\\n\u3000并赋予眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·解除敌方全体的属性值提升效果，\\n\u3000并小幅度提升自身的技能值、物理防御力和魔法防御力。\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000对前方第二、第三名角色造成物理伤害（大）。\\n\u3000【战斗领域效果】\\n经过一段时间后，产生激流。\\n·对队伍全体持续造成魔法伤害（小）。\\n\u3000角色的生命值低于80％时，\\n\u3000将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\u3000若阿克艾利欧斯的目标处于击破状态，\\n\u3000则小幅度降低阿克艾利欧斯的技能值。\\n\u3000若阿克艾利欧斯的目标没有处于击破状态，\\n\u3000则小幅度提升阿克艾利欧斯的\\n\u3000物理防御力和魔法防御力。');
insert into unit_enemy_data values (302903, '阿克艾利欧斯', 302903, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操纵着寄宿在神瓶中魔力的水瓶座魔星兽。\\n喷射的激流可吞没万物，它作为苍海支配者统治着一切。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000若角色的生命值在80％以下，则将其击退，\\n\u3000若在50%以下，则增加击退强度，\\n\u3000并赋予眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·解除敌方全体的属性值提升效果，\\n\u3000并小幅度提升自身的技能值、物理防御力和魔法防御力。\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000对前方第二、第三名角色造成物理伤害（大）。\\n\u3000【战斗领域效果】\\n经过一段时间后，产生激流。\\n·对队伍全体持续造成魔法伤害（小）。\\n\u3000角色的生命值低于80％时，\\n\u3000将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\u3000若阿克艾利欧斯的目标处于击破状态，\\n\u3000则小幅度降低阿克艾利欧斯的技能值。\\n\u3000若阿克艾利欧斯的目标没有处于击破状态，\\n\u3000则小幅度提升阿克艾利欧斯的\\n\u3000物理防御力和魔法防御力。');
insert into unit_enemy_data values (302904, '阿克艾利欧斯', 302904, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】操纵着寄宿在神瓶中魔力的水瓶座魔星兽。\\n喷射的激流可吞没万物，它作为苍海支配者统治着一切。\\n\\n·连结爆发时，根据角色最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\u3000若角色的生命值在80％以下，则将其击退，\\n\u3000若在50%以下，则增加击退强度，\\n\u3000并赋予眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·解除敌方全体的属性值提升效果，\\n\u3000并小幅度提升自身的技能值、物理防御力和魔法防御力。\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000对前方第二、第三名角色造成物理伤害（大）。\\n\u3000【战斗领域效果】\\n经过一段时间后，产生激流。\\n·对队伍全体持续造成魔法伤害（小）。\\n\u3000角色的生命值低于80％时，\\n\u3000将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\u3000若阿克艾利欧斯的目标处于击破状态，\\n\u3000则小幅度降低阿克艾利欧斯的技能值。\\n\u3000若阿克艾利欧斯的目标没有处于击破状态，\\n\u3000则小幅度提升阿克艾利欧斯的\\n\u3000物理防御力和魔法防御力。');
insert into unit_enemy_data values (303000, '托尔佩顿', 303000, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '在沧海间遨游，唤来暴风雨的双鱼座魔星兽。\\n围在身边的手下们那红色鱼鳍正是不服来战的高傲证明。\\n\\n·容易受到物理攻击力提升·下降\\n\u3000的效果。\\n·必杀技能对敌方全体造成物理伤害（大）\\n\u3000并提升自身的行动速度\\n\u3000与物理攻击力。\\n·对敌方全体造成物理伤害（小）。\\n·对前方两名敌人造成物理伤害（中）\\n\u3000并小幅降低其物理防御力。');
insert into unit_enemy_data values (303001, '托尔佩顿', 303001, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背负着整片大海命运的暴走双鱼座魔星兽。\\n被那背影打动的小弟们，都自愿与其共同追求霸道。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据托尔佩顿的物理攻击力，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n\u3000同时中幅度提升自身的行动速度和\\n\u3000物理攻击力。\\n·对敌方全体造成物理伤害（小）。\\n·对前方两名角色造成物理伤害（中），\\n并小幅度降低其物理防御力。');
insert into unit_enemy_data values (303002, '托尔佩顿', 303002, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背负着整片大海命运的暴走双鱼座魔星兽。\\n被那背影打动的小弟们，都自愿与其共同追求霸道。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据托尔佩顿的物理攻击力，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n\u3000同时中幅度提升自身的行动速度和\\n\u3000物理攻击力。\\n·对敌方全体造成物理伤害（小）。\\n·对前方两名角色造成物理伤害（中），\\n并小幅度降低其物理防御力。\\n·召唤1只旗手小弟。\\n\u3000旗手小弟可以回复托尔佩顿的技能值。\\n·当旗手小弟的生命值低于一定值时，\\n\u3000中幅度提升队伍全体的物理攻击力\\n\u3000和魔法攻击力。');
insert into unit_enemy_data values (303003, '托尔佩顿', 303003, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背负着整片大海命运的暴走双鱼座魔星兽。\\n被那背影打动的小弟们，都自愿与其共同追求霸道。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据托尔佩顿的物理攻击力，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n\u3000同时中幅度提升自身的行动速度和\\n\u3000物理攻击力。\\n·对敌方全体造成物理伤害（小）。\\n·对前方两名角色造成物理伤害（中），\\n并小幅度降低其物理防御力。\\n·召唤1只旗手小弟。\\n\u3000旗手小弟可以回复托尔佩顿的技能值。\\n·当旗手小弟的生命值低于一定值时，\\n\u3000中幅度提升队伍全体的物理攻击力\\n\u3000和魔法攻击力。');
insert into unit_enemy_data values (303004, '托尔佩顿', 303002, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】背负着整片大海命运的暴走双鱼座魔星兽。\\n被那背影打动的小弟们，都自愿与其共同追求霸道。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n\\n·连结爆发时，解除敌方全体的屏障，\\n\u3000并根据托尔佩顿的物理攻击力，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n\u3000同时中幅度提升自身的行动速度和\\n\u3000物理攻击力。\\n·对敌方全体造成物理伤害（小）。\\n·对前方两名角色造成物理伤害（中），\\n并小幅度降低其物理防御力。\\n·召唤1只旗手小弟。\\n\u3000旗手小弟可以回复托尔佩顿的技能值。\\n·当旗手小弟的生命值低于一定值时，\\n\u3000中幅度提升队伍全体的物理攻击力\\n\u3000和魔法攻击力。');
insert into unit_enemy_data values (303100, '冬眠魔熊', 303100, 0, 13, 270, 1000, 1, 3.5, 0, 0, 0, '【物理】终生藏身在冰穴最深处冬眠的巨熊。在睡梦中度过了十分漫长的岁月，却会在狩猎猎物的瞬间醒来。\\n\\n·对敌方全体造成魔法伤害（大），并降低物理攻击力。\\n\\n·对前方三名角色造成物理伤害（小）。同时，大幅度击飞前方一名角色，并赋予冻结状态，使其移动速度下降。');
insert into unit_enemy_data values (303200, '冰雪夫人', 303200, 0, 6, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】与暴风雪一同出现，\\n召唤大军袭击扰乱地盘的人。\\n雪国第一华美夫人。\\n\\n·对前方四名角色造成魔法伤害（中）。\\n\\n·对随机两名角色造成魔法伤害（小）\\n\u3000并赋予冻结状态。');
insert into unit_enemy_data values (303300, '滴水嘴兽', 303300, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】留在腐朽的遗迹保护无主之地的神秘鸟型石像。如今街道和命令都消失成沙，不管是谁它都会喷出火焰袭击对方。\\n\\n·对前方5名角色造成魔法伤害（中），并赋予烧伤状态。同时降低敌人的魔法防御力。\\n\\n·对随机三名角色造成魔法伤害（小），并赋予黑暗状态。');
insert into unit_enemy_data values (303301, '暗黑滴水嘴兽', 303301, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】侍奉着暴食君主的近卫黑铁像。\\n徘徊于冥府，巧妙地操纵灵魂并将其奉献给主人。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（中），\\n\u3000并赋予烧伤状态，同时中幅度降低\\n\u3000其魔法防御力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对敌方全体造成魔法伤害（中），大幅度降低\\n\u3000物理攻击力，中幅度降低魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (303302, '暗黑滴水嘴兽', 303302, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】侍奉着暴食君主的近卫黑铁像。\\n徘徊于冥府，巧妙地操纵灵魂并将其奉献给主人。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（中），\\n\u3000并赋予烧伤状态，同时中幅度降低\\n\u3000其魔法防御力。\\n\u3000该技能造成的伤害\\n\u3000无法回复敌人的技能值。\\n·对敌方全体造成魔法伤害（中），并中幅度降低\\n\u3000其物理攻击力和魔法攻击力。\\n\u3000角色的生命值低于80％时，\\n\u3000将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (303303, '沙岩滴水嘴兽', 303303, 0, 13, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】散发着塔的魔力，寄宿着生命的沙岩像魔物。\\n在飞扬的尘土中守株待兔，口吐灼焰袭击敌人。\\n\\n·对前方范围内的敌人造成魔法伤害（大），\\n\u3000并使其陷入烧伤状态。同时中幅度降低其魔法防御力。\\n\\n·对前方三名角色造成魔法伤害（中），\\n\u3000并使敌方全体陷入黑暗状态。\\n·对眼前一名敌人造成物理伤害（大）。\\n\u3000·同时对敌方全体中处于烧伤状态的敌人\\n\u3000造成魔法伤害（大）。');
insert into unit_enemy_data values (303400, '沙之槌', 303400, 0, 13, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】君临生存竞争激烈的沙漠\\n顶端的巨大蜥蜴。\\n利用毒、活用沙子的战法是在\\n残酷的环境中习得的生存术。\\n\\n·对敌方全体造成中等物理\\n\u3000伤害，并降低其行动速度。\\n\u3000同时提升己方全体的物理\\n\u3000攻击力。\\n\\n·以前方一名角色为中心，对小范围\\n\u3000内的敌人造成少量物理伤害，\\n\u3000并赋予中毒状态。\\n\u3000同时，降低敌人的物理防御力。');
insert into unit_enemy_data values (303401, '巨型蜥蜴', 303401, 0, 13, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】带着露娜魔力而变异的巨蜥。\\n硬刺状的鳞片可以削弱敌人的体力和防御。\\n\\n·对敌方全体造成物理伤害（大），\\n\u3000同时削减技能值。\\n·对前方两名角色造成物理伤害（中），\\n\u3000并赋予中毒状态。\\n·对前方三名角色造成物理伤害（中）。\\n\u3000同时对前方一名角色造成物理伤害（大），\\n\u3000并中幅降低其物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (303402, '巨型蜥蜴', 303402, 0, 13, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】带着露娜魔力而变异的巨蜥。\\n硬刺状的鳞片可以削弱敌人的体力和防御。\\n\\n·对敌方全体造成物理伤害（大），\\n\u3000同时削减技能值。\\n·对前方两名角色造成物理伤害（中），\\n\u3000并赋予中毒状态。\\n·对前方三名角色造成物理伤害（中）。\\n\u3000同时对前方一名角色造成物理伤害（大），\\n\u3000并中幅降低其物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (303500, '怒蛇', 303500, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】凭借持续吸收其他生物\\n的魔力来掌握妖术的魔物。\\n从敌人身上的伤口处夺取魔力，\\n进而获得更多的力量。\\n\\n·对敌方全体造成魔法伤害（中）\\n\u3000削减所有使用魔法攻击的\\n\u3000敌人的技能值。\\n\\n·以前方一名角色为中心，\\n\u3000对小范围敌人造成魔法伤害（小），\\n\u3000并降低魔法防御力。');
insert into unit_enemy_data values (303501, '怒蛇', 303501, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】凭借持续吸收其他生物的魔力来掌握妖术的魔物。\\n从对敌人造成的伤口处夺取魔力，进而获得更多的力量。\\n\\n·对敌方全体造成魔法伤害（中）。\\n\u3000同时大幅度降低所有使用魔法攻击的\\n\u3000敌人的技能值。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方两名角色造成魔法伤害（中），\\n\u3000并大幅度降低其物理攻击力。');
insert into unit_enemy_data values (303502, '怒蛇', 303502, 0, 13, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】凭借持续吸收其他生物的魔力来掌握妖术的魔物。\\n从对敌人造成的伤口处夺取魔力，进而获得更多的力量。\\n\\n·对敌方全体造成魔法伤害（中），\\n\u3000并将其击退。\\n\u3000同时大幅度降低所有使用魔法攻击的\\n\u3000敌人的技能值。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方两名角色造成魔法伤害（中），\\n\u3000并大幅度降低其物理攻击力。');
insert into unit_enemy_data values (303600, '熔岩龙', 303600, 0, 13, 270, 1000, 1, 1.7, 0, 0, 0, '【物理】凶猛的恐龙，使用强韧的脚\\n和锐利的爪子来瞬间捕获猎物。\\n在毁灭的大地上以岩浆为食，\\n孤高地生存着。\\n\\n·对敌方全体造成中等物理伤害\\n\u3000提升自身的行动速度。\\n\\n·对前方三名角色造成中等\\n\u3000物理伤害，并使其行动速度下降。');
insert into unit_enemy_data values (303700, '地狱犬', 303700, 0, 14, 270, 1000, 1, 0.7, 0, 0, 0, '【物理】坠入火山后，全身缠绕着\\n地狱的火焰而复苏的双头魔犬。\\n与爱犬波尼一同在领地驰骋，\\n用灼热的火焰来招待入侵者。\\n\\n·对敌方全体给予中等物理伤害，\\n\u3000并赋予烧伤状态。同时回复\\n\u3000召唤的怪物的生命值。\\n\\n·召唤波尼。');
insert into unit_enemy_data values (303800, '阿尔玛', 303800, 0, 16, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】从远古开始守护迷宫的防卫兵器。静静等待跨越所有陷阱，侵入最深处的侵入者。\\n·根据角色的最大生命值，对敌方全体给予\\n\u3000中等魔法伤害。\\n·对前方范围内的敌人给予中等物理伤害。');
insert into unit_enemy_data values (303801, '阿尔玛', 303800, 0, 16, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】从远古开始守护迷宫的防卫兵器。静静等待跨越所有陷阱，侵入最深处的侵入者。\\n·根据角色的最大生命值，对敌方全体给予\\n\u3000特大魔法伤害。\\n·对前方范围内的敌人给予中等物理伤害。\\n·对残余生命值最高的敌人，根据其最大生命值，\\n\u3000给予中等魔法伤害并使其眩晕。\\n·当阿尔玛自身的生命值低于50％时，\\n\u3000它的攻击会变得更为凶暴。');
insert into unit_enemy_data values (303900, '独眼巨人', 303900, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】以自己的怪力为傲，天性凶残的独眼巨人。\\n往眼瞳里注入魔力，从而释放出强大的奇怪光线。\\n\\n·对敌方全体造成魔法伤害（大）。\\n\u3000若角色剩余的生命值为100%，\\n\u3000则提升对该角色造成的伤害，并降低其行动速度。\\n·根据最大生命值，对物理攻击力最高的一名角色\\n\u3000造成物理伤害（中），并降低其技能值。');
insert into unit_enemy_data values (303901, '独眼巨人', 303901, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】以自己的怪力为傲的独眼巨人。\\n充满魔力的眼瞳能释放出强大的奇怪光线。\\n\\n·对敌方全体造成魔法伤害（大）。\\n\u3000提升对生命值为100%的敌人造成的伤害\\n\u3000并降低其行动速度。\\n·对物理攻击力最高的一名敌人，根据其最大\\n\u3000生命值，造成物理伤害（中），并降低其技能值。');
insert into unit_enemy_data values (303902, '独眼巨人', 303902, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】以自己的怪力为傲，天性凶残的独眼巨人。\\n往眼瞳里注入魔力，从而释放出强大的奇怪光线。\\n\\n·对敌方全体造成魔法伤害（大），\\n\u3000并解除属性值提升效果。\\n\u3000同时降低其行动速度。\\n\u3000若角色剩余的生命值为100%，\\n\u3000则提升对该角色造成的伤害。\\n·根据最大生命值，对物理攻击力最高的一名角色\\n\u3000造成物理伤害（中），并降低其技能值。\\n·每发动一次普通攻击，就小幅度提升自身的技能值。');
insert into unit_enemy_data values (304000, '暗黑独角兽', 304000, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】诞生于梦幻，徘徊于黑暗中的魔兽。\\n以恶梦的牢笼束缚猎物，津津有味地享用其活力。\\n\\n·对物理攻击力最高的一名敌人造成魔法伤害（特大），\\n\u3000并特大幅度降低其技能值。\\n·以物理攻击力最高的一名敌人为中心，\\n\u3000对范围内的所有敌人造成魔法伤害（中），\\n\u3000并赋予诅咒状态。');
insert into unit_enemy_data values (304001, '暗黑独角兽', 304001, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】诞生于梦幻，徘徊于黑暗中的魔兽。\\n以恶梦的牢笼束缚猎物，津津有味地享用其活力。\\n\\n·对物理攻击力最高的一名敌人造成魔法伤害（特大），\\n\u3000并特大幅度降低其技能值。\\n·以物理攻击力最高的一名敌人为中心，\\n\u3000对范围内的所有敌人造成魔法伤害（中），\\n\u3000并中幅降低其技能值，同时赋予诅咒状态。');
insert into unit_enemy_data values (304100, '泰坦陆龟', 304100, 0, 13, 270, 1000, 1, 2.5, 0, 0, 0, '又老又大的陆龟，龟壳上甚至有大树扎根。\\n持续忍耐敌人的攻击，施加愤怒的反击。\\n\\n·对全体敌人造成大量物理伤害。\\n·根据自己缩在龟壳期间受到的伤害量\\n\u3000来给予敌人相应的物理伤害。');
insert into unit_enemy_data values (304101, '泰坦陆龟', 304101, 0, 13, 270, 1000, 1, 0.1, 0, 0, 0, '【物理】又老又大的陆龟，龟壳上甚至有大树扎根。\\n持续忍耐敌人的攻击，施加愤怒的反击。\\n\\n·对敌方全体造成物理伤害（中）。\\n·根据自己缩在龟壳期间受到的伤害量，\\n\u3000对敌方全体造成物理伤害。\\n·当所有目标陷入击破状态时，\\n\u3000一定时间内无法行动。\\n\u3000无法行动期间，100%降低自身的物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (304102, '泰坦陆龟', 304102, 0, 13, 270, 1000, 1, 0.1, 0, 0, 0, '【物理】又老又大的陆龟，龟壳上甚至有大树扎根。\\n持续忍耐敌人的攻击，施加愤怒的反击。\\n\\n·对敌方全体造成物理伤害（中）。\\n·根据自己缩在龟壳期间受到的伤害量，\\n\u3000对敌方全体造成物理伤害。\\n·当所有目标陷入击破状态时，\\n\u3000一定时间内无法行动。\\n\u3000无法行动期间，100%降低自身的物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (304200, '卡尔古', 304200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞吃尸体的凶暴大型魔兽。\\n全身缠绕着强韧的尖刺，执着的捕获猎物。\\n·对全体敌人造成与其最大生命值相适应的\\n中等物理伤害。\\n·对后方范围造成中等物理伤害\\n\u3000并令其眩晕。');
insert into unit_enemy_data values (304201, '卡尔古', 304200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞吃尸体的凶暴大型魔兽。\\n全身缠绕着强韧的尖刺，执着的捕获猎物。\\n·对全体敌人造成与其最大生命值相适应的\\n中等物理伤害。\\n·对后方范围造成中等物理伤害\\n\u3000并令其眩晕。\\n·对前方第2个敌人造成中等物理伤害。\\n·卡尔古在生命值低于50%后会展开\\n\u3000更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304300, '腾特帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n·根据角色最大生命值，对全体敌人造成相应威力\\n\u3000的大量物理伤害。\\n·对后方范围造成中等魔法伤害，\\n\u3000令其陷入麻痹状态，另外特大幅降低物理攻击力、\\n\u3000魔法攻击力。\\n·经过一定时间后对单个敌人造成\\n\u3000超大量物理伤害。\\n·腾特帕斯自己的生命值低于40％后，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304301, '腾特帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n·根据角色最大生命值，对全体敌人造成相应威力\\n\u3000的大量物理伤害。\\n·对后方范围造成中等魔法伤害，\\n\u3000令其陷入麻痹状态，另外特大幅降低物理攻击力、\\n\u3000魔法攻击力。');
insert into unit_enemy_data values (304302, '腾特帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n·根据角色最大生命值，对全体敌人造成相应威力\\n\u3000的大量物理伤害。\\n·对后方范围造成中等魔法伤害，\\n\u3000令其陷入麻痹状态，另外特大幅降低物理攻击力、\\n\u3000魔法攻击力。\\n·腾特帕斯自己的生命值低于40％后，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304303, '腾特帕斯', 304300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n·根据角色最大生命值，对全体敌人造成相应威力\\n\u3000的大量物理伤害。\\n·对后方范围造成中等魔法伤害，\\n\u3000令其陷入麻痹状态，另外特大幅降低物理攻击力、\\n\u3000魔法攻击力。\\n·经过一定时间后对单个敌人造成\\n\u3000超大量物理伤害。\\n·腾特帕斯自己的生命值低于40％后，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304304, '滑滑章鱼', 304304, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】企图用塔的力量向人类复仇的软体魔兽。\\n年轻时被鱼叉刺到的怨恨比大海还深。\\n\\n·对敌方全体造成物理伤害（大）。\\n·对前方第三名及其后方的角色造成魔法伤害\\n（中），并中幅度降低其物理防御力和行动速度。\\n\u3000同时解除属性值提升效果。\\n·根据剩余的生命值，对剩余生命值最高的敌人\\n\u3000造成物理伤害（大），并中幅度降低其技能值。');
insert into unit_enemy_data values (304400, '岛鲸', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。\\n·对前方三名角色造成魔法伤害（大），\\n\u3000并将其大幅度击飞。\\n·岛鲸自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304401, '岛鲸', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。');
insert into unit_enemy_data values (304402, '岛鲸', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。\\n·对前方三名角色造成魔法伤害（大），\\n\u3000并将其大幅度击飞。\\n·岛鲸自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304403, '岛鲸', 304400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。\\n·对前方三名角色造成魔法伤害（大），\\n\u3000并将其大幅度击飞。\\n·岛鲸自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304500, '雷电', 304500, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】以精湛的格斗技巧摆布猎物的锹形虫魔物。\\n因被豪雷缠绕的敏锐攻击，而全身麻痹的挑战者层出不穷。\\n\\n·连结爆发时，对前方两名角色造成\\n\u3000物理伤害（中），并使其麻痹。\\n\u3000同时，对敌方全体造成物理伤害（中）后，\\n\u3000中幅度降低自身的物理防御力和魔法防御力。\\n·一定时间内，特大幅度提升自身的物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (304600, '雷雷', 304600, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】操纵着雷云，天真无邪的雷电少女。\\n要是掉以轻心的话，会遭到毫不留情的雷击。\\n\\n·对敌方全体造成魔法伤害（中）。\\n·对后方两名敌人造成魔法伤害（小），');
insert into unit_enemy_data values (304601, '雷雷', 304601, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】操纵着雷云，天真无邪的雷电少女。\\n要是掉以轻心的话，会遭到毫不留情的雷击。\\n\\n·对敌方全体造成魔法伤害（中），\\n\u3000使其眩晕。\\n·对后方两名敌人造成魔法伤害（小），\\n\u3000并小幅降低其技能值。');
insert into unit_enemy_data values (304602, '雷雷', 304602, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】操纵着雷云，天真无邪的雷电少女。\\n要是掉以轻心的话，会遭到毫不留情的雷击。\\n\\n·对敌方全体造成魔法伤害（中）。\\n·对后方两名角色造成魔法伤害（小）。');
insert into unit_enemy_data values (304700, '生灵铠甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁和平。\\n·根据角色最大生命值，对全体敌人造成相应威力的\\n\u3000大量物理伤害，大幅度降低物理攻击力和\\n\u3000物理防御力。\\n·对前方范围造成大量物理伤害。\\n·减少技能值最高的三名敌人的技能值，\\n\u3000大幅度提高自身的物理攻击力。\\n·生灵铠甲自身的生命值低于40%后，\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304701, '生灵铠甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁和平。\\n·根据角色最大生命值，对全体敌人造成相应威力的\\n\u3000大量物理伤害，大幅度降低物理攻击力和\\n\u3000物理防御力。\\n·对前方范围造成大量物理伤害。');
insert into unit_enemy_data values (304702, '生灵铠甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁和平。\\n·根据角色最大生命值，对全体敌人造成相应威力的\\n\u3000大量物理伤害，大幅度降低物理攻击力和\\n\u3000物理防御力。\\n·对前方范围造成大量物理伤害。\\n·减少剩余生命值最高的三名敌人的技能值，\\n\u3000大幅度提高自身的物理攻击力。\\n·生灵铠甲自身的生命值低于40%后，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304703, '生灵铠甲', 304700, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁和平。\\n·根据角色最大生命值，对全体敌人造成相应威力的\\n\u3000大量物理伤害，大幅度降低物理攻击力和\\n\u3000物理防御力。\\n·对前方范围造成大量物理伤害。\\n·减少剩余生命值最高的三名敌人的技能值，\\n\u3000大幅度提高自身的物理攻击力。\\n·生灵铠甲自身的生命值低于40%后，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304704, '崩坏的黑甲骑士', 304704, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬露娜之塔的魔力，不断增殖融合的\\n神秘魔物。无差别地碾压一切。\\n\\n·给予全体敌人高等物理伤害，\\n\u3000另外中等幅度降低物理防御力。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000并使其中物理攻击力最高的两名敌人的\\n\u3000物理攻击力特大幅度下降，同时\\n\u3000技能值特大幅度下降。\\n\u3000自身的物理防御力大幅度下降。\\n·对前方三名敌人造成中等物理伤害，\\n\u3000中等提高物理攻击力。');
insert into unit_enemy_data values (304705, '亡灵铠甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁着和平。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力和物理防御力。\\n·对前方三名角色造成物理伤害（大）。\\n·减少技能值最高的三名敌人的技能值，\\n\u3000并大幅度提升自身的物理攻击力。\\n·当亡灵铠甲自身的生命值低于40%时， \u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304706, '亡灵铠甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁着和平。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力和物理防御力。\\n·对前方三名角色造成物理伤害（大）。');
insert into unit_enemy_data values (304707, '亡灵铠甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁着和平。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力和物理防御力。\\n·减少剩余生命值最高的三名敌人的技能值，\\n\u3000并将其击退。\\n\u3000同时大幅度提升自身的物理攻击力。\\n·对前方三名角色造成物理伤害（大）。\\n·当亡灵铠甲自身的生命值低于40%时， \u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304708, '亡灵铠甲', 304705, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】吞噬金属，操纵武器的神秘魔物。\\n通过增殖融合变为超大的怪物，威胁着和平。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力和物理防御力。\\n·减少剩余生命值最高的三名敌人的技能值，\\n\u3000并将其击退。\\n\u3000同时大幅度提升自身的物理攻击力。\\n·对前方三名角色造成物理伤害（大）。\\n·当亡灵铠甲自身的生命值低于40%时， \u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (304800, '幽灵领主', 304800, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】冥府的高官，征服强者的灵魂，使其成为自己的手下亡灵。\\n将死者的执念附于刀刃之上，使对手的动作变得迟缓。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000一定比例的魔法伤害，并特大幅度降低其物理攻击力。\\n·对敌方全体造成魔法伤害（中）。\\n\u3000并降低使用物理攻击的敌人的行动速度。');
insert into unit_enemy_data values (304801, '幽灵领主', 304801, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】冥府的高官，征服强者的灵魂，使其成为自己的手下亡灵。\\n将死者的执念附于刀刃之上，使对手的动作变得迟缓。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000一定比例的魔法伤害，并特大幅度降低其物理攻击力。\\n\u3000·无视敌人的挑衅，并分别使物理攻击力和魔法攻击力\\n\u3000最高的一名角色\\n\u3000陷入恐慌状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对敌方全体造成魔法伤害（中）。\\n\u3000并降低使用物理攻击的敌人的行动速度。');
insert into unit_enemy_data values (304900, '电子吉加斯', 304900, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】通过露娜之魔力醒来的巨腕改造人。\\n小型反应堆的最大输出连自身都能感电。\\n\\n·对前方范围内的敌人造成大量物理伤害＆麻痹。\\n\u3000解除自身状态提升效果，\\n\u3000中等幅度降低物理防御力和魔法防御力。\\n·对敌方全体造成大量魔法伤害，\\n\u3000大幅度长时间提高自身的物理攻击力。\\n·大幅度提高己方全体的行动速度。');
insert into unit_enemy_data values (305000, '布丁南瓜灯', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n「我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟~」\\n\\n·对全体敌人造成大量物理伤害，\\n\u3000角色的生命值低于40%后，\\n\u3000变为诱惑状态。\\n·对全体敌人造成少量魔法伤害，\\n\u3000解除敌人状态提升效果。\\n·对最近的敌人造成中等物理伤害，\\n\u3000另外，对前方三名敌人造成中等物理\\n\u3000伤害＆赋予眩晕。\\n·布丁南瓜灯自身的生命值\\n\u3000低于40%后，会展开更为激烈\\n\u3000凶暴的攻击。\\n');
insert into unit_enemy_data values (305001, '布丁南瓜灯', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n「我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟~」\\n\\n·对全体敌人造成大量物理伤害，\\n\u3000角色的生命值低于40%时，\\n\u3000赋予诱惑状态。\\n·对最近的敌人造成中等物理伤害，\\n\u3000另外，对前方三名敌人造成中等物理\\n\u3000伤害＆赋予眩晕。\\n');
insert into unit_enemy_data values (305002, '布丁南瓜灯', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n「我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟~」\\n\\n·对全体敌人造成大量物理伤害，\\n\u3000角色的生命值低于40%时，\\n\u3000赋予诱惑状态。\\n·对全体敌人造成少量魔法伤害，\\n\u3000解除敌人状态提升效果。\\n·对最近的敌人造成中等物理伤害，\\n\u3000另外，对前方三名敌人造成中等物理\\n\u3000伤害＆赋予眩晕。\\n·布丁南瓜灯自身的生命值\\n\u3000低于40%后，会展开更为激烈\\n\u3000凶暴的攻击。\\n');
insert into unit_enemy_data values (305003, '布丁南瓜灯', 305000, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n「我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟~」\\n\\n·对全体敌人造成大量物理伤害，\\n\u3000角色的生命值低于40%时，\\n\u3000赋予诱惑状态。\\n·对全体敌人造成少量魔法伤害，\\n\u3000解除敌人状态提升效果。\\n·对最近的敌人造成中等物理伤害，\\n\u3000另外，对前方三名敌人造成中等物理\\n\u3000伤害＆赋予眩晕。\\n·布丁南瓜灯自身的生命值\\n\u3000低于40%后，会展开更为激烈\\n\u3000凶暴的攻击。\\n');
insert into unit_enemy_data values (305004, '布丁南瓜灯', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n“我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟～”\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000造成相应的物理伤害（大），\\n\u3000角色的生命值低于40%时，\\n\u3000赋予魅惑状态。\\n·对敌方全体造成魔法伤害（小），\\n\u3000并解除敌人属性提升效果。\\n·对最近的敌人造成物理伤害（中），\\n\u3000另外，对前方三名敌人造成物理\\n\u3000伤害（中）＆使其眩晕。\\n·当布丁南瓜灯自身的生命值\\n\u3000低于40%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。\\n');
insert into unit_enemy_data values (305005, '布丁南瓜灯', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n“我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟～”\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（中），\\n\u3000角色的生命值低于40%时，\\n\u3000使其陷入诱惑状态。\\n·对最近的敌人造成物理伤害（大），\\n\u3000并对前方三名角色造成物理伤害（中）\\n\u3000且使其眩晕。\\n');
insert into unit_enemy_data values (305006, '布丁南瓜灯', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n“我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟～”\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（中），\\n\u3000角色的生命值低于40%时，\\n\u3000使其陷入诱惑状态。\\n·对全体敌人造成魔法伤害（小），\\n\u3000并解除角色的属性值提升效果。\\n·对最近的敌人造成物理伤害（大），\\n\u3000并对前方三名角色造成物理伤害（中）\\n\u3000且使其眩晕。\\n·布丁南瓜灯自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。\\n');
insert into unit_enemy_data values (305007, '布丁南瓜灯', 305004, 0, 16, 270, 1000, 1, 0.8, 0, 0, 0, '【物理】企图向人类复仇的灵界居民。\\n“我是南瓜灯！布丁南瓜灯！\\n\u3000不陪我玩就捣乱哟～”\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（中），\\n\u3000角色的生命值低于40%时，\\n\u3000使其陷入诱惑状态。\\n·对全体敌人造成魔法伤害（小），\\n\u3000并解除角色的属性值提升效果。\\n·对最近的敌人造成物理伤害（大），\\n\u3000并对前方三名角色造成物理伤害（中）\\n\u3000且使其眩晕。\\n·布丁南瓜灯自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。\\n');
insert into unit_enemy_data values (305100, '巨型凶暴兔', 305100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】凭借巨大的身躯肆虐各方的大型兔子魔物。\\n其奋力的一击消耗非常大，似乎还未能很好地掌控力道。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（大），并将其击退。\\n\u3000随后，当凶暴兔头昏眼花时，它自身的物理防御力\\n\u3000和魔法防御力将大幅度降低。\\n·对敌方全体造成物理伤害（中），\\n\u3000并使前方范围内的敌人陷入眩晕状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (305101, '巨型凶暴兔', 305100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】凭借巨大的身躯肆虐各方的大型兔子魔物。\\n其奋力的一击消耗非常大，但攻击力也同样强大。\\n\\n·对敌方全体造成物理伤害（大），\\n\u3000同时击退敌人。\\n\u3000之后，在恢复过来期间，\\n\u3000大幅降低自身的物理防御力与魔法防御力。\\n\\n·对敌方全体造成物理伤害（中），\\n\u3000并使前方范围内的敌人眩晕。');
insert into unit_enemy_data values (305102, '巨型凶暴兔', 305102, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】凭借巨大的身躯肆虐各方的大型兔子魔物。\\n其奋力的一击消耗非常大，似乎还未能很好地掌控力道。\\n\\n·连结爆发时，对敌方全体造成\\n\u3000物理伤害（大），并将其击退。\\n\u3000随后，当凶暴兔头昏眼花时，它自身的物理防御力\\n\u3000和魔法防御力将大幅度降低。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对敌方全体造成物理伤害（中），\\n\u3000并使前方范围内的敌人陷入眩晕状态。\\n\u3000随后中幅度恢复自身的技能值。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·普通攻击时，对最前方的角色造成物理伤害（中），\\n\u3000并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (305200, '奥拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遥远的古代诞生的防卫兵器。\\n由于恶党的阴谋，其悠久的沉睡宣告了终结。\\n\\n·根据角色最大生命值，给予全体敌人相应威力的\\n\u3000高等物理伤害，\\n\u3000同时大幅度降低自身的物理攻击力。\\n·给予前方中范围内的敌人中等物理伤害，\\n\u3000大幅度降低物理攻击力。\\n·给予前方大范围内的敌人中等物理伤害，\\n\u3000并让其陷入麻痹状态。\\n\u3000角色的生命值在70％以下的时候，\\n\u3000麻痹持续时间变长。\\n·奥拉姆自身的生命值低于40%后，\u3000\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (305201, '奥拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遥远的古代诞生的防卫兵器。\\n由于恶党的阴谋，其悠久的沉睡宣告了终结。\\n\\n·根据角色最大生命值，给予全体敌人相应威力的\\n\u3000高等物理伤害，\\n\u3000同时大幅度降低自身的物理攻击力。\\n·给予前方中范围内的敌人中等物理伤害，\\n\u3000大幅度降低物理攻击力。');
insert into unit_enemy_data values (305202, '奥拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遥远的古代诞生的防卫兵器。\\n由于恶党的阴谋，其悠久的沉睡宣告了终结。\\n\\n·根据角色最大生命值，给予全体敌人相应威力的\\n\u3000高等物理伤害，\\n\u3000同时大幅度降低自身的物理攻击力。\\n·给予前方中范围内的敌人中等物理伤害，\\n\u3000大幅度降低物理攻击力。\\n·给予前方大范围内的敌人中等物理伤害，\\n\u3000并让其陷入麻痹状态。\\n\u3000角色的生命值在70％以下的时候，\\n\u3000麻痹持续时间变长。\\n·奥拉姆自身的生命值低于40%后，\u3000\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (305203, '奥拉姆', 305200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在遥远的古代诞生的防卫兵器。\\n由于恶党的阴谋，其悠久的沉睡宣告了终结。\\n\\n·根据角色最大生命值，给予全体敌人相应威力的\\n\u3000高等物理伤害，\\n\u3000同时大幅度降低自身的物理攻击力。\\n·给予前方中范围内的敌人中等物理伤害，\\n\u3000大幅度降低物理攻击力。\\n·给予前方大范围内的敌人中等物理伤害，\\n\u3000并让其陷入麻痹状态。\\n\u3000角色的生命值在70％以下的时候，\\n\u3000麻痹持续时间变长。\\n·奥拉姆自身的生命值低于40%后，\u3000\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (305204, '诅咒·奥拉姆', 305204, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】因露娜之塔的魔力而暴走的古代兵器。\\n古老的守护之力化为了散布诅咒的可怕灾祸。\\n\\n·对敌方全体造成物理伤害（大），\\n\u3000并大幅降低自身的物理防御力和魔法防御力。\\n·以前方一名敌人为中心，对范围内的所有敌人\\n\u3000造成物理伤害（中），中幅降低其物理防御力。\\n\u3000同时使其眩晕。\\n·对敌方全体造成物理伤害（中），并赋予\\n\u3000诅咒状态。当角色的生命值在40％以下时，\\n\u3000诅咒的伤害提升至2倍。');
insert into unit_enemy_data values (305205, '奥拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】诞生于遥远古代的防卫兵器。\\n漫长的沉睡因恶党的阴谋而被画上了句号。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低自身的物理攻击力。\\n·对前方中范围内的敌人造成物理伤害（中），\\n\u3000并大幅度降低其物理攻击力。\\n·对前方大范围内的敌人造成物理伤害（中），\\n\u3000并使其麻痹。\\n\u3000角色的生命值低于70%时，\\n\u3000麻痹的持续时间变长。\\n·奥拉姆自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (305206, '奥拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】诞生于遥远古代的防卫兵器。\\n漫长的沉睡因恶党的阴谋而被画上了句号。\\n\\n·连结爆发时，在大幅度降低自身的\\n\u3000物理攻击力后，将根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方中范围内的敌人造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力。');
insert into unit_enemy_data values (305207, '奥拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】诞生于遥远古代的防卫兵器。\\n漫长的沉睡因恶党的阴谋而被画上了句号。\\n\\n·连结爆发时，在大幅度降低自身的\\n\u3000物理攻击力后，将根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方中范围内的敌人造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力。\\n·对前方大范围内的敌人造成物理伤害（大），\\n\u3000并使其麻痹。\\n\u3000角色的生命值低于70%时，\\n\u3000麻痹的持续时间变长。\\n·奥拉姆自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (305208, '奥拉姆', 305205, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】诞生于遥远古代的防卫兵器。\\n漫长的沉睡因恶党的阴谋而被画上了句号。\\n\\n·连结爆发时，在大幅度降低自身的\\n\u3000物理攻击力后，将根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方中范围内的敌人造成物理伤害（大），\\n\u3000并大幅度降低其物理攻击力。\\n·对前方大范围内的敌人造成物理伤害（大），\\n\u3000并使其麻痹。\\n\u3000角色的生命值低于70%时，\\n\u3000麻痹的持续时间变长。\\n·奥拉姆自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (305300, '高等食尸兽', 305300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】沐浴在露娜魔力之下而变异的狰狞魔兽。\\n强韧的爪牙能轻而易举地将历练的冒险者撕裂。\\n\\n·必杀技能对敌方全体造成大量物理伤害，\\n\u3000并会回复自己的生命值。\\n·对后方范围内的敌人造成物理伤害，\\n\u3000使其眩晕。\\n\u3000并使敌方全体的物理防御力中幅度下降。\\n·对前方范围内的敌人造成物理伤害\\n\u3000使其陷入中毒状态。');
insert into unit_enemy_data values (305301, '寒冰卡尔古', 305301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖息于雪山中的狞恶魔狼。\\n强韧的爪牙能轻而易举地\\n将历练的冒险者变为冰块墓碑。\\n\\n·连结爆发时，对敌方全体\\n\u3000造成物理伤害（大）。\\n\\n·以最后方的敌人为中心，\\n\u3000对范围内的所有敌人造成\\n\u3000物理伤害（小），并使其眩晕。\\n\u3000同时中幅度降低敌方全体的\\n\u3000物理防御力。\\n\\n·对前方范围内的全体敌人造成\\n\u3000物理伤害（小），并赋予毒状态。');
insert into unit_enemy_data values (305302, '寒冰卡尔古', 305301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖息于雪山中的狞恶魔狼。\\n强韧的爪牙能轻而易举地\\n将历练的冒险者变为冰块墓碑。\\n\\n·连结爆发时，对敌方全体\\n\u3000造成物理伤害（大）。\\n\\n·以最后方的敌人为中心，\\n\u3000对范围内的所有敌人造成\\n\u3000物理伤害（小），并使其眩晕。\\n\u3000同时中幅度降低敌方全体的\\n\u3000物理防御力。\\n\\n·对前方范围内的全体敌人造成\\n\u3000物理伤害（小），并赋予毒状态。');
insert into unit_enemy_data values (305400, '冰角龙', 305400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】强而有力的带冰头部能\\n贯穿坚韧护盾的独角之兽。\\n在布满冰丘的北方尽头，\\n将冒险者推落到冰之地狱。\\n\\n·对敌方全体造成大量魔法伤害，\\n\u3000降低物理防御力。\\n\u3000并使己方全体的技能值\\n\u3000上升。\\n\\n·对前方小范围造成少量魔法伤害，\\n\u3000使其陷入结冰状态。并且\\n\u3000对全体造成少量魔法伤害，\\n\u3000将前方三名角色小幅度\\n\u3000击飞。');
insert into unit_enemy_data values (305500, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在无数传说中都有所记载的记忆之大精灵。\\n没有实体，如雾般缥缈隐藏全身。\\n\\n·必杀技能给予敌方全体\\n\u3000魔法伤害（大），\\n\u3000并且在敌人处于诅咒状态时\\n\u3000提升伤害。\\n·给予敌方全体魔法伤害（中）。\\n\u3000并使其陷入诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）（蓝）之中的其中一个。\\n\u3000召唤时给予敌人全体反击。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的屏障。\\n·【物理】分身（红）会给予敌方全体\\n\u3000魔法伤害（中）。\\n·【物理】分身（蓝）给予敌方全体\\n\u3000物理伤害（中）。\\n\u3000并且使其陷入诅咒状态。\\n\u3000分身（蓝）的生命值降到30%以下时，\\n\u3000回复雾精的300技能值。\\n·雾精自身的生命值\\n\u3000降到50%时，\\n\u3000会变得更为凶暴，攻击更为猛烈。');
insert into unit_enemy_data values (305501, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】身负无数传承之名，记忆的大精灵。\\n没有实体，如雾般缥缈隐藏全身。\\n\\n·必杀技能给予敌方全体\\n\u3000魔法伤害（大），\\n\u3000并且在敌人处于诅咒状态时\\n\u3000提升伤害。\\n·给予敌方全体魔法伤害（中）。\\n\u3000并使其陷入诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）之中的其中一个。\\n\u3000召唤时给予敌人全体反击。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的屏障。\\n·【物理】分身（红）会给予敌方全体\\n\u3000魔法伤害（中）。');
insert into unit_enemy_data values (305502, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】身负无数传承之名，记忆的大精灵。\\n没有实体，如雾般缥缈隐藏全身。\\n\\n·必杀技能给予敌方全体\\n\u3000魔法伤害（大），\\n\u3000并且在敌人处于诅咒状态时\\n\u3000提升伤害。\\n·给予敌方全体魔法伤害（中）。\\n\u3000并使其陷入诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）之中的其中一个。\\n\u3000\u3000召唤时给予敌人全体反击。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的屏障。\\n·【物理】分身（红）会给予敌方全体\\n\u3000魔法伤害（中）。\\n·雾精自身的生命值\\n\u3000降到50%时，\\n\u3000会变得更为凶暴，攻击更为猛烈。');
insert into unit_enemy_data values (305503, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】身负无数传承之名，记忆的大精灵。\\n没有实体，如雾般缥缈隐藏全身。\\n\\n·必杀技能给予敌方全体\\n\u3000魔法伤害（大），\\n\u3000并且在敌人处于诅咒状态时\\n\u3000提升伤害。\\n·敵给予敌方全体魔法伤害（中）。\\n\u3000并使其陷入诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）（蓝）之中的其中一个。\\n\u3000召唤时给予敌人全体反击。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的屏障。\\n·【物理】分身（红）会给予敌方全体\\n\u3000魔法伤害（中）。\\n·【物理】分身（蓝）给予敌方全体\\n\u3000物理伤害（中）。\\n\u3000并且使其陷入诅咒状态。\\n\u3000分身（蓝）的生命值降到30%以下时，\\n\u3000回复雾精的300技能值。\\n·雾精自身的生命值\\n\u3000降到50%时，\\n\u3000会变得更为凶暴，攻击更为猛烈。');
insert into unit_enemy_data values (305504, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在无数传说中都有所记载的记忆之大精灵。\\n没有实体，如雾般缥缈，隐匿身形。\\n\\n·必杀技能对敌方全体\\n\u3000造成魔法伤害（大），\\n\u3000并且在敌人处于诅咒状态时，\\n\u3000提升造成的伤害。\\n·对敌方全体造成魔法伤害（大）。\\n\u3000并赋予诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）（蓝）之中的其中一个。\\n\u3000召唤时击退敌方全体。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的领域。\\n·【物理】分身（红）会对敌方全体\\n\u3000造成魔法伤害（中）。\\n·【物理】分身（蓝）会对敌方全体\\n\u3000造成魔法伤害（中）。\\n\u3000并赋予诅咒状态。\\n\u3000当分身（蓝）的生命值降到30%以下时，\\n\u3000回复雾精300技能值。\\n·当雾精自身的生命值\\n\u3000低于50%时，会变得更为凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (305505, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在无数传说中都有所记载的记忆之大精灵。\\n没有实体，如雾般缥缈，隐匿身形。\\n\\n·必杀技能对敌方全体\\n\u3000造成魔法伤害（中）。\u3000并且在敌人处于诅咒状态时，\\n\u3000提升造成的伤害。\\n·对敌方全体造成魔法伤害（小），\\n\u3000并赋予诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）之中的其中一个。\\n\u3000召唤时击退敌方全体。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的领域。\\n·【物理】分身（红）会对敌方全体\\n\u3000造成魔法伤害（大）。');
insert into unit_enemy_data values (305506, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在无数传说中都有所记载的记忆之大精灵。\\n没有实体，如雾般缥缈，隐匿身形。\\n\\n·必杀技能对敌方全体\\n\u3000造成魔法伤害（中）。\u3000并且在敌人处于诅咒状态时，\\n\u3000提升造成的伤害。\\n·对敌方全体造成魔法伤害（小），\\n\u3000并赋予诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）之中的其中一个。\\n\u3000召唤时击退敌方全体。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的领域。\\n·【物理】分身（红）会对敌方全体\\n\u3000并造成魔法伤害（大）。\\n·当雾精自身的生命值\\n\u3000低于50%时，会变得更为凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (305507, '雾精', 305500, 0, 16, 270, 2160, 2, 3.0, 0, 0, 0, '【魔法】在无数传说中都有所记载的记忆之大精灵。\\n没有实体，如雾般缥缈，隐匿身形。\\n\\n·必杀技能对敌方全体\\n\u3000造成魔法伤害（大），\\n\u3000并且在敌人处于诅咒状态时，\\n\u3000提升造成的伤害。\\n·对敌方全体造成魔法伤害（大）。\\n\u3000并赋予诅咒状态。\\n·随机召唤\\n\u3000分身（紫）（红）（蓝）之中的其中一个。\\n\u3000召唤时击退敌方全体。\\n·【物理】分身（紫）会为自身展开吸收\\n\u3000物理/魔法的领域。\\n·【物理】分身（红）会对敌方全体\\n\u3000并造成魔法伤害（大）。\\n·【物理】分身（蓝）会对敌方全体\\n\u3000造成物理伤害（小）。\\n\u3000并赋予诅咒状态。\\n\u3000当分身（蓝）的生命值降到30%以下时，\\n\u3000回复雾精300技能值。\\n·当雾精自身的生命值\\n\u3000低于50%时，会变得更为凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (305600, '异界魔主', 305600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【魔法】渴望获得月神魔力而出现的异界魔物。\\n企图凭魔眼和自己率领的士兵征服露娜之塔。\\n\\n·对敌方全体造成魔法伤害（大），\\n\u3000并中幅度降低其魔法防御力。\\n·随机对一名角色造成\\n\u30006次魔法伤害（小）。\\n·对后方第三名角色造成魔法伤害（中），\\n\u3000并将其长时间拘束。\\n\\n·同时对敌方全体造成魔法伤害（小）。');
insert into unit_enemy_data values (305700, '巨型哥布林', 305700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】豪爽地挥舞战斧，身经百战的哥布林战士。\\n腋下夹着年幼的战士，为其展示千锤百炼的技艺。\\n\\n·连结爆发时，中幅度提升自身的\\n\u3000物理攻击力，小幅度提升物理防御力，\\n\u3000并对眼前的一名敌人造成物理伤害（特大）。');
insert into unit_enemy_data values (305701, '巨型哥布林', 305701, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '豪爽地挥舞战斧，身经百战的哥布林战士。\\n腋下夹着年幼的战士，为其展示千锤百炼的技艺。\\n\\n·必杀技能中幅提升自身的物理攻击力，\\n\u3000小幅提升自身的物理防御力，同时\\n\u3000对前方一名敌人造成物理伤害（特大）。');
insert into unit_enemy_data values (305702, '巨型哥布林', 305702, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】豪爽地挥舞战斧，身经百战的哥布林战士。\\n腋下夹着年幼的战士，为其展示千锤百炼的技艺。\\n\\n·连结爆发时，中幅度提升自身的\\n\u3000物理攻击力，小幅度提升物理防御力。\\n\u3000并对眼前的一名敌人造成物理伤害（特大），\\n\u3000同时使其眩晕。');
insert into unit_enemy_data values (305800, '海蛞蝓', 305800, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】海神的使者，一种神秘的软体魔物。\\n据闻几乎全身都是由带有魔力的海水构成。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，并大幅度\\n\u3000降低其物理攻击力，中幅度降低魔法攻击力。\\n·对前方第二名角色造成魔法伤害（特大），\\n\u3000对前方第三名角色造成魔法伤害（中）。\\n·在一定范围内，展开大幅降低行动速度和\\n\u3000持续造成魔法伤害的领域。');
insert into unit_enemy_data values (305801, '海神使者', 305801, 0, 16, 270, 1000, 2, 2.6, 0, 0, 0, '【魔法】在露娜之塔肆虐的海兽。曾侍奉远古的海神，\\n如今却成为了舍弃正义的破坏者。\\n\\n·对敌方全体造成魔法伤害。\\n·在一定范围内，降低敌方的物理攻击力和\\n\u3000魔法防御力，并展开造成持续\\n\u3000魔法伤害的领域。\\n·对前方第二名、第三名敌人\\n\u3000造成魔法伤害（大）。');
insert into unit_enemy_data values (305802, '海蛞蝓', 305802, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】侍奉海神的奇妙魔物。\\n当看到有入侵者威胁水域的和平时，\\n它便会行使神使之力将其一举消灭。\\n\\n·对敌方全体造成魔法伤害（大）。\\n\\n·对前方第二名角色造成魔法伤害\\n\u3000（特大），对前方第三名角色造成\\n\u3000魔法伤害（中）。\\n\\n·在一定范围内，展开降低魔法防御\\n\u3000力和持续造成魔法伤害的领域。');
insert into unit_enemy_data values (305900, '极彩鸟', 305900, 0, 16, 270, 1000, 1, 2.2, 0, 0, 0, '【物理】能散发出惊人的吸引力，有着缤纷色彩的艳丽鸟类。\\n若被那份美丽所吸引，便会成为其仆人，袭击同伴。\\n\\n·必杀技能对魅惑状态以外的全体敌人\\n\u3000造成物理伤害（大）。\\n·对前方两名角色造成魔法伤害（小），并赋予\\n\u3000魅惑状态，再大幅提升物理攻击力\\n\u3000与魔法攻击力。');
insert into unit_enemy_data values (305901, '极彩鸟', 305901, 0, 16, 270, 1000, 1, 2.2, 0, 0, 0, '【物理】散发着压倒性魅力的妖娆五彩艳鸟。\\n一旦被它的美艳所困，便会成为不惜袭击同伴的仆人。\\n\\n·连结爆发时，除处于诱惑状态的角色以外，\\n\u3000对敌方全体造成物理伤害（大）。\\n\u3000并同时赋予敌方全体诱惑状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\\n·对前方两名角色造成魔法伤害（小），\\n\u3000并赋予诱惑状态，随后大幅度提升其物理攻击力和\\n\u3000魔法攻击力。');
insert into unit_enemy_data values (306000, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·必杀技能对敌方全体造成\\n\u3000物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000降低物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在召唤后\\n\u30008秒产生大爆炸，对范围内的敌方全体造成\\n\u3000物理伤害（中）。\\n\u3000但是，在爆炸前将炸弹年糕的生命值\\n\u3000降到50%，\\n\u3000则小幅回复敌方全体生命值，并消失。\\n·邪糕神伽米自身的生命值\\n\u3000降到50%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306001, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·必杀技能对敌方全体造成\\n\u3000物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000降低物理攻击力。');
insert into unit_enemy_data values (306002, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·必杀技能对敌方全体造成\\n\u3000物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000降低物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在召唤后\\n\u30008秒产生大爆炸，对范围内的敌方全体造成\\n\u3000物理伤害（中）。\\n\u3000但是，在爆炸前将炸弹年糕的生命值\\n\u3000降到50%，\\n\u3000则小幅回复敌方全体生命值，并消失。\\n·邪糕神伽米自身的生命值\\n\u3000降到50%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306003, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·必杀技能对敌方全体造成\\n\u3000物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000降低物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在召唤后\\n\u30008秒产生大爆炸，对范围内的敌方全体造成\\n\u3000物理伤害（中）。\\n\u3000但是，在爆炸前将炸弹年糕的生命值\\n\u3000降到50%，\\n\u3000则小幅回复敌方全体生命值，并消失。\\n·邪糕神伽米自身的生命值\\n\u3000降到50%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306004, '邪糕神伽米', 306004, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【MODE1】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·邪糕神伽米自身收到攻击时，\\n 小幅回复己方全体的生命值，\\n\u3000回复邪糕神伽米自身的全部生命值。');
insert into unit_enemy_data values (306005, '邪糕神伽米', 306005, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【MODE2】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·对前方一名角色造成物理伤害。\\n·对前方范围内造成魔法伤害（中），\\n\u3000并大幅击飞。\\n·注入6份邪念，召唤一只烦恼（红）。\\n·注入3份邪念，召唤一只烦恼（紫）。\\n·注入1份邪念，召唤一只烦恼（蓝）。');
insert into unit_enemy_data values (306006, '邪糕神伽米', 306006, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【MODE3】汇聚了邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·对前方一名角色造成物理伤害。\\n·必杀技能对敌方全体造成\\n\u3000物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000降低物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在召唤后\\n\u30008秒产生大爆炸，对范围内的敌方全体造成\\n\u3000物理伤害（中）。\\n\u3000但是，在爆炸前将炸弹年糕的生命值\\n\u3000降到50%，\\n\u3000则小幅回复敌方全体生命值，并消失。');
insert into unit_enemy_data values (306007, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由汇集的邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·连结爆发时，根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000并小幅度降低其物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在被召唤\\n8秒后爆炸，对范围内的全体敌方造成\\n\u3000物理伤害（中）。\\n\u3000然而，若炸弹年糕的生命值在爆炸前\\n\u3000低于50%，\\n\u3000则小幅度回复敌方全体生命值，并就此消失。');
insert into unit_enemy_data values (306008, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由汇集的邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·连结爆发时，根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000并小幅度降低其物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在被召唤\\n8秒后爆炸，对范围内的全体敌方造成\\n\u3000物理伤害（中）。\\n\u3000然而，若炸弹年糕的生命值在爆炸前\\n\u3000低于50%，\\n\u3000则小幅度回复敌方全体生命值，并就此消失。\\n·邪糕神伽米自身的生命值\\n\u3000低于50%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306009, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由汇集的邪念残渣化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·连结爆发时，根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000并小幅度降低其物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在被召唤\\n8秒后爆炸，对范围内的全体敌方造成\\n\u3000物理伤害（大）。\\n\u3000然而，若炸弹年糕的生命值在爆炸前\\n\u3000低于50%，\\n\u3000则小幅度回复敌方全体生命值，并就此消失。\\n·邪糕神伽米自身的生命值\\n\u3000低于50%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306010, '邪糕神伽米', 306000, 0, 16, 270, 2160, 1, 1.6, 0, 0, 0, '【物理】由邪念的残渣汇集、化身而成的邪神。\\n净化所有显现出的烦恼，迎接新年吧！\\n\\n·必杀技能对敌方全体\\n·造成与角色的最大生命值\\n\u3000相应的物理伤害（大）。\\n·对前方三名敌人造成魔法伤害（中），\\n\u3000并降低其物理攻击力。\\n·在前方中距离召唤倒计时式炸弹年糕。\\n·炸弹年糕会在召唤后\\n\u30008秒产生大爆炸，对范围内的敌方全体\\n\u3000造成物理伤害（中）。\\n\u3000但是，若在爆炸前将炸弹年糕的生命值\\n\u3000低于50%时，\\n\u3000则小幅回复敌方全体生命值，并消失。\\n·当邪糕神伽米自身的生命值\\n\u3000低于60%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306100, '偷盗豺狼', 306100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】潜藏在黑暗之中，在村落偷盗财物的\\n魔物头领。\\n是一个会毫不留情地使用蒙骗回来的赃物攻击敌人，\\n并妨碍开拓的流氓。\\n\\n·对前方三名角色造成\\n\u3000物理伤害（中），\\n\u3000并使其麻痹。\\n\\n·对敌方全体造成物理伤害（小），\\n\u3000并降低其行动速度。\\n\u3000同时，使前方小范围\\n\u3000陷入毒状态。');
insert into unit_enemy_data values (306101, '偷盗豺狼', 306101, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】潜藏在黑暗之中，在村落中偷盗财物的魔物头领。\\n是一个会灵巧地使用蒙骗回来的赃物攻击敌人的流氓。\\n\\n·对前方三名角色造成物理伤害（中），\\n\u3000并使其麻痹。\\n·对敌方全体造成物理伤害（小），\\n\u3000并降低其行动速度。\\n\u3000同时，使前方小范围\\n\u3000陷入毒状态。\\n\u3000这个技能的毒在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (306102, '偷盗豺狼', 306102, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】潜藏在黑暗之中，在村落中偷盗财物的魔物头领。\\n是一个会灵巧地使用蒙骗回来的赃物攻击敌人的流氓。\\n\\n·对前方三名角色造成物理伤害（中），\\n\u3000并使其麻痹。\\n·对敌方全体造成物理伤害（小），\\n\u3000并降低其行动速度。\\n\u3000同时，使前方小范围\\n\u3000陷入毒状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\u3000该技能造成的伤害\\n\u3000无法回复技能值。');
insert into unit_enemy_data values (306200, '狸猫首领', 306200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖身于森林深处，与手下一同支配着周边的狡猾大狸猫。以虚构的幻象侵蚀敌人的精神，能巧妙地使用幻影进行攻击。\\n\\n·对敌方全体造成魔法伤害（中），并召唤2只淘气豆狸。\\n\\n·对敌方全体造成魔法伤害（小），消灭不处于无敌状态的召唤怪物。并在敌人的生命值降至40%以下时，赋予其麻痹状态。');
insert into unit_enemy_data values (306201, '狸猫首领', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖身于森林深处，支配着这一带的狡猾大狸猫。\\n与召唤而来的小狸猫相互配合，以多彩的招数蛊惑敌人。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（中），\\n\u3000并召唤2只淘气豆狸。\\n·对敌方全体造成魔法伤害（小），将其击退\\n\u3000并消灭非无敌状态的淘气豆狸。\\n\u3000若敌人的生命值低于50%，\\n\u3000则赋予其麻痹状态。');
insert into unit_enemy_data values (306202, '狸猫首领', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖身于森林深处，支配着这一带的狡猾大狸猫。\\n与召唤而来的小狸猫相互配合，以多彩的招数蛊惑敌人。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（中），\\n\u3000并召唤2只淘气豆狸。\\n·对敌方全体造成魔法伤害（小），将其击退\\n\u3000并消灭非无敌状态的淘气豆狸。\\n\u3000若敌人的生命值低于50%，\\n\u3000则赋予其麻痹状态。');
insert into unit_enemy_data values (306203, '狸猫首领', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖身于森林深处，支配着这一带的狡猾大狸猫。\\n与召唤而来的小狸猫相互配合，以多彩的招数蛊惑敌人。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（中），\\n\u3000并召唤2只淘气豆狸。\\n·对敌方全体造成魔法伤害（小），将其击退\\n\u3000并消灭非无敌状态的淘气豆狸。\\n\u3000若敌人的生命值低于50%，\\n\u3000则赋予其麻痹状态。');
insert into unit_enemy_data values (306204, '狸猫首领', 306201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖身于森林深处，支配着这一带的狡猾大狸猫。\\n与召唤而来的小狸猫相互配合，以多彩的招数蛊惑敌人。\\n\\n·连结爆发时，对敌方全体造成魔法伤害（中），\\n\u3000并召唤2只淘气豆狸。\\n·对敌方全体造成魔法伤害（小），将其击退\\n\u3000并消灭非无敌状态的淘气豆狸。\\n\u3000若敌人的生命值低于50%，\\n\u3000则赋予其麻痹状态。');
insert into unit_enemy_data values (306300, '长耳猴首领', 306300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】使用露娜魔力，统领长耳猴的仙猿。\\n自在操纵宝武具之棍，击退所有敌人。\\n\\n·对敌方全体造成大量物理伤害\\n\u3000该攻击对处于烧伤状态的敌人，\\n\u3000伤害会变为1.8倍。\\n·对前方中范围的敌人造成中等物理伤害\\n·对前方小范围的敌方造成中等魔法伤害，\\n\u3000使其变成烧伤状态。');
insert into unit_enemy_data values (306301, '长耳猴首领', 306301, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】使用露娜魔力，统领长耳猴的仙猿。\\n自在操纵宝武具之棍，击退所有敌人。\\n\\n·对敌方全体造成大量物理伤害，\\n\u3000并使物理攻击角色的物理攻击力下降。\\n\u3000该攻击对处于烧伤状态的敌人，\\n\u3000伤害会变为1.8倍。\\n·对前方中范围的敌人造成中等物理伤害。\\n·对前方小范围的敌人造成中等魔法伤害，\\n\u3000使其变成烧伤状态。');
insert into unit_enemy_data values (306400, '野性飞鸦', 306400, 0, 16, 270, 1000, 1, 3.5, 0, 0, 0, '【物理】作为荒山的捕食者君临此地的凶恶怪鸟兽。\\n利用通过无数次狩猎锻炼而成的惊人怪力与硬爪袭向入侵者。\\n\\n·对敌方全体造成物理伤害（大），并降低其技能值上升量。每次发动都会提升造成的伤害。这个效果最多可以累积三次。\\n\\n·以后方第二名敌人为中心，造成小范围的物理伤害（小），并赋予麻痹状态。');
insert into unit_enemy_data values (306500, '部落兽人', 306500, 0, 16, 270, 1000, 1, 0.9, 0, 0, 0, '【物理】边境森林中的兽人们的头目。四处传播其具有独特民族性的奇怪旋律。那奇怪的声音可令敌人陷入混乱。\\n\\n·对敌方全体造成物理伤害（大），并降低其物理防御力与魔法防御力，同时提升自身的物理攻击力与魔法攻击力。\\n\\n·对前方四名敌人造成魔法伤害（小），当敌人的生命值降至70%以下时，赋予混乱状态。');
insert into unit_enemy_data values (306501, '吵闹兽人', 306501, 0, 16, 270, 1000, 1, 0.9, 0, 0, 0, '【物理】被露娜之塔的力量所魅惑的兽人魁首。\\n以奇特的太鼓旋律在战场上引起骚乱。\\n\\n·对敌方全体造成物理伤害（大），并降低其物理防御力\\n\u3000和魔法防御力。同时提升自身的\\n\u3000物理攻击力和魔法攻击力。\\n·对前方三名角色造成魔法伤害（小），\\n\u3000并将其小幅度击飞。若敌人生命值低于\\n\u300070%，使其陷入混乱状态。\\n·根据剩余的生命值，对敌方全体造成魔法伤害（大），\\n并降低其行动速度。\\n\u3000同时解除敌方全体的\\n\u3000属性值提升效果。');
insert into unit_enemy_data values (306600, '毒液沙罗曼蛇', 306600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】在水边洒满剧毒，以此袭击猎物的山椒鱼魔物。积存在其身体里的剧毒十分危险，光是靠近都能令猎物失去意识。\\n\\n·对敌方全体造成魔法伤害（中），并赋予毒状态。同时赋予猛毒状态。\\n\\n·对前方范围内的敌人造成魔法伤害（小），并赋予猛毒状态。');
insert into unit_enemy_data values (306700, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因被痛骂而暴走的巨大巧克力魔兽。\\n呢喃爱意一不小心也会化作伤害他人的刀刃。\\n\\n·必杀技能会根据敌方全体角色的\\n\u3000最大生命值给予物理伤害（大），\\n\u3000处于烧伤状态时，会追加伤害。\\n·给予前方三名角色物理伤害（中），\\n\u3000使其眩晕。\\n\u3000并且角色的生命值低于50%时，\\n\u3000会使其变成烧伤状态。\\n·丑萌巧克力兽自身的生命值\\n\u3000低于50%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306701, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因被痛骂而暴走的巨大巧克力魔兽。\\n呢喃爱意一不小心也会化作伤害他人的刀刃。\\n\\n·必杀技能会根据敌方全体角色的\\n\u3000最大生命值给予物理伤害（大），\\n\u3000处于烧伤状态时，会追加伤害。\\n·给予前方三名角色物理伤害（中），\\n\u3000使其眩晕。\\n\u3000并且角色的生命值低于50%时，\\n\u3000会使其变成烧伤状态。');
insert into unit_enemy_data values (306702, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因被痛骂而暴走的巨大巧克力魔兽。\\n呢喃爱意一不小心也会化作伤害他人的刀刃。\\n\\n·必杀技能会根据敌方全体角色的\\n\u3000最大生命值给予物理伤害（大），\\n\u3000处于烧伤状态时，会追加伤害。\\n·给予前方三名角色物理伤害（中），\\n\u3000使其眩晕。\\n\u3000并且角色的生命值低于50%时，\\n\u3000会使其变成烧伤状态。\\n·丑萌巧克力兽自身的生命值\\n\u3000低于50%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306703, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因被痛骂而暴走的巨大巧克力魔兽。\\n呢喃爱意一不小心也会化作伤害他人的刀刃。\\n\\n·必杀技能会根据敌方全体角色的\\n\u3000最大生命值给予物理伤害（大），\\n\u3000处于烧伤状态时，会追加伤害。\\n·给予前方三名角色物理伤害（中），\\n\u3000使其眩晕。\\n\u3000并且角色的生命值低于50%时，\\n\u3000会使其变成烧伤状态。\\n·丑萌巧克力兽自身的生命值\\n\u3000低于50%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306704, '丑萌巧克力兽', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE1】猛烈喷射巧克力，将自身覆盖隐藏。\\n不断受到敌人的攻击，爆发愤怒的一击。\\n\\n·给予敌方全体物理伤害（小），使其战斗期间\\n\u3000变为烧伤状态。\\n·藏在巧克力巨蛋之中时，\\n\u3000丑萌巧克力兽自身的物理防御力中幅提升。\\n\u3000解除巧克力巨蛋状态后，会根据在此\\n\u3000期间所受到的伤害量反击\\n\u3000给予物理伤害。\\n\u3000并且丑萌巧克力兽自身的物理防御力\\n\u3000大幅下降。');
insert into unit_enemy_data values (306705, '丑萌巧克力兽', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【MODE2】可可兽振奋起来，\\n为了从激化的魔物攻击下，\\n 保护重要的人们\\n 投身死地。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值给予物理伤害（大），\\n·可可兽会作为角色的同伴出现。\\n\u3000可可兽出现期间，角色全体的物理\\n\u3000攻击力和行动速度中幅提升。\\n·给予敌方全体魔法伤害（小），\\n\u3000大幅降低其行动速度。\\n');
insert into unit_enemy_data values (306706, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【MODE3】轰鸣的咆哮声回响在会场之中。\\n爱恨交织的情人节事变终于迎来终局。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值给予物理伤害（大），\\n\u3000烧伤状态下，追加伤害。\\n·给予前方三名角色物理伤害（中），\\n\u3000使其眩晕。\\n\u3000角色的生命值低于50%时，\\n\u3000使其陷入烧伤状态。');
insert into unit_enemy_data values (306708, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因恶毒的言语而暴走的巨大巧克力魔物。\\n呢喃的爱意若被误解，也会化作伤害他人的刀刃。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n\\n·根据角色的最大生命值，对前方三名角色\\n\u3000造成物理伤害（中），并使其陷入\\n\u3000烧伤状态。');
insert into unit_enemy_data values (306709, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因恶毒的言语而暴走的巨大巧克力魔物。\\n呢喃的爱意若被误解，也会化作伤害他人的刀刃。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n\\n·根据角色的最大生命值，对前方三名角色\\n\u3000造成物理伤害（中），并使其陷入\\n\u3000烧伤状态。\\n·丑萌巧克力兽自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306710, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【物理】因恶毒的言语而暴走的巨大巧克力魔物。\\n呢喃的爱意若被误解，也会化作伤害他人的刀刃。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大），\\n\u3000若处于烧伤状态，则赋予追加伤害。\\n\\n·根据角色的最大生命值，对前方三名角色\\n\u3000造成物理伤害（中），并使其陷入\\n\u3000烧伤状态。\\n·丑萌巧克力兽自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306711, '丑萌巧克力兽', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【阶段1】强烈喷射巧克力，覆盖自身，隐藏起来。\\n不断受到敌人的攻击，爆发愤怒的一击。\\n\\n·对敌方全体造成物理伤害（小），使其在战斗期间\\n\u3000一直处于烧伤状态。\\n·藏在巧克力巨蛋之中时，\\n\u3000中幅提升丑萌巧克力兽自身的物理防御力。\\n\u3000解除巧克力巨蛋状态后，会根据在此\\n\u3000期间所受到的伤害量进行反击，\\n·造成物理伤害。\\n\u3000并且大幅降低丑萌巧克力兽自身的\\n\u3000物理防御力。');
insert into unit_enemy_data values (306712, '丑萌巧克力兽', 306700, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【阶段2】可可兽振奋起来，\\n为了在狂暴化的魔物攻击下，\\n保护重要的人们而自我牺牲。\\n\\n·必杀技能对敌方全体造成与角色\\n 最大生命值相应的物理伤害（大）。\\n·可可兽会作为角色的同伴出现。\\n 可可兽出现期间，中幅提升全体角色的\\n 物理攻击力、魔法攻击力和行动速度。\\n·对敌方全体造成魔法伤害（小），\\n 并大幅降低其行动速度。\\n');
insert into unit_enemy_data values (306713, '丑萌巧克力兽', 306700, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【阶段3】轰鸣的咆哮声回响在会场之中。\\n爱恨交织的情人节事变也终于迎来了尾声。\\n\\n·必杀技能对敌方全体造成与角色\\n\u3000最大生命值相应的物理伤害（大），\\n\u3000当目标处于烧伤状态时，追加伤害。\\n·对前方三名敌人造成物理伤害（中），\u3000并使其眩晕。\\n\u3000当角色的生命值降至50％以下时，\\n\u3000赋予烧伤状态。\\n·在战斗开始后，立刻提升自身的\\n\u3000物理攻击力与行动速度。');
insert into unit_enemy_data values (306800, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望，而堕落成魔的悲哀女王。\\n痛哭着用恐怖和诅咒填满一切。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值造成魔法伤害（大），\\n\u3000降低魔法防御力。\\n·对前方第二名、第三名角色\\n\u3000造成魔法伤害（中），使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低物理攻击力，减少技能值。\\n\u3000并且使其陷入诅咒状态。\\n·哀叹女神自身的生命值\\n\u3000降到40％时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306801, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望，而堕落成魔的悲哀女王。\\n痛哭着用恐怖和诅咒填满一切。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值造成魔法伤害（大），\\n\u3000降低魔法防御力。\\n·对前方第二名、第三名角色\\n\u3000造成魔法伤害（中），使其眩晕。');
insert into unit_enemy_data values (306802, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望，而堕落成魔的悲哀女王。\\n痛哭着用恐怖和诅咒填满一切。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值造成魔法伤害（大），\\n\u3000降低魔法防御力。\\n·对前方第二名、第三名角色\\n\u3000造成魔法伤害（中），使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低物理攻击力，减少技能值。\\n\u3000并且使其陷入诅咒状态。\\n\u3000即使被赋予了异常状态免疫效果，\\n\u3000该技能也会生效。\\n·哀叹女神自身的生命值\\n\u3000降到40％时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306803, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望，而堕落成魔的悲哀女王。\\n痛哭着用恐怖和诅咒填满一切。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值造成魔法伤害（大），\\n\u3000降低魔法防御力。\\n·对前方第二名、第三名角色\\n\u3000造成魔法伤害（中），使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低物理攻击力，减少技能值。\\n\u3000并且使其陷入诅咒状态。\\n\u3000即使被赋予了异常状态免疫效果，\\n\u3000该技能也会生效。\\n·哀叹女神自身的生命值\\n\u3000降到40％时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (306804, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE1】将【自卫团】成员作为暗影召唤。\\n企图斩断羁绊，攻击挑战者内心软弱之处。\\n\\n·让暗影出现的\\n·哀叹女神自身不会做出攻击行动。');
insert into unit_enemy_data values (306805, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE2】以永久之黑暗充斥着周围，\\n\u3000可使用诅咒咒语\\n\u3000不断阻碍着冒险者的一切。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值造成魔法伤害（大），\\n\u3000降低魔法防御力。\\n·对前方三名角色造成魔法伤害（小），\\n\u3000降低物理防御力，减少技能值，\\n\u3000降低获取率。\\n\u3000并且使其变成诅咒、混乱状态，降低行动速度。\\n\u3000即使被赋予了异常状态免疫效果，\\n\u3000该技能也会生效。\\n·哀叹女神自身的物理防御力下降。\\n\u3000并且变成诅咒状态，减少技能值。');
insert into unit_enemy_data values (306806, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【MODE3】充满狂气的悲哀，让女王解放了真正的身姿。被诅咒的愿望容不下一丝的希望。\\n\\n·必杀技能根据敌方全体角色的\\n\u3000最大生命值造成魔法伤害（大），\\n\u3000降低魔法防御力。\\n·对前方第二名、第三名角色\\n\u3000造成魔法伤害（中），使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低物理攻击力，减少技能值。\\n\u3000并且使其陷入诅咒状态。\\n\u3000即使被赋予了异常状态免疫效果，\\n\u3000该技能也会生效。');
insert into unit_enemy_data values (306807, '哀叹女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望而堕落成魔的悲哀公主。\\n渴求恸哭，用恐怖和诅咒填满一切。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成魔法伤害（大），\\n\u3000并降低其魔法防御力。\\n·对前方第二名、第三名的角色\\n\u3000造成魔法伤害（中），并使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低其物理攻击力并减少技能值。\\n\u3000同时使其陷入诅咒状态。\\n·哀叹女神自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306808, '哀叹女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望而堕落成魔的悲哀公主。\\n渴求恸哭，用恐怖和诅咒填满一切。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成魔法伤害（大），\\n\u3000并降低其魔法防御力。\\n·根据角色的最大生命值，对前方第二名、第三名的角色\\n\u3000造成魔法伤害（中），\\n\u3000并使其眩晕。');
insert into unit_enemy_data values (306809, '哀叹女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望而堕落成魔的悲哀公主。\\n渴求恸哭，用恐怖和诅咒填满一切。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成魔法伤害（大），\\n\u3000并降低其魔法防御力。\\n·根据角色的最大生命值，对前方第二名、第三名的角色\\n\u3000造成魔法伤害（中），\\n\u3000并使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低其物理攻击力并减少技能值。\\n\u3000同时使其陷入诅咒状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·哀叹女神自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306810, '哀叹女神', 306807, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】因失意和绝望而堕落成魔的悲哀公主。\\n渴求恸哭，用恐怖和诅咒填满一切。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成魔法伤害（大），\\n\u3000并降低其魔法防御力。\\n·根据角色的最大生命值，对前方第二名、第三名的角色\\n\u3000造成魔法伤害（中），\\n\u3000并使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低其物理攻击力并减少技能值。\\n\u3000同时使其陷入诅咒状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·哀叹女神自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (306811, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式1】将【自卫团】成员作为暗影召唤。\\n企图斩断羁绊，攻击挑战者内心软弱之处。\\n\\n·召唤暗影\\n·哀叹女神自身不会做出攻击行动。');
insert into unit_enemy_data values (306812, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式2】为了让四周充满永久之暗，\\n\u3000持续地用诅咒和咒语阻挡着\\n\u3000所有冒险者。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成魔法伤害（大），\\n\u3000并降低其魔法防御力。\\n·对前方三名角色造成魔法伤害（小），\\n\u3000降低其物理防御力，在减少其技能值的同时\\n\u3000降低技能值的上升速度。\\n\u3000并且使其陷入诅咒、混乱状态，降低行动速度。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·降低哀叹女神自身的物理防御力。\\n\u3000并进入诅咒状态，减少技能值。');
insert into unit_enemy_data values (306813, '哀叹女神', 306800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式3】充满狂气的悲哀，让女王解放了\u3000真正的身姿。被诅咒的愿望容不下\u3000一丝的希望。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成魔法伤害（大），\\n\u3000并降低其魔法防御力。\\n·对前方第二名、第三名的角色\\n\u3000造成魔法伤害（中），并使其眩晕。\\n·对前方两名角色造成魔法伤害（小），\\n\u3000降低其物理攻击力并减少技能值。\\n\u3000同时使其陷入诅咒状态。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·战斗开始后，提升自身的魔法攻击力\\n\u3000和行动速度。');
insert into unit_enemy_data values (306900, '三战士图腾', 306900, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】过去曾被人供奉的三名战士的石像。\\n会提升各自的能力，释放出必杀的一击。\\n\\n·更容易受到降低物理攻击力与\\n魔法攻击力的效果影响。\\n·极大幅度提升自身的物理攻击力与\\n\u3000魔法攻击力，对敌方全体造成物理伤害（中）\\n\u3000与魔法伤害（中）。\\n·对前方范围内的敌人造成魔法伤害（小）。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (306901, '三战士图腾', 306901, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】过去曾被人供奉的三战士石像。\\n相互提升各自的能力，释放出必杀的一击。\\n\\n·容易受到物理攻击力下降和魔法攻击力下降的\\n\u3000效果影响。\\n\\n·连结爆发时，特大幅度提升自身的物理攻击力\\n\u3000和魔法攻击力，并对敌方全体造成物理伤害\\n\u3000（中）和魔法伤害（中）。\\n·以前方第一名敌人为中心，对其小范围内的敌\\n\u3000人造成魔法伤害（小）。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (307000, '魔石巨人', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307001, '魔石巨人', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的无畏巨人。\\n以强韧的肉体作为武器，不断释放猛烈的攻击。\\n\\n·容易受物理攻击力提升·下降的效果\\n\u3000影响。\\n·必杀技能给予敌方全体物理伤害（大）。\\n·给予前方三名角色物理伤害（中）。\\n·给予敌方全体物理伤害，造成\\n\u3000大力的击退效果。');
insert into unit_enemy_data values (307002, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307003, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的无畏巨人。\\n以强韧的肉体作为武器，不断释放猛烈的攻击。\\n\\n·容易受物理攻击力提升·下降的效果\\n\u3000影响。\\n·必杀技能给予敌方全体物理伤害（大）。\\n·给予前方三名角色物理伤害（中）。\\n·一定时间内做出防御后，根据期间所受到的\\n\u3000伤害量给予敌方全体物理伤害，\\n\u3000使前方两名角色麻痹。\\n\u3000并且提升自身的物理攻击力。\\n·给予敌方全体物理伤害，造成\\n\u3000大力的击退效果。\\n·魔石巨人自身的生命值降到40%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307004, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的无畏巨人。\\n以强韧的肉体作为武器，不断释放猛烈的攻击。\\n\\n·容易受物理攻击力提升·下降的效果\\n\u3000影响。\\n·必杀技能给予敌方全体物理伤害（大）。\\n·给予前方三名角色物理伤害（中）。\\n·一定时间内做出防御后，根据期间所受到的\\n\u3000伤害量给予敌方全体物理伤害，\\n\u3000使前方两名角色麻痹。\\n\u3000并且提升自身的物理攻击力。\\n·给予敌方全体物理伤害，造成\\n\u3000大力的击退效果。\\n·魔石巨人自身的生命值降到40%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307005, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE1】将【美食殿堂】成员作为暗影\\n召唤。以旅途的回忆为盾，试探三人\\n的弱点。\\n\\n·让暗影出现，\\n·给予前方三名角色物理伤害（中）。\\n·给予敌方全体物理伤害，造成\\n\u3000大力的击退效果。');
insert into unit_enemy_data values (307006, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【MODE2】强韧的肉体能抵挡\\n一切攻击。以愤怒为食粮，巨人会做出\\n怒涛般的强力反击。\\n\\n·容易受物理攻击力提升·下降的效果\\n\u3000影响。\\n·必杀技能给予敌方全体物理伤害（大）。\\n·给予前方三名角色物理伤害（中）。\\n·一定时间内做出防御后，根据期间所受到的\\n\u3000伤害量给予敌方全体物理伤害，\\n\u3000使前方两名角色麻痹。\\n\u3000并且提升自身的物理攻击力。');
insert into unit_enemy_data values (307007, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【MODE3】无畏的巨人，解放了\\n全身的力量。在强大无比的破坏力前\\n耍小聪明的攻击无法奏效。\\n\\n·容易受物理攻击力提升·下降的效果\\n\u3000影响。\\n·必杀技能给予敌方全体物理伤害（大）。\\n·给予前方三名角色物理伤害（中）。\\n·一定时间内做出防御后，根据期间所受到的\\n\u3000伤害量给予敌方全体物理伤害，\\n\u3000使前方两名角色麻痹。\\n\u3000并且提升自身的物理攻击力。\\n·给予敌方全体物理伤害，造成\\n\u3000大力的击退效果。');
insert into unit_enemy_data values (307008, '魔石巨人', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (307009, '魔石巨人', 307000, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的庞然巨人。\\n以强韧的肉体为武器，发动猛烈的攻击。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大）。\\n·对前方三名角色造成物理伤害（中）。\\n·对敌方全体造成物理伤害（中），\\n\u3000并大幅度地将其击退。');
insert into unit_enemy_data values (307010, '魔石巨人', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的庞然巨人。\\n以强韧的肉体为武器，发动猛烈的攻击。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大）。\\n·对前方三名角色造成物理伤害（中）。\\n·对敌方全体造成物理伤害（中），\\n\u3000并大幅度地将其击退。\\n·保持防御姿势一段时间后，根据时间内所受到的\\n\u3000伤害量，对敌方全体造成物理伤害，\\n并降低其行动速度。\\n\u3000同时，使前方两名角色麻痹，\\n\u3000并提升自身的物理攻击力。\\n·当魔石巨人的生命值低于35%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307011, '魔石巨人', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的庞然巨人。\\n以强韧的肉体为武器，发动猛烈的攻击。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大）。\\n·对前方三名角色造成物理伤害（中）。\\n·对敌方全体造成物理伤害（中），\\n\u3000并大幅度地将其击退。\\n·保持防御姿势一段时间后，根据时间内所受到的\\n\u3000伤害量，对敌方全体造成物理伤害，\\n并降低其行动速度。\\n\u3000同时，使前方两名角色麻痹，\\n\u3000并提升自身的物理攻击力。\\n·当魔石巨人的生命值低于35%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307012, '魔石巨人', 307008, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】从异界的魔石中诞生的庞然巨人。\\n以强韧的肉体为武器，发动猛烈的攻击。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成物理伤害（大）。\\n·对前方三名角色造成物理伤害（中）。\\n·保持防御姿势一段时间后，根据时间内所受到的\\n\u3000伤害量，对敌方全体造成物理伤害，\\n并降低其行动速度。\\n\u3000同时，使前方两名角色麻痹，\\n\u3000并提升自身的物理攻击力。\\n·对敌方全体造成物理伤害（中），\\n\u3000并大幅度地将其击退。\\n·当魔石巨人的生命值低于35%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307013, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【模式1】将【美食殿堂】成员作为暗影召唤。以旅途的回忆为盾，试探三人\\n的弱点。\\n\\n·对前方三名角色造成物理伤害（中）。\\n·对敌方全体造成物理伤害（中），\\n\u3000并大幅度地将其击退。');
insert into unit_enemy_data values (307014, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 5.0, 0, 0, 0, '【模式2】强韧的肉体能抵挡\\n一切攻击。以愤怒为食粮，巨人会做出\\n怒涛般的强力反击。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n·连结爆发时，对敌方全体造成物理伤害（中）。\\n·对前方三名角色造成物理伤害（大）。\\n·保持防御姿势一段时间后，根据时间内所受到的\\n\u3000伤害量，对敌方全体造成物理伤害，\\n并使前方两名角色麻痹。\\n\u3000同时提升自身的物理攻击力。');
insert into unit_enemy_data values (307015, '魔石巨人', 307002, 0, 16, 270, 3000, 1, 3.0, 0, 0, 0, '【模式3】庞然的巨人解放了\\n全身的力量。在强大无比的破坏力前，\\n耍小聪明的攻击无法奏效。\\n\\n·容易受到物理攻击力提升·下降的\\n效果影响。\\n·连结爆发时，对敌方全体造成物理伤害（中）。\\n·对前方三名角色造成物理伤害（大）。\\n·保持防御姿势一段时间后，根据时间内所受到的\\n\u3000伤害量，对敌方全体造成物理伤害，\\n并使前方两名角色麻痹。\\n\u3000同时提升自身的物理攻击力。\\n·对敌方全体造成物理伤害（大），\\n\u3000并大幅度地将其击退。\\n·战斗开始后，提升自身的物理攻击力\\n\u3000和行动速度。');
insert into unit_enemy_data values (307100, '机械莉玛（MODE1）', 307100, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '神秘巨型兵器的第1形态，结构坚硬并拥有多彩的技能。\\n使用苹果型的补给机器填充未知的能量，\\n要注意的是，它的连续攻击可以令大范围地区化作焦土！\\n\\n·连结爆发时，对敌方全体造成物理伤害（大）。\\n·对前方一名角色造成物理伤害（小）。\\n·在一定范围内，展开降低物理攻击力和回避率，\\n\u3000并续赋赋予物理伤害的领域。\\n\u3000同时解除前方范围内的角色的\\n\u3000属性值提升效果。\\n·对前方范围内的敌人造成物理伤害（中），\\n\u3000并提升自身的技能值。');
insert into unit_enemy_data values (307101, '机械莉玛（MODE2）', 307101, 0, 16, 270, 3000, 1, 1.2, 0, 0, 0, '神秘巨型兵器的第2形态，会把所有状态都切换为攻击。\\n释放出的原子炉莉玛光线可以将大地燃烧殆尽。\\n对无防备的巨大兵器造成会心一击吧！\\n\\n·连结爆发时，对前方小范围内的敌人\\n\u3000造成物理伤害（特大），对中范围内的敌人造成物理伤害（大），\\n\u3000并对大范围内的敌人造成物理伤害（中），\\n\u3000同时大幅度将其击飞。\\n·对前方一名角色造成物理伤害（小）。\\n·随机对一名角色造成物理伤害（小）。\\n\\n·在一定范围内，展开大幅度降低物理攻击力和魔法攻击力\\n\u3000并持续赋予魔法伤害的领域。\\n\u3000·同时使魔法攻击力最高的两名角色\\n\u3000陷入沉默状态。');
insert into unit_enemy_data values (307102, '机械莉玛（MODE3）', 307102, 0, 16, 270, 3000, 1, 5.5, 0, 0, 0, '神秘巨型兵器的第3形态，会自我修复损耗。\\n防卫无人机会阻止外界对满身破绽的本体的攻击。\\n使用范围攻击将无人机一一击退，抓住打倒它的好时机！\\n\\n·大幅度击飞敌方全体，\\n\u3000并召唤3台迷你机械莉玛。\\n·迷你机械莉玛会对前方一名角色\\n\u3000造成物理伤害（小）。\\n·迷你机械莉玛会对随机一名角色\\n\u3000造成魔法伤害（中）。\\n·并根据剩余生命值，对敌方全体\\n\u3000造成一定比例的物理伤害（特大）。');
insert into unit_enemy_data values (307200, '巴吉里斯克', 307200, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】追求露娜魔力飞来的大怪鸟。\\n率领雏鸟，挥下石化的咒剑。\\n\\n·对非石化状态的角色全体造成魔法伤害（大）\\n\u3000使其短时间石化。\\n\u3000对石化状态的角色全员造成最大生命值\\n\u300080%的伤害。\\n·对前方三名角色造成魔法伤害（小）。\\n\u3000并且因该技能伤害\\n\u3000陷入中毒状态的角色会长时间石化。\\n·对前方范围内的角色造成魔法伤害（中）\\n\u3000并且使其变为中毒状态。\\n\u3000自身的生命值降到50％以下时，会对敌方全体\\n\u3000做出反击，召唤出可可。\\n·可可会对前方范围内物理攻击力\\n\u3000最高的一名角色造成物理伤害（小），\\n\u3000并且使其陷入中毒状态。\\n\u3000当自身的生命值处于最大生命的35%以下时，\\n\u3000中幅提升物理攻击力最高的己方同伴的技能值，\\n\u3000自身变为无法战斗状态。');
insert into unit_enemy_data values (307201, '巴吉里斯克', 307201, 0, 16, 270, 3000, 2, 1.8, 0, 0, 0, '【魔法】随身带着一把石化咒剑的怪鸟。以尾蛇的毒牙\\n腐蚀猎物，以咒剑的石化阻止冒险者前进。\\n\\n·连结爆发时，对所有非处于无法行动状态的角色\\n\u3000造成魔法伤害（大），\\n\u3000并使其陷入石化状态。\\n\u3000对所有处于无法行动状态的角色造成\\n\u3000最大生命值80%的伤害。\\n\u3000同时解除敌方全体的属性值提升效果。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方三名角色造成魔法伤害（小）。\\n\u3000若有处于毒状态的角色因该技能而受到伤害，\\n\u3000则使其陷入石化状态。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并使其陷入毒状态。');
insert into unit_enemy_data values (307300, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的物理伤害（大），\\n\u3000并中幅提升自身的物理攻击力。');
insert into unit_enemy_data values (307301, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的物理伤害（大），\\n\u3000并中幅提升自身的物理攻击力。');
insert into unit_enemy_data values (307302, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的物理伤害（大），\\n\u3000并中幅提升自身的物理攻击力。');
insert into unit_enemy_data values (307303, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的物理伤害（大），\\n\u3000并中幅提升自身的物理攻击力。同时，\\n\u3000令所有已被召唤的家臣的生命值\\n\u3000变为0。\\n·召唤一名会对眼前一名敌人\\n\u3000进行物理攻击的家臣。\\n\u3000当家臣自己的生命值为0时，\\n\u3000会发生大爆炸，对范围内的所有敌人造成\\n\u3000物理伤害（中）。\\n·当恶霸地方官自身的生命值\\n\u3000低于40%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (307304, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】将【纯白之翼\\n兰德索尔分部】的成员作为暗影\\n召唤出来。嘲笑三人坚固情谊的\\n欲望之影将发动强袭。\\n\\n·召唤暗影\\n·对眼前一名敌人进行物理攻击\\n');
insert into unit_enemy_data values (307305, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】以物欲使周围的生物服从自己，\\n其制造出的假象能将任何敌人拖入欲望的旋涡。\\n\\n·对眼前一名敌人进行物理攻击\\n·对敌方全体造成物理伤害（小），\\n\u3000并赋予魅惑状态。\\n');
insert into unit_enemy_data values (307306, '恶霸地方官', 307300, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】当内心充满虚荣之时，\\n就会释放出真正的力量，想以此来支配一切。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的物理伤害（大），\\n\u3000并中幅提升自身的物理攻击力。同时，\\n\u3000令所有已被召唤的家臣的生命值\\n\u3000变为0。\\n·召唤一名会对眼前一名敌人\\n\u3000进行物理攻击的家臣。\\n\u3000当家臣自己的生命值为0时，\\n\u3000会发生大爆炸，对范围内的所有敌人造成\\n\u3000物理伤害（中）。\\n');
insert into unit_enemy_data values (307307, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害，并中幅度提升\\n\u3000自身的物理攻击力。');
insert into unit_enemy_data values (307308, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害，并中幅度提升\\n\u3000自身的物理攻击力。');
insert into unit_enemy_data values (307309, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害，并中幅度提升\\n\u3000自身的物理攻击力。同时，\\n\u3000令所有已被召唤的家臣的生命值\\n\u3000降至0。\\n·召唤一名会对眼前一名敌人\\n\u3000进行物理攻击的家臣。\\n\u3000当家臣的生命值降为0时，\\n\u3000会引发大爆炸，并根据角色最大的生命值，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n·恶霸地方官自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (307310, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】充斥着贪婪欲念的机关人偶。\\n作为大江户镇的暴政者君临此地，\\n极尽蛮横之事。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害，并中幅度提升\\n\u3000自身的物理攻击力。同时，\\n\u3000令所有已被召唤的家臣的生命值\\n\u3000降至0。\\n·召唤一名会对眼前一名敌人\\n\u3000进行物理攻击的家臣。\\n\u3000当家臣的生命值降为0时，\\n\u3000会引发大爆炸，并根据角色最大的生命值，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n·恶霸地方官自身的生命值\\n\u3000低于40%时，会展开更为激烈\\n\u3000凶暴的攻击。');
insert into unit_enemy_data values (307311, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】将【纯白之翼\\n兰德索尔分部】成员作为暗影召唤。嘲笑三人坚固情谊的\\n欲望之影将发动强袭。\\n\\n·对前方一名角色造成物理伤害。');
insert into unit_enemy_data values (307312, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】利用贪念让周围的生物服从自己，\\n并制造出各种假象将对方拖入欲望的漩涡。\\n\\n·对前方一名角色造成物理伤害。\\n·对敌方全体造成物理伤害（小），\\n\u3000并使其陷入诱惑状态。');
insert into unit_enemy_data values (307313, '恶霸地方官', 307307, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】为了主宰一切，充满虚荣的贪欲\\n释放出真正的力量。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害，并中幅度提升\\n\u3000自身的物理攻击力。同时，\\n\u3000令所有已被召唤的家臣的生命值\\n\u3000降至0。\\n·召唤一名会对眼前一名敌人\\n\u3000进行物理攻击的家臣。\\n\u3000当家臣的生命值降为0时，\\n\u3000会引发大爆炸，并根据角色最大的生命值，\\n\u3000对敌方全体造成一定比例的物理伤害。\\n·战斗开始后，提升自身的物理攻击力\\n\u3000和行动速度。');
insert into unit_enemy_data values (307400, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (307401, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在露格尼卡恶名昭彰的魔女教干部。\\n哪怕到了异世界，也仍然遵从着自己的信念，\\n凭借强大的权能“不可视之手”在暗中活跃。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并降低技能值。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n\\n·根据角色的最大生命值，对后方两名角色造成一定比例的\\n\u3000物理伤害。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力小幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力中幅度降低。\\n·中央目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力特大幅度降低。\\n·玩家右侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力大幅度降低。');
insert into unit_enemy_data values (307402, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在露格尼卡恶名昭彰的魔女教干部。\\n哪怕到了异世界，也仍然遵从着自己的信念，\\n凭借强大的权能“不可视之手”在暗中活跃。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并降低技能值。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n\\n·根据角色的最大生命值，对后方两名角色造成一定比例的\\n\u3000物理伤害。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力小幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力中幅度降低。\\n·中央目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力特大幅度降低。\\n·玩家右侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力大幅度降低。\\n·当剩余时间少于40秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (307403, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】在露格尼卡恶名昭彰的魔女教干部。\\n哪怕到了异世界，也仍然遵从着自己的信念，\\n凭借强大的权能“不可视之手”在暗中活跃。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并降低技能值。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n\\n·根据角色的最大生命值，对后方两名角色造成一定比例的\\n\u3000物理伤害。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力小幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力中幅度降低。\\n·中央目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力特大幅度降低。\\n·玩家右侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力大幅度降低。\\n·当剩余时间少于40秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (307404, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】召唤雷姆和拉姆的暗影。\\n被大罪司教的疯狂所吞噬的双胞胎暗影，\\n会化为魔女教的爪牙，阻挡在伙伴的面前。\\n\\n·对眼前一名敌人造成物理伤害。');
insert into unit_enemy_data values (307405, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】威力增强后的权能变得强大无比，\\n将会毫不留情地消灭怠惰的仇敌。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n\\n·根据角色的最大生命值，对后方两名角色造成一定比例的\\n\u3000物理伤害。\\n·对剩余的生命值比例低的一名角色\\n\u3000造成魔法伤害（大），\\n\u3000并赋予倒计时。\\n\u3000当倒计时为0时，根据角色的最大生命值，\\n\u3000造成一定比例的魔法伤害。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力小幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力中幅度降低。\\n·中央目标处于击破状态时，\\n\u3000物理防御力中幅度降低，魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力中幅度降低和魔法防御力大幅度降低，\\n\u3000物理攻击力小幅度降低，魔法攻击力大幅度降低。');
insert into unit_enemy_data values (307406, '培提尔其乌斯', 307400, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】失去理性和人类姿态的狂热信徒，\\n只为执念所行动，为忠爱竭尽全力。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并降低技能值。\\n\u3000同时对敌方全体造成魔法伤害（中）。\\n\\n·根据角色的最大生命值，对后方两名角色造成一定比例的\\n\u3000物理伤害。\\n·玩家左侧的目标处于击破状态时，\\n\u3000物理防御力和魔法防御力小幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力中幅度降低。\\n·中央目标处于击破状态时，\\n\u3000物理防御力中幅度降低，魔法防御力大幅度降低，物理攻击力\\n\u3000小幅度降低，魔法攻击力特大幅度降低。\\n·玩家右侧目标处于击破状态时，\\n\u3000物理防御力中幅度降低和魔法防御力大幅度降低，\\n\u3000物理攻击力小幅度降低，魔法攻击力大幅度降低。\\n·当剩余时间少于40秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (307500, '基兹', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】卷起暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·根据敌方全体角色的最大生命值\\n\u3000造成大量物理伤害。\\n·对前方范围内的敌人造成中等物理伤害，\\n\u3000并使其眩晕。');
insert into unit_enemy_data values (307501, '基兹', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】卷起暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·根据敌方全体角色的最大生命值\\n\u3000造成大量物理伤害。\\n·对前方范围内的敌人造成中等物理伤害，\\n\u3000并使其眩晕。');
insert into unit_enemy_data values (307502, '基兹', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】卷起暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·根据敌方全体角色的最大生命值\\n\u3000造成大量物理伤害。\\n·对前方范围内的敌人造成中等物理伤害，\\n\u3000并使其眩晕。\\n·根据前方范围内的敌方角色的最大生命值\\n\u3000造成中等物理伤害。\\n·基兹自身的生命值降到50%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307503, '基兹', 307500, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】卷起暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·根据敌方全体角色的最大生命值\\n\u3000造成大量物理伤害。\\n·对前方范围内的敌人造成中等物理伤害，\\n\u3000并使其眩晕。\\n·根据前方范围内的敌方角色的最大生命值\\n\u3000造成中等物理伤害。\\n·基兹自身的生命值降到50%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307504, '红极鸟', 307504, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬塔中的魔力，四处肆虐的巨大魔鸟。\\n要是掉以轻心地接近它，便会被暴风与狂雷撕裂。\\n\\n·对敌方全体造成物理伤害（大），并对所有\\n\u3000使用魔法攻击的敌人追加物理伤害（中）。\\n·以前方第二名敌人为中心，造成小范围\\n\u3000物理伤害（小），并使其眩晕。\\n·对前方范围内的敌人造成物理伤害（中），\u3000并小幅度击飞敌人。');
insert into unit_enemy_data values (307505, '基兹', 307505, 0, 3, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】身缠猛烈暴风的大怪鸟。\\n从魔物图鉴中逃出，大肆进行破坏。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对前方范围内的敌人造成物理伤害（中），\\n\u3000并使其眩晕。\\n\\n·根据最大生命值，对前方范围内的敌人\\n\u3000造成物理伤害（中）。\\n·基兹自身的生命值低于50%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307600, '疯狂小丑', 307600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】意图将露娜之塔作为自己舞台的\\n魔界小丑。面带开朗而疯狂的笑容，玩弄着观众的生命。\\n\\n·对敌方全体造成魔法伤害（大），\\n\u3000并赋予黑暗状态。\\n·随机对一名敌人造成六次物理伤害（小），\\n\u3000并对敌方全体造成物理伤害（大）。\\n\u3000越是位于前列的角色，\\n\u3000越容易受到该攻击。\\n·在前方中距离召唤倒计时式炸弹。\\n\u3000炸弹会在召唤后8秒发生大爆炸，\\n\u3000对范围内的所有敌人造成物理伤害（中）。\\n\u3000但是，若炸弹的生命值在爆炸前\\n\u3000低于1%，则会对疯狂小丑造成\\n\u3000最大生命值15％的物理伤害。');
insert into unit_enemy_data values (307700, '阿尔玛', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】从远古开始守护迷宫的防卫兵器。在最深处静静等待着跨越所有陷阱而来的入侵者。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的魔法伤害（特大）。\\n·对前方范围内的敌人造成物理伤害（中）。');
insert into unit_enemy_data values (307701, '阿尔玛', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】从远古开始守护迷宫的防卫兵器。在最深处静静等待着跨越所有陷阱而来的入侵者。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的魔法伤害（特大）。\\n·对前方范围内的敌人造成物理伤害（中）。');
insert into unit_enemy_data values (307702, '阿尔玛', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】从远古开始守护迷宫的防卫兵器。在最深处静静等待着跨越所有陷阱而来的入侵者。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的魔法伤害（特大）。\\n·对前方范围内的敌人造成物理伤害（中）。\\n·对剩余生命值最高的敌人造成与其最大生命值\\n\u3000相应的魔法伤害（中），并赋予麻痹状态。\\n·当阿尔玛自身的生命值低于50％时，\\n\u3000它的攻击会变得更为凶暴。');
insert into unit_enemy_data values (307703, '阿尔玛', 307700, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】从远古开始守护迷宫的防卫兵器。在最深处静静等待着跨越所有陷阱而来的入侵者。\\n\\n·对敌方全体造成与角色的最大生命值\\n\u3000相应的魔法伤害（特大）。\\n·对前方范围内的敌人造成物理伤害（中）。\\n·对剩余生命值最高的敌人造成与其最大生命值\\n\u3000相应的魔法伤害（中），并赋予麻痹状态。\\n·当阿尔玛自身的生命值低于50％时，\\n\u3000它的攻击会变得更为凶暴。');
insert into unit_enemy_data values (307704, '诅咒·阿尔玛', 307704, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】因露娜之塔的魔力而失控的古代兵器。\\n被魔力强化后的守护之力变作摧毁万物的灾难。\\n\\n·对敌方全体造成物理伤害（特大）。\\n\\n·随机3次对前方小范围内的敌人\\n\u3000造成物理伤害（大）。\\n·对魔法攻击力最高的一名角色\\n\u3000造成物理伤害（中），并使其麻痹。\\n\u3000同时，对该角色周围的小范围内的敌人\\n\u3000造成物理伤害（中）。');
insert into unit_enemy_data values (307800, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n为无垠的大地降下哀泣的雨。\\n\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（大），同时击飞敌人。\\n\u3000并对前方范围内的敌人造成\\n\u3000追加的魔法伤害（中）。\\n·对最远的一名敌人造成魔法伤害（中），\\n\u3000并小幅度拉近目标。');
insert into unit_enemy_data values (307801, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n为无垠的大地降下哀泣的雨。\\n\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（大），同时击飞敌人。\\n\u3000并对前方范围内的敌人造成\\n\u3000追加的魔法伤害（中）。\\n·对最远的一名敌人造成魔法伤害（中），\\n\u3000并小幅度拉近目标。');
insert into unit_enemy_data values (307802, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n为无垠的大地降下哀泣的雨。\\n\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（大），同时击飞敌人。\\n\u3000并对前方范围内的敌人造成\\n\u3000魔法伤害（中）。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并小幅度击飞敌人。再对离自己最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对最远的一名敌人造成魔法伤害（中），\\n\u3000并小幅度拉近目标。\\n·当雨神大人自身的生命值低于40%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307803, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n为无垠的大地降下哀泣的雨。\\n\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（大），同时击飞敌人。\\n\u3000并对前方范围内的敌人造成\\n\u3000追加的魔法伤害（中）。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并小幅度击飞敌人。再对离自己最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对最远的一名敌人造成魔法伤害（中），\\n\u3000并小幅度拉近目标。\\n·当雨神大人自身的生命值低于40%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307804, '雨神大人', 307801, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式1】沉浸在悲叹中的雨吉\\n抗拒着众人的想法，又因其过于焦急\\n甚至连自己心念已久的晴吉的声音\\n都听不到了。\\n\\n·展开屏障，完全防御敌人的攻击。\\n\u3000屏障的耐久与伤害量无关，\\n\u3000只要被攻击命中就会减少耐久度，\\n\u3000受到200次攻击后，屏障就会被\\n\u3000破坏。\\n·必杀技能对敌方全体造成魔法伤害（大），\\n\u3000并击飞敌人。同时，对前方范围内的所有敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并小幅度击飞敌人。再对离自己最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。');
insert into unit_enemy_data values (307805, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式2】哀泣的雨伴随着悲伤\\n不断降下。那漆黑的雨滴如悲哀的渴求\\n侵蚀着人们的身心。\\n\\n·在战斗开始时召唤诅咒水晶。\\n\u3000场上存在诅咒水晶期间，\\n\u3000会对敌方全体造成持续伤害。同时，\\n\u3000因某种效果而回复生命值时，\\n\u3000回复效果将会无效，并受到原本回复量10%的\\n\u3000伤害。\\n·必杀技能对敌方全体造成魔法伤害（大），\\n\u3000并击飞敌人。同时，对前方范围内的所有敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并小幅度击飞敌人。再对离自己最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对最远的一名敌人造成魔法伤害（中），\\n\u3000并小幅度拉近目标。');
insert into unit_enemy_data values (307806, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式3】乞求着想要向晴吉赎罪的心\\n化为恸哭的奔流，撕裂着对峙者的内心。\\n爱、友情、所有的感情都将化为尘土。\\n\\n·必杀技能对敌方全体造成魔法伤害（大），\\n\u3000并击飞敌人。同时，对前方范围内的所有敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并小幅度击飞敌人。再对离自己最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对最远的一名敌人造成魔法伤害（中），\\n\u3000并小幅度拉近目标。\\n·当雨神大人自身的生命值低于40%时，\\n\u3000攻击会变得更为凶暴。');
insert into unit_enemy_data values (307807, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n用哀泣的雨吞没无垠的大地。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对距离最远的一名敌人造成魔法伤害（中），\\n\u3000并将其小幅度拉近。');
insert into unit_enemy_data values (307808, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n用哀泣的雨吞没无垠的大地。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对距离最远的一名敌人造成魔法伤害（中），\\n\u3000并将其小幅度拉近。');
insert into unit_enemy_data values (307809, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n用哀泣的雨吞没无垠的大地。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并将其小幅度击飞。同时对距离最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对距离最远的一名敌人造成魔法伤害（中），\\n\u3000并将其小幅度拉近。\\n·雨神大人自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307810, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】自古以来便守护着岛上气候的守护神。\\n对友人的思念令其忧心忡忡，最终变成了令人害怕的模样。\\n用哀泣的雨吞没无垠的大地。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并将其小幅度击飞。同时对距离最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对距离最远的一名敌人造成魔法伤害（中），\\n\u3000并将其小幅度拉近。\\n·雨神大人自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307811, '雨神大人', 307801, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式1】悲痛欲绝的雨吉\\n拒绝了大家的好意，甚至连一直\\n渴望相见的挚友——晴吉的声音\\n现在也无法传递给她。\\n\\n·展开屏障，完全防御敌人的攻击。\\n\u3000屏障的耐久与伤害量无关，\\n\u3000每次受到攻击都会逐渐减少耐久性，\\n\u3000受到200次攻击后，\\n\u3000屏障就会破裂。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对前方范围内的所有敌人\\n\u3000造成魔法伤害（中）。\\n');
insert into unit_enemy_data values (307812, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式2】心酸的眼泪化作雨水，\\n与悲伤一同降下。那漆黑的雨滴如悲哀的渴求，\\n侵蚀人们的身心。\\n\\n·战斗开始时唤出诅咒水晶。\\n·诅咒水晶在战斗中存在的期间，\\n\u3000会持续对敌方全体造成魔法伤害。并且，\\n\u3000若想通过某种效果回复生命值，\\n\u3000该效果将会无效，并受到原本回复量的\\n\u300010%伤害。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并将其小幅度击飞。同时对距离最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对距离最远的一名敌人造成魔法伤害（中），\\n\u3000并将其小幅度拉近。');
insert into unit_enemy_data values (307813, '雨神大人', 307800, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式3】乞求想要得到晴吉宽恕的心\\n化为恸哭的奔流，撕裂着对立者的心。\\n爱、友情、所有的感情都归为尘土。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并将其击飞。\\n\u3000同时根据角色的最大生命值，对前方范围内的\\n\u3000所有敌人造成一定比例的\\n\u3000魔法追加伤害。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并将其小幅度击飞。同时对距离最近的一名敌人\\n\u3000造成追加的魔法伤害（中）。\\n·对距离最远的一名敌人造成魔法伤害（中），\\n\u3000并将其小幅度拉近。\\n·雨神大人自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307900, '卡尔古', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】吞食尸体的凶暴大型魔兽。\\n全身缠绕着强韧的尖刺，会执着地追捕猎物。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n·对前方第三、第四、第五名的角色\\n\u3000造成物理伤害（中），并使其眩晕。');
insert into unit_enemy_data values (307901, '卡尔古', 307900, 0, 16, 270, 1000, 1, 1.9, 0, 0, 0, '【物理】吞食尸体的凶暴大型魔兽。\\n全身缠绕着强韧的尖刺，会执着地追捕猎物。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n·对前方第三、第四、第五名的角色\\n\u3000造成物理伤害（中），并使其眩晕。');
insert into unit_enemy_data values (307902, '卡尔古', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】吞食尸体的凶暴大型魔兽。\\n全身缠绕着强韧的尖刺，会执着地追捕猎物。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n·对前方第三、第四、第五名的角色\\n\u3000造成物理伤害（中），并使其眩晕。\\n·对前方两名角色造成物理伤害（中）。\\n·卡尔古自身的生命值低于50%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (307903, '卡尔古', 307900, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】吞食尸体的凶暴大型魔兽。\\n全身缠绕着强韧的尖刺，会执着地追捕猎物。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成一定比例的物理伤害。\\n·对前方第三、第四、第五名的角色\\n\u3000造成物理伤害（中），并使其眩晕。\\n·对前方两名角色造成物理伤害（中）。\\n·卡尔古自身的生命值低于50%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308000, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n\u3000层数，强化自身的普通攻击与\\n\u3000各种技能的效果。\\n·每发动一次普通攻击就能获得6层“吸魂”。\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（特大）。并获得5层“吸魂”。\\n·对敌方全体造成魔法伤害（小），并降低其技能值，\\n\u3000再展开一个能降低技能值上升量的\\n\u3000领域。技能值的减少量与领域的效果值，\\n\u3000会随奄美魔物保持的“吸魂”层数\\n\u3000而强化。\\n·每次进行攻击，奄美魔物便获得1层“吸魂”\\n\u3000并召唤3只分身，再小幅度击飞\\n\u3000所有敌人。\\n·奄美魔物每受到一次暴击伤害\\n\u3000便减少奄美魔物2层“吸魂”。\\n·每当分身受到暴击伤害时，\\n\u3000便减少奄美魔物1层“吸魂”。\\n·当奄美魔物自身的生命值低于40％时，\\n\u3000它的攻击会变得更为凶暴。\\n\u3000并获得20层“吸魂”。');
insert into unit_enemy_data values (308001, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n\u3000层数，强化自身的普通攻击与\\n\u3000各种技能的效果。\\n·每发动一次普通攻击就能获得6层“吸魂”。\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（特大）。并获得5层“吸魂”。\\n·对敌方全体造成魔法伤害（小），并降低其技能值，\\n\u3000再展开一个能降低技能值上升量的\\n\u3000领域。技能值的减少量与领域的效果值，\\n\u3000会随奄美魔物保持的“吸魂”层数\\n\u3000而强化。\\n·每次进行攻击，奄美魔物便获得1层“吸魂”\\n\u3000并召唤3只分身，再小幅度击飞\\n\u3000所有敌人。\\n·奄美魔物每受到一次暴击伤害\\n\u3000便减少奄美魔物2层“吸魂”。\\n·每当分身受到暴击伤害时，\\n\u3000便减少奄美魔物1层“吸魂”。');
insert into unit_enemy_data values (308002, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n\u3000层数，强化自身的普通攻击与\\n\u3000各种技能的效果。\\n·每发动一次普通攻击就能获得6层“吸魂”。\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（特大）。并获得5层“吸魂”。\\n·对敌方全体造成魔法伤害（小），并降低其技能值，\\n\u3000再展开一个能降低技能值上升量的\\n\u3000领域。技能值的减少量与领域的效果值，\\n\u3000会随奄美魔物保持的“吸魂”层数\\n\u3000而强化。\\n·每次进行攻击，奄美魔物便获得1层“吸魂”\\n\u3000并召唤3只分身，再小幅度击飞\\n\u3000所有敌人。\\n·奄美魔物每受到一次暴击伤害\\n\u3000便减少奄美魔物2层“吸魂”。\\n·每当分身受到暴击伤害时，\\n\u3000便减少奄美魔物1层“吸魂”。\\n·当奄美魔物自身的生命值低于40％时，\\n\u3000它的攻击会变得更为凶暴。\\n\u3000并获得20层“吸魂”。');
insert into unit_enemy_data values (308003, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】现身于黄昏的极恶化身，\\n顺从本能贪婪地吞噬着无数的灵魂。\\n\\n·当战斗开始时，特大幅度提升自身的\\n\u3000魔法攻击力，并展开一个特大幅度降低\\n\u3000敌人队伍物理暴击率与魔法暴击率的\\n\u3000领域。\\n·奄美魔物会根据保有的“吸魂”属性值的\\n\u3000层数，强化自身的普通攻击与\\n\u3000各种技能的效果。\\n·每发动一次普通攻击就能获得6层“吸魂”。\\n·必杀技能对敌方全体造成魔法伤害（特大）。\\n\u3000并获得5层“吸魂”。\\n·对敌方全体造成魔法伤害（小），并降低其技能值，\\n\u3000再展开一个能降低技能值上升量的\\n\u3000领域。技能值的减少量与领域的效果值，\\n\u3000会随奄美魔物保持的“吸魂”层数\\n\u3000而强化。\\n·奄美魔物每受到一次暴击伤害\\n\u3000便减少奄美魔物5层“吸魂”。');
insert into unit_enemy_data values (308004, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】现身于黑夜的怨灵集合，\\n将会撕裂人们的灵魂。\\n\\n·每打倒1只分身，剩余的奄美魔物数量\\n\u3000便会减少1。之后，再次召唤分身。\\n·奄美魔物会根据保有的“吸魂”属性值的\\n\u3000层数，强化自身的普通攻击与\\n\u3000各种技能的效果。\\n·每发动一次普通攻击就能获得6层“吸魂”。\\n·每次进行攻击，奄美魔物便获得1层“吸魂”\\n\u3000并召唤3只分身，再小幅度击飞\\n\u3000所有敌人。\\n·奄美魔物每受到一次暴击伤害\\n\u3000便减少奄美魔物2层“吸魂”。\\n·每当分身受到暴击伤害时，\\n\u3000便减少奄美魔物1层“吸魂”。');
insert into unit_enemy_data values (308005, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】现身于凌晨的跋扈魑魅，\\n终于露出了要吞噬世间一切灵魂的獠牙。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n\u3000层数，强化自身的普通攻击与\\n\u3000各种技能的效果。\\n·每发动一次普通攻击就能获得6层“吸魂”。\\n·必杀技能对敌方全体造成\\n\u3000魔法伤害（特大）。并获得5层“吸魂”。\\n·对敌方全体造成魔法伤害（小），并降低其技能值，\\n\u3000再展开一个能降低技能值上升量的\\n\u3000领域。技能值的减少量与领域的效果值，\\n\u3000会随奄美魔物保持的“吸魂”层数\\n\u3000而强化。\\n·每次进行攻击，奄美魔物便获得1层“吸魂”\\n\u3000并召唤3只分身，再小幅度击飞\\n\u3000所有敌人。\\n·奄美魔物每受到一次暴击伤害\\n\u3000便减少奄美魔物2层“吸魂”。\\n·每当分身受到暴击伤害时，\\n\u3000便减少奄美魔物1层“吸魂”。\\n·当剩余时间还有30秒时，\\n\u3000它的攻击会变得更为凶暴。\\n\u3000并获得20层“吸魂”。');
insert into unit_enemy_data values (308006, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并增加5个“吸魂”。\\n·对敌方全体造成魔法伤害（小）的同时减少其技能值，\\n\u3000并展开降低技能值上升量的\\n\u3000领域。技能值减少量和领域的效果值\\n\u3000会随着奄美魔物保有的“吸魂”个数\\n\u3000增多而强化。\\n·每进行一次攻击，奄美魔物便获得1个“吸魂”\\n并召唤3只分身，同时将敌方全体\\n\u3000小幅度击飞。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少2个。\\n·分身每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少1个。\\n·奄美魔物自身的生命值低于30%时，\\n\u3000会展开更为激烈凶暴的攻击。\\n\u3000并获得20个“吸魂”。');
insert into unit_enemy_data values (308007, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·连结爆发时，根据奄美魔物\\n\u3000保有的“吸魂”个数，对敌方全体造成\\n\u3000一定比例的魔法伤害，\\n\u3000并增加5个“吸魂”。\\n·对敌方全体造成魔法伤害（小）的同时减少其技能值，\\n\u3000并展开降低技能值上升量的\\n\u3000领域。技能值减少量和领域的效果值\\n\u3000会随着奄美魔物保有的“吸魂”个数\\n\u3000增多而强化。\\n·每进行一次攻击，奄美魔物便获得1个“吸魂”\\n并召唤3只分身，同时将敌方全体\\n\u3000小幅度击飞。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少2个。\\n·分身每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少1个。');
insert into unit_enemy_data values (308008, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·连结爆发时，根据奄美魔物\\n\u3000保有的“吸魂”个数，对敌方全体造成\\n\u3000一定比例的魔法伤害，\\n\u3000并增加5个“吸魂”。\\n·对敌方全体造成魔法伤害（小）的同时减少其技能值，\\n\u3000并展开降低技能值上升量的\\n\u3000领域。技能值减少量和领域的效果值\\n\u3000会随着奄美魔物保有的“吸魂”个数\\n\u3000增多而强化。\\n·每进行一次攻击，奄美魔物便获得1个“吸魂”\\n并召唤3只分身，同时将敌方全体\\n\u3000小幅度击飞。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少2个。\\n·分身每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少1个。\\n·奄美魔物自身的生命值低于30%时，\\n\u3000会展开更为激烈凶暴的攻击。\\n\u3000并获得20个“吸魂”。');
insert into unit_enemy_data values (308009, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】现身于黄昏的极恶化身，\\n顺从本能贪婪地吞噬着无数的灵魂。\\n\u3000·战斗开始后，特大幅度提升自身的\\n\u3000魔法攻击力，并展开特大幅度降低敌方全体的\\n\u3000物理暴击率和魔法暴击率的\\n\u3000领域。\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·连结爆发时，根据奄美魔物\\n\u3000保有的“吸魂”个数，对敌方全体造成\\n\u3000一定比例的魔法伤害，\\n\u3000并增加5个“吸魂”。\\n·对敌方全体造成魔法伤害（小）的同时减少其技能值，\\n\u3000并展开降低技能值上升量的\\n\u3000领域。技能值减少量和领域的效果值\\n\u3000会随着奄美魔物保有的“吸魂”个数\\n\u3000增多而强化。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少5个。');
insert into unit_enemy_data values (308010, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】现身于黑夜的怨灵集合，\\n将会撕裂人们的灵魂。\\n·每打倒1只分身，\\n\u3000剩下的奄美魔物数量就减少1只。之后，会再次召唤分身。\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·每进行一次攻击，奄美魔物便获得1个“吸魂”\\n并召唤3只分身，同时将敌方全体\\n\u3000小幅度击飞。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少2个。\\n·分身每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少1个。');
insert into unit_enemy_data values (308011, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】现身于凌晨的跋扈魑魅，\\n终于露出了要吞噬世间一切灵魂的獠牙。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·连结爆发时，根据奄美魔物\\n\u3000保有的“吸魂”个数，对敌方全体造成\\n\u3000一定比例的魔法伤害，\\n\u3000并增加5个“吸魂”。\\n·对敌方全体造成魔法伤害（小）的同时减少其技能值，\\n\u3000并展开降低技能值上升量的\\n\u3000领域。技能值减少量和领域的效果值\\n\u3000会随着奄美魔物保有的“吸魂”个数\\n\u3000增多而强化。\\n·每进行一次攻击，奄美魔物便获得1个“吸魂”\\n并召唤3只分身，同时将敌方全体\\n\u3000小幅度击飞。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少2个。\\n·分身每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少1个。\\n·剩余时间少于30秒时，\\n\u3000会展开更为激烈凶暴的攻击。\\n\u3000并获得20个“吸魂”。');
insert into unit_enemy_data values (308012, '奄美魔物', 308000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】以善良的灵魂为食的凶狠恶灵。\\n为了寻求更好的祭品，会分出更多邪恶的身躯。\\n\\n·奄美魔物会根据保有的“吸魂”属性值的\\n个数，强化自身的普通攻击\\n\u3000和各技能的效果。\\n·每发动一次普通攻击就能获得6个“吸魂”。\\n·连结爆发时，根据奄美魔物\\n\u3000保有的“吸魂”个数，对敌方全体造成\\n\u3000一定比例的魔法伤害，\\n\u3000并增加5个“吸魂”。\\n·对敌方全体造成魔法伤害（小）的同时减少其技能值，\\n\u3000并展开降低技能值上升量的\\n\u3000领域。技能值减少量和领域的效果值\\n\u3000会随着奄美魔物保有的“吸魂”个数\\n\u3000增多而强化。\\n·每进行一次攻击，奄美魔物便获得1个“吸魂”\\n并召唤3只分身，同时将敌方全体\\n\u3000小幅度击飞。\\n·奄美魔物每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少2个。\\n·分身每受到一次暴击伤害，\\n\u3000奄美魔物的“吸魂”都会减少1个。');
insert into unit_enemy_data values (308100, '腾特帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n其强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对后方范围内的敌人造成魔法伤害（中），\\n\u3000使其陷入麻痹状态并特大幅度降低\\n\u3000物理攻击力和魔法攻击力。\\n·经过一定时间后，对敌方单体\\n\u3000造成物理伤害（超特大）。\\n·腾特帕斯自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308101, '腾特帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n其强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对后方范围内的敌人造成魔法伤害（中），\\n\u3000使其陷入麻痹状态并特大幅度降低\\n\u3000物理攻击力和魔法攻击力。');
insert into unit_enemy_data values (308102, '腾特帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n其强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对后方范围内的敌人造成魔法伤害（中），\\n\u3000使其陷入麻痹状态并特大幅度降低\\n\u3000物理攻击力和魔法攻击力。\\n·腾特帕斯自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308103, '腾特帕斯', 308100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】君临海边的巨大软体魔兽。\\n其强韧的触手和钢铁的大鱼叉可以彻底破坏一切。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对后方范围内的敌人造成魔法伤害（中），\\n\u3000使其陷入麻痹状态并特大幅度降低\\n\u3000物理攻击力和魔法攻击力。\\n·经过一定时间后，对敌方单体\\n\u3000造成物理伤害（超特大）。\\n·腾特帕斯自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308200, '剧毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (308201, '剧毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】生长异常的碧的曼德拉草。\\n会用强韧的根茎与坚硬的种子子弹压制眼前的敌人。\\n\\n·根据最大生命值，对前方两名角色造成一定比例\\n\u3000的物理伤害。\\n\\n·连结爆发时，对敌方全体造成物理伤害（大），\\n\u3000并根据造成的\\n\u3000累计伤害量，回复自身的生命值。\\n·持续对敌方全体造成物理伤害（小），\\n\u3000并降低其物理防御力3次。\\n·提升自身的物理攻击力的同时，\\n\u3000增加技能值。');
insert into unit_enemy_data values (308202, '剧毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】生长异常的碧的曼德拉草。\\n会用强韧的根茎与坚硬的种子子弹压制眼前的敌人。\\n\\n·根据最大生命值，对前方两名角色造成一定比例\\n\u3000的物理伤害。\\n\\n·连结爆发时，对敌方全体造成物理伤害（大），\\n\u3000并根据造成的\\n\u3000累计伤害量，回复自身的生命值。\\n·持续对敌方全体造成物理伤害（小），\\n\u3000并降低其物理防御力3次。\\n·提升自身的物理攻击力的同时，\\n\u3000增加技能值。');
insert into unit_enemy_data values (308203, '剧毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】生长异常的碧的曼德拉草。\\n会用强韧的根茎与坚硬的种子子弹压制眼前的敌人。\\n\\n·根据最大生命值，对前方两名角色造成一定比例\\n\u3000的物理伤害。\\n\\n·连结爆发时，对敌方全体造成物理伤害（大），\\n\u3000并根据造成的\\n\u3000累计伤害量，回复自身的生命值。\\n·持续对敌方全体造成物理伤害（小），\\n\u3000并降低其物理防御力3次。\\n·提升自身的物理攻击力的同时，\\n\u3000增加技能值。\\n·曼德拉草的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308204, '剧毒曼德拉草', 308204, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】释放剧毒孢子，将大地\\n化为荒野。\\n以无数的尸骸为温床，遍地绽放\\n剧毒的鲜花。\\n\\n按顺序重复以下行动。\\n·埋入地面期间，获得不会受到\\n\u3000伤害的状态。\\n·对敌方全体赋予强大的毒状态。\\n·解除自身的属性值降低效果后，\\n\u3000极大幅度降低自身的物理防御力\\n\u3000与魔法防御力。');
insert into unit_enemy_data values (308205, '剧毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】带有剧毒的粘液从触手上滴落而下。\\n仅仅一滴便能让泉水干涸，令森林腐化，威胁生命。\\n\\n·对前方两名角色造成物理伤害，\\n\u3000并使其陷入毒状态。\\n\\n·连结爆发时，对敌方全体造成物理伤害（大），\\n\u3000并根据造成的\\n\u3000累计伤害量，回复自身的生命值。\\n\u3000大幅提升处于毒状态中的敌人的伤害量。\\n·持续对敌方全体造成物理伤害（小），\\n\u3000并降低其物理防御力3次。\\n·提升自身的物理攻击力的同时，\\n\u3000增加技能值。');
insert into unit_enemy_data values (308206, '剧毒曼德拉草', 308200, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】绝命的咆哮，巨腕的蹂躏。\\n如花朵般凋零的生命。为自己即将迎来的终结献上摇篮曲，\\n亡骸就此永眠。\\n\\n·根据最大生命值，对前方两名角色造成一定比例的\\n\u3000物理伤害。\\n\\n·连结爆发时，对敌方全体造成物理伤害（大），\\n\u3000并根据造成的\\n\u3000累计伤害量，回复自身的生命值。\\n·持续对敌方全体造成物理伤害（小），\\n\u3000并降低其物理防御力3次。\\n·提升自身的物理攻击力的同时，\\n\u3000增加技能值。\\n·当剩余时间少于40秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (308300, '岛鲸', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。\\n·对前方三名角色造成魔法伤害（大），\\n\u3000并将其大幅度击飞。\\n·岛鲸自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308301, '岛鲸', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。');
insert into unit_enemy_data values (308302, '岛鲸', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。\\n·对前方三名角色造成魔法伤害（大），\\n\u3000并将其大幅度击飞。\\n·岛鲸自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308303, '岛鲸', 308300, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】吞噬了大量探险家的幻岛巨鲸。冷酷无情地送葬深陷欲望与幻想的愚者。\\n\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理伤害（大）。\\n·对敌方全体造成魔法伤害（中），并极大幅度提升\\n\u3000岛鲸自身的物理防御力和魔法防御力。\\n·对前方三名角色造成魔法伤害（大），\\n\u3000并将其大幅度击飞。\\n·岛鲸自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308400, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】被束缚在对自己孩子的执念中的亡父之灵。\\n为了享受与女儿共度的虚假时光，\\n可以毫不留情地屠戮阻挡在自己面前的敌人。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并降低其魔法防御力。\\n·对距离最近的一名敌人造成魔法伤害（大）。\\n\u3000同时根据角色的最大生命值，\\n\u3000对前方三名角色造成一定比例的魔法伤害，\\n\u3000并大幅度将其击飞。');
insert into unit_enemy_data values (308401, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】被束缚在对自己孩子的执念中的亡父之灵。\\n为了享受与女儿共度的虚假时光，\\n可以毫不留情地屠戮阻挡在自己面前的敌人。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并降低其魔法防御力。\\n·对距离最近的一名敌人造成魔法伤害（大）。\\n\u3000同时根据角色的最大生命值，\\n\u3000对前方三名角色造成一定比例的魔法伤害，\\n\u3000并大幅度将其击飞。');
insert into unit_enemy_data values (308402, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】被束缚在对自己孩子的执念中的亡父之灵。\\n为了享受与女儿共度的虚假时光，\\n可以毫不留情地屠戮阻挡在自己面前的敌人。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并降低其魔法防御力。\\n·对距离最近的一名敌人造成魔法伤害（大）。\\n\u3000同时根据角色的最大生命值，\\n\u3000对前方三名角色造成一定比例的魔法伤害，\\n\u3000并大幅度将其击飞。\\n\\n·对距离最远的一名敌人造成物理伤害（中），\\n\u3000并将其拉至距离最近的角色的位置，\\n\u3000同时使其眩晕。\\n·幻影男爵的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308403, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【魔法】被束缚在对自己孩子的执念中的亡父之灵。\\n为了享受与女儿共度的虚假时光，\\n可以毫不留情地屠戮阻挡在自己面前的敌人。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并降低其魔法防御力。\\n·对距离最近的一名敌人造成魔法伤害（大）。\\n\u3000同时根据角色的最大生命值，\\n\u3000对前方三名角色造成一定比例的魔法伤害，\\n\u3000并大幅度将其击飞。\\n\\n·对距离最远的一名敌人造成物理伤害（中），\\n\u3000并将其拉至距离最近的角色的位置，\\n\u3000同时使其眩晕。\\n·幻影男爵的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308404, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式1】召唤【小小甜心】的\\n暗影。\\n天真少女们引领而至的终点，是亡者涌动的永夜国度。\\n\\n·对前方一名敌人造成魔法伤害。');
insert into unit_enemy_data values (308405, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式2】冥府之门悄然敞开，\\n生者之魂堕入深渊。再也无法回来的灵魂，\\n只能以思念为印记，游荡在黑暗之中。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并降低其魔法防御力。\\n\\n·对距离最远的一名敌人造成物理伤害（中），\\n\u3000并将其拉至距离最近的角色的位置，\\n\u3000同时使其眩晕。\\n·对前方三名角色造成魔法伤害（中），\\n\u3000中幅度降低其技能值的同时\\n\u3000中幅度回复幻影男爵的技能值。\\n\u3000并且解除使用物理攻击的前三名角色的\\n\u3000属性值提升效果，\\n\u3000对使用魔法攻击的前三名角色造成\\n\u3000追加的魔法伤害（大）。');
insert into unit_enemy_data values (308406, '幻影男爵', 308400, 0, 16, 270, 3000, 2, 1.6, 0, 0, 0, '【模式3】与挚爱离别的时刻正在逼近。\\n为了反抗悲哀的宿命，\\n怨灵发出了临死前的恸哭。\\n\\n·连结爆发时，根据角色的最大生命值，\\n\u3000对敌方全体造成一定比例的魔法伤害，\\n\u3000并降低其魔法防御力。\\n·对距离最近的一名敌人造成魔法伤害（大）。\\n\u3000同时根据角色的最大生命值，\\n\u3000对前方三名角色造成一定比例的魔法伤害，\\n\u3000并大幅度将其击飞。\\n\\n·对距离最远的一名敌人造成物理伤害（中），\\n\u3000并将其拉至距离最近的角色的位置，\\n\u3000同时使其眩晕。\\n·战斗开始后，提升自身的魔法攻击力\\n\u3000和行动速度。');
insert into unit_enemy_data values (308500, '水瑚麟', 308500, 0, 16, 270, 1000, 1, 2.8, 0, 0, 0, '【物理】被月神魔力所魅惑，变得狂暴的水之神兽。\\n忘记了自己的使命，化为吞噬万物的狂兽。\\n\\n·对敌方全体造成魔法伤害（大），并赋予畏惧状态。\\n\u3000陷入畏惧状态的角色，在一段时间内\\n\u3000必杀技能的攻击力与回复生命值效果都将被减半。\\n·对前方范围内的敌人造成魔法伤害（中），\\n\u3000并根据击中次数，小幅提升自身的\\n\u3000物理防御力。同时，展开一个能造成\\n\u3000魔法伤害的领域。\\n·对前方一名角色造成魔法伤害（大），\\n\u3000并消耗自身的生命值，对敌方全体造成追加的\\n\u3000魔法伤害（中）。\\n\u3000同时，小幅提升自身的物理攻击力与\\n\u3000魔法攻击力。');
insert into unit_enemy_data values (308600, '类龙生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (308601, '类龙生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】如龙？一样展翅飞舞在空中，\\n如龙？一样以灼热的吐息点燃敌人。\\n\\n·在战斗开始时，获得70个“火焰果”。\\n·连结爆发时，根据类龙生物\\n\u3000保有的“火焰果”个数，对敌方全体造成\\n\u3000一定比例的物理伤害。\\n\u3000随后减少60个“火焰果”。\\n\\n·根据角色的最大生命值，对前方三名角色造成一定比例的\\n\u3000物理伤害，并使其眩晕。\\n·一定时间内，物理防御力和魔法防御力会大幅度降低，\\n\u3000在类龙生物吃东西时，\\n\u3000最多可持续获得60个“火焰果”。\\n\u3000如果在吃东西的时候，\\n\u3000类龙生物受到了7500以上的伤害，该技能中断，\\n\u3000并减少30个“火焰果”。');
insert into unit_enemy_data values (308602, '类龙生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】如龙？一样展翅飞舞在空中，\\n如龙？一样以灼热的吐息点燃敌人。\\n\\n·在战斗开始时，获得70个“火焰果”。\\n·连结爆发时，根据类龙生物\\n\u3000保有的“火焰果”个数，对敌方全体造成\\n\u3000一定比例的物理伤害。\\n\u3000随后减少60个“火焰果”。\\n\\n·根据角色的最大生命值，对前方三名角色造成一定比例的\\n\u3000物理伤害，并使其眩晕。\\n·一定时间内，物理防御力和魔法防御力会大幅度降低，\\n\u3000在类龙生物吃东西时，\\n\u3000最多可持续获得60个“火焰果”。\\n\u3000如果在吃东西的时候，\\n\u3000类龙生物受到了20000以上的伤害，该技能中断，\\n\u3000并减少30个“火焰果”。');
insert into unit_enemy_data values (308603, '类龙生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】如龙？一样展翅飞舞在空中，\\n如龙？一样以灼热的吐息点燃敌人。\\n\\n·在战斗开始时，获得70个“火焰果”。\\n·连结爆发时，根据类龙生物\\n\u3000保有的“火焰果”个数，对敌方全体造成\\n\u3000一定比例的物理伤害。\\n\u3000随后减少60个“火焰果”。\\n\\n·根据角色的最大生命值，对前方三名角色造成一定比例的\\n\u3000物理伤害，并使其眩晕。\\n·一定时间内，物理防御力和魔法防御力会大幅度降低，\\n\u3000在类龙生物吃东西时，\\n\u3000最多可持续获得60个“火焰果”。\\n\u3000如果在吃东西的时候，\\n\u3000类龙生物受到了160000以上的伤害，该技能中断，\\n\u3000并减少30个“火焰果”。\\n·类龙生物的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (308604, '类龙生物', 308600, 0, 16, 270, 2160, 1, 1.8, 0, 0, 0, '【模式1】自苍天降下的咆哮撕裂了天空，\\n伪龙在阳光下展开自傲的双翼，降临于此。\\n\\n·类龙生物的生命值低于80%时，\\n\u3000会进入下一模式。\\n\\n·在战斗开始时，获得70个“火焰果”。\\n·连结爆发时，根据类龙生物\\n\u3000保有的“火焰果”个数，对敌方全体造成\\n\u3000一定比例的物理伤害。\\n\u3000随后减少60个“火焰果”。\\n\\n·根据角色的最大生命值，对前方三名角色造成一定比例的\\n\u3000物理伤害，并使其眩晕。\\n·一定时间内，物理防御力和魔法防御力会大幅度降低，\\n\u3000在类龙生物吃东西时，\\n\u3000最多可持续获得60个“火焰果”。\\n\u3000如果在吃东西的时候，\\n\u3000类龙生物受到了150000以上的伤害，该技能中断，\\n\u3000并减少30个“火焰果”。\\n·召唤4只怪物，并小幅度击飞\\n\u3000敌方全体。');
insert into unit_enemy_data values (308605, '类龙生物', 308600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【模式2】在伪龙的呼唤下，森林里的\\n魔物集结于此，拼尽全力地保护它。\\n\\n·打倒魔像、树精、\\n\u3000毒食花后，进入下一模式。\\n\\n·类龙生物对眼前的一名敌人进行\\n\u3000物理攻击。');
insert into unit_enemy_data values (308606, '类龙生物', 308606, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【模式3】对龙的憧憬使蜥蜴觉醒了。空中霸者的吐息将化为焚毁这座小岛的\\n劫火。\\n\\n·在战斗开始时，获得70个“火焰果”。\\n·连结爆发时，根据类龙生物\\n\u3000保有的“火焰果”个数，对敌方全体造成\\n\u3000一定比例的物理伤害。\\n\u3000随后减少60个“火焰果”。\\n\\n·根据角色的最大生命值，对前方三名角色造成一定比例的\\n\u3000物理伤害，并使其眩晕。\\n·一定时间内，物理防御力和魔法防御力会大幅度降低，\\n\u3000在类龙生物吃东西时，\\n\u3000最多可持续获得60个“火焰果”。\\n\u3000如果在吃东西的时候，\\n\u3000类龙生物受到了250000以上的伤害，该技能中断，\\n\u3000并减少30个“火焰果”。\\n·战斗开始后，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (309000, '陆生树懒', 309000, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】贪睡在梦境与现实之间的树懒。\\n被打扰清梦时会大发雷霆，用超能力大肆破坏。\\n·根据角色最大生命值，对敌方全体造成\\n\u3000一定比例的魔法伤害，并大幅度降低物理攻击力\\n\u3000和魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对敌方全体造成魔法伤害（小）。');
insert into unit_enemy_data values (309001, '陆生树懒', 309001, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】贪睡在梦境与现实之间的树懒。\\n被打扰清梦时会大发雷霆，用超能力大肆破坏。\\n·根据角色最大生命值，对敌方全体造成\\n\u3000一定比例的魔法伤害，并大幅度降低物理攻击力\\n\u3000和魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对敌方全体造成魔法伤害（小），并使其眩晕。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。');
insert into unit_enemy_data values (309100, '鳄龙', 309100, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】栖息于大河中的巨鳄魔物。\\n看似呆笨，却会用那柄奇异的长枪溶解大地，封锁冒险者的行动。\\n\\n·对敌方全体造成物理伤害（大），并降低其物理防御力与行动速度。\\n\\n·以前方第三名敌人为中心，造成小范围的物理伤害（小），并赋予束缚状态。');
insert into unit_enemy_data values (309200, '天空女武神', 309200, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】飞舞于战场上空的女武神。\\n会使出让人应接不暇的连射，阻止敌人的前进。\\n\\n·必杀技能对前方范围内最多4名角色\\n\u3000造成物理伤害（大），特大幅度降低其技能值，\\n\u3000大幅度降低其行动速度。\\n·对前方三名角色造成物理伤害（中），\\n\u3000并大幅度提升自身的行动速度。');
insert into unit_enemy_data values (309201, '天空女武神', 309201, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】飞舞于战场上空的女武神。\\n会使出让人应接不暇的连射，阻止敌人的前进。\\n\\n·必杀技能对前方范围内最多4名角色\\n\u3000造成物理伤害（大），特大幅度降低其技能值，\\n\u3000大幅度降低其行动速度。\\n·对前方3名角色造成物理伤害（中），\\n\u3000并大幅降低其物理攻击力和魔法攻击力。\\n\u3000同时大幅提升自身的行动速度。');
insert into unit_enemy_data values (309300, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (309301, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】下定决心背叛主人的精英驯鹿。\\n对贪得无厌的圣诞老人们降下随从真心实意的制裁。\\n\\n·必杀技能会在召唤角色被消灭后，\\n\u3000根据角色的最大生命值\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000承受该伤害后，生命值低于40%的角色\\n\u3000在一段时间内变成驯鹿，\\n\u3000且物理暴击率\\n\u3000和魔法暴击率降低。变成驯鹿后的角色，\\n\u3000只能使用普通攻击。\\n\u3000一段时间内，自身的物理防御力大幅降低。\\n·以最前方的角色为中心，根据角色的最大生命值\\n\u3000对一定范围内的角色\\n\u3000造成物理比例伤害。并提升自己的\\n\u3000物理攻击力。\\n·对最前方的角色造成物理伤害，\\n\u3000将其击退的同时使其眩晕。');
insert into unit_enemy_data values (309302, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】下定决心背叛主人的精英驯鹿。\\n对贪得无厌的圣诞老人们降下随从真心实意的制裁。\\n\\n·必杀技能会在召唤角色被消灭后，\\n\u3000根据角色的最大生命值\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000承受该伤害后，生命值低于40%的角色\\n\u3000在一段时间内变成驯鹿，\\n\u3000且物理暴击率\\n\u3000和魔法暴击率降低。变成驯鹿后的角色，\\n\u3000只能使用普通攻击。\\n\u3000一段时间内，自身的物理防御力大幅降低。\\n·以最前方的角色为中心，根据角色的最大生命值\\n\u3000对一定范围内的角色\\n\u3000造成物理比例伤害。并提升自己的\\n\u3000物理攻击力。\\n·对最前方的角色造成物理伤害，\\n\u3000将其击退的同时使其眩晕。');
insert into unit_enemy_data values (309303, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】下定决心背叛主人的精英驯鹿。\\n对贪得无厌的圣诞老人们降下随从真心实意的制裁。\\n\\n·必杀技能会在召唤角色被消灭后，\\n\u3000根据角色的最大生命值\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000承受该伤害后，生命值低于40%的角色\\n\u3000在一段时间内变成驯鹿，\\n\u3000且物理暴击率\\n\u3000和魔法暴击率降低。变成驯鹿后的角色，\\n\u3000只能使用普通攻击。\\n\u3000一段时间内，自身的物理防御力大幅降低。\\n·以最前方的角色为中心，根据角色的最大生命值\\n\u3000对一定范围内的角色\\n\u3000造成物理比例伤害。并提升自己的\\n\u3000物理攻击力。\\n·对最前方的角色造成物理伤害，\\n\u3000将其击退的同时使其眩晕。\\n·复仇驯鹿的生命值低于50%时，\\n\u3000 会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (309304, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【模式1】召唤克莉丝提娜、望、\\n伊莉亚的暗影。三人扭曲的欲望与多管闲事的心，\\n将化为实体，令圣夜陷入混沌。\\n\\n·对最前方的角色造成物理伤害。');
insert into unit_enemy_data values (309305, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式2】绝望如雪花般洒落在\\n圣夜的街道上。积蓄已久的憎恶将溢出\\n充满欲望的礼物袋。\\n\\n·必杀技能会在召唤角色被消灭后，\\n\u3000根据角色的最大生命值\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000承受该伤害后，生命值低于40%的角色\\n\u3000在一段时间内变成驯鹿，\\n\u3000且物理暴击率\\n\u3000和魔法暴击率降低。变成驯鹿后的角色，\\n\u3000只能使用普通攻击。\\n\u3000一段时间内，自身的物理防御力大幅降低。\\n·以最前方的角色为中心，根据角色的最大生命值\\n\u3000对一定范围内的角色\\n\u3000造成物理比例伤害。并提升自己的\\n\u3000物理攻击力。\\n·在前方展开一个持续一段时间的领域。\\n\u3000在这个领域内的角色，\\n\u3000物理攻击力、物理暴击率、\\n\u3000技能值上升量会大幅降低。\\n·对最前方的角色造成物理伤害，\\n\u3000将其击退的同时使其眩晕。');
insert into unit_enemy_data values (309306, '复仇驯鹿', 309300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式3】负伤的巨兽点燃了\\n反击的狼烟。完全陷于憎恶与愤怒中，将变得\\n残忍无比。\\n\\n·必杀技能会在召唤角色被消灭后，\\n\u3000根据角色的最大生命值\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000承受该伤害后，生命值低于35%的角色\\n\u3000在一定时间内变成驯鹿，\\n\u3000且物理暴击率\\n\u3000和魔法暴击率降低。变成驯鹿后的角色，\\n\u3000只能使用普通攻击。\\n\u3000一段时间内，自身的物理防御力大幅降低。\\n·以最前方的角色为中心，根据角色的最大生命值\\n\u3000对一定范围内的角色\\n\u3000造成物理比例伤害。并提升自己的\\n\u3000物理攻击力。\\n·对最前方的角色造成物理伤害，\\n\u3000将其击退的同时使其眩晕。\\n·战斗开始后，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (309400, '侍从·刀刃（物理）', 309400, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】霸瞳皇帝创造的移动力量储藏库。\\n掌管力量的权能，其巨大的剑戟可斩破一切。\\n\\n·眩晕与击飞有效。\\n\\n·必杀技能会对敌方全体造成与角色\\n\u3000最大生命值相应的物理百分比伤害。\\n\\n·以眼前一名敌人为中心，对范围内的所有敌人\\n\u3000造成与角色的最大生命值相应的\\n\u3000物理百分比伤害。\\n\\n·当侍从·刀刃（物理）的生命值\\n\u3000低于40%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (309500, '侍从·魔能（魔法）', 309500, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】霸瞳皇帝创造的移动力量储藏库。\\n掌管魔法的权能，其无穷的魔力可毁灭一切。\\n\\n·必杀技能会对敌方全体造成与角色\\n\u3000最大生命值相应的魔法百分比伤害。\\n\u3000同时，小幅降低其物理攻击力与魔法攻击力。\\n\\n·对随机一名敌人造成魔法伤害，\\n\u3000并赋予诅咒、麻痹状态，大幅降低其技能值。\\n\\n·当侍从·魔能（魔法）的生命值\\n\u3000低于40%时，会变得更加凶暴，\\n\u3000攻击更为猛烈。');
insert into unit_enemy_data values (309600, '侍从·洛克斯（多部位）', 309600, 0, 16, 270, 1000, 1, 1.8, 0, 0, 0, '【物理】霸瞳皇帝创造的移动力量储藏库。\\n掌管责任与义务的权能，可屠戮广阔领域中的一切。\\n\\n·必杀技能会以眼前一名敌人为中心，\\n\u3000对范围内的所有敌人造成与角色最大生命值\\n\u3000相应的物理百分比伤害，\\n\u3000并对眼前一名敌人造成物理伤害（小）。\\n\\n·以眼前一名敌人为中心，造成与\\n\u3000角色最大生命值相应的\\n物理百分比伤害。\\n\\n·当侍从·洛克斯（多部位）的生命值\\n\u3000低于40%时，会变得更加顽强，\\n\u3000进一步提升自身的防御力。');
insert into unit_enemy_data values (309700, '侍从·铁壁（防卫）', 309700, 0, 16, 270, 1000, 2, 1.8, 0, 0, 0, '【魔法】霸瞳皇帝创造的移动力量储藏库。\\n掌管守护的权能，其坚固的铁壁可防御一切。\\n\\n·必杀技能会大幅提升自身的\\n\u3000物理防御力与魔法防御力。\\n\\n·以眼前一名敌人为中心，对范围内的所有敌人\\n\u3000造成魔法伤害。同时，小幅提升自身的物理防御力\\n\u3000和魔法防御力。\\n\\n·当侍从·铁壁（防卫）的生命值\\n\u3000低于40%时，会变得更加顽强，\\n\u3000进一步提升自身的防御力。');
insert into unit_enemy_data values (309800, '霸瞳皇帝', 309800, 0, 16, 270, 1000, 1, 3.6, 309800, 309800, 0, '王都最终决战_基座单元');
insert into unit_enemy_data values (309801, '霸瞳皇帝', 309801, 0, 16, 270, 1000, 1, 2.4, 309800, 309800, 0, '【模式1】抗拒着一切的悲伤公主。\\n以神自居，沉浸于不详的力量之中。\\n并向整个阿斯特朗举起了狂乱的刀刃。\\n就用无数的剑刃，来穿破守护着自欺欺人的公主的铁壁吧。\\n\\n·展开屏障，完全防御敌人的攻击。\\n\u3000屏障的耐久与伤害量无关，\\n\u3000只要被攻击命中就会减少耐久度，\\n\u3000受到280次攻击后，屏障就会被\\n\u3000破坏。\\n\\n·必杀技能会根据敌方全体的剩余生命值\\n\u3000造成特大百分比伤害。\\n\\n·对敌方全体造成物理伤害（小）与\\n\u3000魔法伤害（小）。');
insert into unit_enemy_data values (309802, '霸瞳皇帝', 309800, 0, 16, 270, 1000, 1, 1.8, 309800, 309800, 0, '【模式2】对渺小之人的反抗表现出些许的急躁。\\n将以自己的大义去制裁那些心怀希望、阻挡自己的人。\\n举起那柄悲愤之剑，将其灵魂化为尘土。\\n以正义的魔法，去对抗伪神所挥出的\\n漆黑之刃吧。\\n\\n·必杀技能会根据敌方全体的剩余生命值\\n\u3000造成特大百分比伤害。\\n\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000并对其周围的所有敌人造成魔法伤害（中），\\n\u3000使其昏迷。昏迷的角色\\n\u3000在受到下次攻击前，都无法行动。\\n\\n·对敌方全体造成物理伤害（小）与\\n\u3000魔法伤害（小）。');
insert into unit_enemy_data values (309803, '霸瞳皇帝', 309800, 0, 16, 270, 1000, 1, 1.6, 309800, 309800, 0, '【模式3】创世神发出了临终的呼声。\\n那因怨恨而吐露的拒绝之语将化为诅咒，\\n折磨众人的身体、精神、灵魂，让一切回归黑暗。\\n此刻即为决战。各位，举起剑来，用自己的双手\\n开拓明天吧。\\n\\n·必杀技能会根据敌方全体的剩余生命值\\n\u3000造成特大百分比伤害。\\n\\n·对眼前一名敌人造成物理伤害（特大），\\n\u3000并对其周围的所有敌人造成魔法伤害（中），\\n\u3000使其昏迷。昏迷的角色\\n\u3000在受到下次攻击前，都无法行动。\\n\\n·对敌方全体造成物理伤害（小）与\\n\u3000魔法伤害（小）。\\n\\n·以最后一名敌人为中心，展开中幅降低\\n\u3000物理防御力与与魔法防御力的领域，\\n\u3000并造成魔法伤害（小），\\n\u3000同时赋予诅咒状态。诅咒所造成的持续伤害\\n\u3000会逐秒增加。\\n\\n·在战斗开始后，大幅提升自身的\\n\u3000行动速度，并小幅提升自身的\\n\u3000魔法防御力。');
insert into unit_enemy_data values (309804, '霸瞳皇帝', 309804, 0, 16, 270, 1000, 1, 1.8, 309800, 309800, 0, '显示地图用');
insert into unit_enemy_data values (309900, '专家哥布林', 309900, 0, 17, 270, 1100, 2, 1.8, 0, 0, 0, '【魔法】企图将塔的魔力占为己有的哥布林学者。\\n用禁术操纵泥塑人偶，强行掠夺敌人的自由。\\n\\n·对敌方全体造成魔法伤害（大），\\n\u3000让所有召唤体、分身即死。\\n·对前方大范围造成与生命值相应的\\n\u3000百分比物理伤害（中），并大幅击飞敌人。\\n\u3000同时，召唤1只污泥人偶。\\n\u3000污泥人偶会对前方第一名或第二名敌人\\n\u3000造成物理伤害，并降低其行动速度。\\n·以前方第二名敌人为中心，造成小范围的\\n\u3000物理伤害（中），并赋予猛毒、眩晕状态。');
insert into unit_enemy_data values (310000, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】传说拥有迅捷速度的山中土地神。\\n自太古时代便为了寻求劲敌，而每日奔波着。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。\\n\u3000对最前方的角色追加物理伤害（特大），\\n\u3000并大幅击飞对方，\\n\u3000使其眩晕。\\n\u3000山神大人每使用一次必杀技能，\\n\u3000自身的物理防御力都会降低。\\n\u3000这个效果可以累积。\\n·对魔法攻击力最高的1名角色，\\n\u3000根据其最大生命值造成魔法比例伤害，\\n\u3000并大幅度降低其技能值。\\n·提升自身的技能值和行动速度。\\n·山神大人的生命值低于55%时，\\n\u3000会展开更为激烈凶暴的攻击，\\n\u3000但自身的物理防御力也会降低。');
insert into unit_enemy_data values (310001, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】传说拥有迅捷速度的山中土地神。\\n自太古时代便为了寻求劲敌，而每日奔波着。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。\\n\u3000对最前方的角色追加物理伤害（特大），\\n\u3000并大幅击飞对方，\\n\u3000使其眩晕。\\n\u3000山神大人每使用一次必杀技能，\\n\u3000自身的物理防御力都会降低。\\n\u3000这个效果可以累积。\\n·提升自身的技能值和行动速度。');
insert into unit_enemy_data values (310002, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】传说拥有迅捷速度的山中土地神。\\n自太古时代便为了寻求劲敌，而每日奔波着。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。\\n\u3000对最前方的角色追加物理伤害（特大），\\n\u3000并大幅击飞对方，\\n\u3000使其眩晕。\\n\u3000山神大人每使用一次必杀技能，\\n\u3000自身的物理防御力都会降低。\\n\u3000这个效果可以累积。\\n·对魔法攻击力最高的1名角色，\\n\u3000根据其最大生命值造成魔法比例伤害，\\n\u3000并大幅度降低其技能值。\\n·提升自身的技能值和行动速度。\\n·山神大人的生命值低于55%时，\\n\u3000会展开更为激烈凶暴的攻击，\\n\u3000但自身的物理防御力也会降低。');
insert into unit_enemy_data values (310003, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】传说拥有迅捷速度的山中土地神。\\n自太古时代便为了寻求劲敌，而每日奔波着。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。\\n\u3000对最前方的角色追加物理伤害（特大），\\n\u3000并大幅击飞对方，\\n\u3000使其眩晕。\\n\u3000山神大人每使用一次必杀技能，\\n\u3000自身的物理防御力都会降低。\\n\u3000这个效果可以累积。\\n·对魔法攻击力最高的1名角色，\\n\u3000根据其最大生命值造成魔法比例伤害，\\n\u3000并大幅度降低其技能值。\\n·提升自身的技能值和行动速度。\\n·山神大人的生命值低于55%时，\\n\u3000会展开更为激烈凶暴的攻击，\\n\u3000但自身的物理防御力也会降低。');
insert into unit_enemy_data values (310004, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】试探冒险者的实力，召唤内在的\\n影子。寒风凛冽，天下险峻，自身的脆弱\\n将受到考验。\\n\\n·对最前方的角色造成物理伤害。');
insert into unit_enemy_data values (310005, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】男子汉的疾驰可震撼大地。\\n仿佛是为了庆祝这幅盛景，目出鲷也飞舞于高山之上。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。\\n\u3000对最前方的角色追加物理伤害（特大），\\n\u3000并大幅击飞对方，\\n\u3000使其眩晕。\\n\u3000山神大人每使用一次必杀技能，\\n\u3000自身的物理防御力都会降低。\\n\u3000这个效果可以累积。\\n·对魔法攻击力最高的2名角色，\\n\u3000根据其最大生命值造成魔法比例伤害，\\n\u3000并大幅度降低技能值。\\n·在后方展开一个降低物理防御力的领域，\\n\u3000并对敌方全体造成物理伤害（中）。\\n\u3000目出鲷离开后背期间，特大幅度降低\\n\u3000山神大人的魔法防御力。');
insert into unit_enemy_data values (310006, '山神大人', 310000, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】给予向神发起竞争的强者最后的试炼。\\n拼上彼此的一切，奔向思念之人。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。\\n\u3000对最前方的角色追加物理伤害（特大），\\n\u3000并大幅击飞对方，\\n\u3000使其眩晕。\\n\u3000山神大人每使用一次必杀技能，\\n\u3000自身的物理防御力都会降低。\\n\u3000这个效果可以累积。\\n·对魔法攻击力最高的1名角色，\\n\u3000根据其最大生命值造成魔法比例伤害，\\n\u3000并大幅度降低其技能值。\\n·提升自身的技能值和行动速度。\\n·战斗开始后，会展开更为激烈凶暴的攻击，\\n\u3000同时会降低自身的\\n\u3000物理防御力。');
insert into unit_enemy_data values (310100, '愤怒巨龙', 310100, 0, 14, 270, 1000, 1, 2.6, 0, 0, 0, '【物理】栖息在忘却的秘境里的年轻巨龙。\\n用灼热的业火烧光闯入禁忌的冒险者。\\n\\n·必杀技能会对敌方全体造成\\n\u3000物理比例伤害，并降低其技能值。\\n·战斗开始时，特大幅度降低自身的技能值。\\n·以前方的1名角色为中心，对一定范围内的角色\\n\u3000造成魔法伤害，\\n\u3000并降低其物理防御力。\\n·对敌方全体造成物理伤害，\\n\u3000并使其陷入烧伤状态。\\n·对敌方全体造成物理伤害，击退对方\\n\u3000并解除属性值提升效果。\\n\\n·所有目标被击破时，特大幅度降低\\n\u3000自身技能值。\\n·愤怒巨龙自身剩余的生命值低于10%时，\\n\u3000会展开更为激烈凶暴的攻击，\\n\u3000且无法被击破。\\n·若战斗超时，会使敌方全体陷入\\n\u3000无法战斗状态。\\n');
insert into unit_enemy_data values (310200, '硬头鲨', 310200, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】作为海蚀洞的支配者君临于此的鲨鱼魔物。\\n将凶恶的欲望倾注到捕食中的海中大恶徒。\\n\\n·对敌方全体造成物理伤害（特大），并降低其物理防御力与魔法攻击力。\\n\\n·对前方范围内的所有敌人造成魔法伤害（小），并降低其技能值与技能值上升量。');
insert into unit_enemy_data values (310201, '贪婪鲨', 310201, 0, 16, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】吸收塔中的魔力，暴饮暴食的巨大鲨鱼。\\n用声波扰乱感官，把迟钝的猎物吃个精光。\\n\\n·对敌方全体造成物理伤害（特大），降低其物理防御力\\n\u3000和魔法攻击力。\\n·对技能值最高的1名敌人造成魔法伤害（中），\\n\u3000使其麻痹。\\n\u3000并且使其陷入挑衅状态。\\n·无视挑衅，对生命值最高的1名敌人\\n\u3000造成每秒都会增加的持续伤害。');
insert into unit_enemy_data values (310300, '反物质兽', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (310301, '反物质兽', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】为寻求爱的力量而显现的负面魔法生物。\\n扭曲人们心中的爱之力量，给世界带来灾难。\\n\\n·必杀技能会从异次元取出道具\\n\u3000发动攻击。根据道具的不同\\n\u3000效果也会有所不同。\\n\u3000若使用锤子进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅降低其物理攻击力。\\n\u3000若使用铜钹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000若使用炸弹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并使其陷入诅咒状态。\\n·以最前方的敌人为中心，\\n\u3000对一定范围内的敌人造成物理伤害（中），\\n\u3000并将其击退。\\n·对一定范围内的所有敌人\\n\u3000造成物理伤害（大）。');
insert into unit_enemy_data values (310302, '反物质兽', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】为寻求爱的力量而显现的负面魔法生物。\\n扭曲人们心中的爱之力量，给世界带来灾难。\\n\\n·必杀技能会从异次元取出道具\\n\u3000发动攻击。根据道具的不同\\n\u3000效果也会有所不同。\\n\u3000若使用锤子进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅降低其物理攻击力。\\n\u3000若使用铜钹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000若使用炸弹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并使其陷入诅咒状态。\\n·以最前方的敌人为中心，\\n\u3000对一定范围内的敌人造成物理伤害（中），\\n\u3000并将其击退。\\n·对一定范围内的所有敌人\\n\u3000造成物理伤害（大）。');
insert into unit_enemy_data values (310303, '反物质兽', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】为寻求爱的力量而显现的负面魔法生物。\\n扭曲人们心中的爱之力量，给世界带来灾难。\\n\\n·必杀技能会从异次元取出道具\\n\u3000发动攻击。根据道具的不同\\n\u3000效果也会有所不同。\\n\u3000若使用锤子进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅降低其物理攻击力。\\n\u3000若使用铜钹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000若使用炸弹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并使其陷入诅咒状态。\\n·以最前方的敌人为中心，\\n\u3000对一定范围内的敌人造成物理伤害（中），\\n\u3000并将其击退。\\n·对一定范围内的所有敌人\\n\u3000造成物理伤害（大）。\\n·反物质兽自身的生命值低于50%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (310304, '反物质兽', 310304, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【模式1】被黑暗的力量所污染，\\n以爱与欲望构成的负面魔法生物。开始残酷地\\n扭曲整个世界。\\n\\n·必杀技能会从异次元取出道具\\n\u3000发动攻击。根据道具的不同\\n\u3000效果也会有所不同。\\n\u3000若使用锤子进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅降低其物理攻击力。\\n\u3000若使用铜钹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000若使用炸弹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并使其陷入诅咒状态。\\n·以最前方的敌人为中心，\\n\u3000对一定范围内的敌人造成物理伤害（中），\\n\u3000并将其击退。\\n·对一定范围内的所有敌人\\n\u3000造成物理伤害（大）。');
insert into unit_enemy_data values (310305, '反物质兽', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式2】召唤魔法少女的暗影。\\n扭曲而负面的绝望阴影，将考验魔法少女们\\n爱与希望的力量。\\n\\n·默默地守望暗影的战斗。');
insert into unit_enemy_data values (310306, '反物质兽', 310300, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式3】愤怒至极的负面魔法生物\\n终于解放了真正的力量。势要彻底摧毁魔法少女的心，\\n以扭曲的爱之力令一切屈服。\\n\\n·必杀技能会从异次元取出道具\\n\u3000发动攻击。根据道具的不同\\n\u3000效果也会有所不同。\\n\u3000若使用锤子进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅降低其物理攻击力。\\n\u3000若使用铜钹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并大幅度降低其魔法攻击力。\\n\u3000若使用炸弹进行攻击，则根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并使其陷入诅咒状态。\\n·以最前方的敌人为中心，\\n\u3000对一定范围内的敌人造成物理伤害（中），\\n\u3000并将其击退。\\n·对一定范围内的所有敌人\\n\u3000造成物理伤害（大）。\\n·战斗开始后，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (310400, '变色龙', 310400, 0, 11, 270, 1000, 1, 2.4, 0, 0, 0, '【物理】潜藏于沼泽林，暗暗瞄准猎物的\\n 变色龙魔物。性格胆小而狡猾，\\n但被惹怒时也会发动冲动的突击。\\n\\n必杀技能会对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低\\n\u3000其物理防御力。\\n\\n·随机对1名角色\\n\u3000造成物理伤害（中）。\\n\\n·变色龙在一定时间内根据背景做出拟态，\\n\u3000极大幅度提升回避率，特大幅度提升行动速度，\\n\u3000大幅降低物理防御力。\\n\\n·对前方3名角色造成\\n\u3000物理伤害（中）。');
insert into unit_enemy_data values (310401, '变色龙', 310401, 0, 11, 270, 1000, 1, 2.4, 0, 0, 0, '【物理】潜藏于沼泽林，暗暗瞄准猎物的\\n 变色龙魔物。性格胆小而狡猾，\\n但被惹怒时也会发动冲动的突击。\\n\\n必杀技能会对敌方全体造成物理伤害（大），\\n\u3000并大幅度降低\\n\u3000其物理防御力。\\n\\n·随机对1名角色\\n\u3000造成物理伤害（中）。\\n\\n·变色龙在一定时间内根据背景做出拟态，\\n\u3000极大幅度提升回避率，特大幅度提升行动速度，\\n\u3000大幅降低物理防御力。\\n\\n·对前方3名角色造成\\n\u3000物理伤害（中）。');
insert into unit_enemy_data values (310500, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '');
insert into unit_enemy_data values (310501, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】拥有时尚体色的巨兔魔物。\\n与外表相反，令人厌烦至极的歌声\\n会震动大地，挫伤冒险者的心。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。随后，\\n\u3000在恢复之前，大幅降低自身的物理防御力\\n\u3000和魔法防御力。\\n·以最前方的1名角色为中心，对一定范围内的角色\\n\u3000造成物理伤害（中），\\n\u3000并降低其行动速度。');
insert into unit_enemy_data values (310502, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】拥有时尚体色的巨兔魔物。\\n与外表相反，令人厌烦至极的歌声\\n会震动大地，挫伤冒险者的心。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。随后，\\n\u3000在恢复之前，大幅降低自身的物理防御力\\n\u3000和魔法防御力。\\n·以最前方的1名角色为中心，对一定范围内的角色\\n\u3000造成物理伤害（中），\\n\u3000并降低其行动速度。\\n·对前方3名角色造成物理伤害（小），\\n\u3000并大幅降低其物理防御力。');
insert into unit_enemy_data values (310503, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【物理】拥有时尚体色的巨兔魔物。\\n与外表相反，令人厌烦至极的歌声\\n会震动大地，挫伤冒险者的心。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。随后，\\n\u3000在恢复之前，大幅降低自身的物理防御力\\n\u3000和魔法防御力。\\n·以最前方的1名角色为中心，对一定范围内的角色\\n\u3000造成物理伤害（中），\\n\u3000并降低其行动速度。\\n·对前方3名角色造成物理伤害（小），\\n\u3000并大幅降低其物理防御力。\\n·喧闹巨兔自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (310504, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式1】召唤New Generations的\\n暗影。在森林遇到的巨兔。\\n三个人能否贯彻不放弃梦想的心，\\n巨兔展现了他们各自的弱点。\\n\\n·对最前方的角色造成物理伤害。');
insert into unit_enemy_data values (310505, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式2】森林中的明星的歌声\\n吸引了众多魔物。热血沸腾的野生宴会\\n于此刻开幕。\\n\\n·打倒蓝色魔像、嗜睡猫头鹰、\\n\u3000啄啄鸟后，进入下一模式。\\n\\n·喧闹巨兔对最前方的1名角色\\n\u3000造成物理伤害。');
insert into unit_enemy_data values (310506, '喧闹巨兔', 310500, 0, 16, 270, 3000, 1, 1.6, 0, 0, 0, '【模式3】宴会也要结束了，巨兔使出\\n最后的力气。咆哮般的破坏之歌阻挡3人的\\n梦想之路。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其击退。随后，\\n\u3000在恢复之前，大幅降低自身的物理防御力\\n\u3000和魔法防御力。\\n·以最前方的1名角色为中心，对一定范围内的角色\\n\u3000造成物理伤害（中），\\n\u3000并降低其行动速度。\\n·对前方3名角色造成物理伤害（小），\\n\u3000并大幅降低其物理防御力。\\n·战斗开始后，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (310600, '纠葛的盆栽宝宝', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '');
insert into unit_enemy_data values (310601, '纠葛的盆栽宝宝', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】不知是魔物还是精灵，\\n拥有巨型身躯的谜团重重的生物。带着纠结的表情喷着迷之花粉，\\n将城市引向一片混乱。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力和\\n\u3000魔法防御力。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000并将其击退。\\n·左右的叶子被击破时，会在一定时间内\\n\u3000消失。\\n·击破左侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破本体时，大幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破右侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (310602, '纠葛的盆栽宝宝', 310600, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】不知是魔物还是精灵，\\n拥有巨型身躯的谜团重重的生物。带着纠结的表情喷着迷之花粉，\\n将城市引向一片混乱。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力和\\n\u3000魔法防御力。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000并将其击退。\\n·召唤球根酱。\\n\u3000球根酱不会成为攻击对象，\\n\u3000在一段时间后会自爆，对前方范围内的角色\\n\u3000造成魔法伤害。\\n·左右的叶子被击破时，会在一定时间内\\n\u3000消失。\\n·击破左侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破本体时，大幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破右侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (310603, '纠葛的盆栽宝宝', 310603, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【魔法】不知是魔物还是精灵，\\n拥有巨型身躯的谜团重重的生物。带着纠结的表情喷着迷之花粉，\\n将城市引向一片混乱。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力和\\n\u3000魔法防御力。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000并将其击退。\\n·召唤球根酱。\\n\u3000球根酱不会成为攻击对象，\\n\u3000在一段时间后会自爆，对前方范围内的角色\\n\u3000造成魔法伤害。\\n·左右的叶子被击破时，会在一定时间内\\n\u3000消失。\\n·击破左侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破本体时，大幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破右侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·盆栽宝宝自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (310604, '纠葛的盆栽宝宝', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '');
insert into unit_enemy_data values (310605, '纠葛的盆栽宝宝', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【模式1】最终变为极其巨大的迷之生物。\\n再次露出纠结的表情，大如瀑布的泪水浸湿了大地，\\n无情地侵蚀着一切。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力和\\n\u3000魔法防御力。\\n·使敌方全体的技能值上升后，展开可以造成\\n\u3000持续魔法伤害的领域。\\n·左右的叶子被击破时，会在一定时间内\\n\u3000消失。\\n·击破左侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破本体时，大幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破右侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (310606, '纠葛的盆栽宝宝', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【模式2】也许是被冒险者的抵抗吓倒，\\n它伫立在那里，露出两叶和那庞大的身躯。然而，其表情依旧是\\n一副无可奈何的样子。\\n\\n·所有目标击破无效。\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力和\\n\u3000魔法防御力。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000并将其击退。\\n·召唤球根酱。\\n\u3000球根酱不会成为攻击对象，\\n\u3000在一段时间后会自爆，对前方范围内的角色\\n\u3000造成魔法伤害。\\n');
insert into unit_enemy_data values (310607, '纠葛的盆栽宝宝', 310604, 0, 16, 270, 3000, 1, 1.6, 310600, 310600, 0, '【模式3】那不变的表情，冒险者终究\\n还是会为生物的疯狂和畏惧\\n而颤抖。生物的谜团究竟能否解开……\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并降低其物理防御力和\\n\u3000魔法防御力。\\n·对前方范围内的敌人造成物理伤害，\\n\u3000并将其击退。\\n·召唤球根酱。\\n\u3000球根酱不会成为攻击对象，\\n\u3000在一段时间后会自爆，对前方范围内的角色\\n\u3000造成魔法伤害。\\n·左右的叶子被击破时，会在一定时间内\\n\u3000消失。\\n·击破左侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破本体时，大幅降低其物理防御力\\n\u3000和魔法防御力。\\n·击破右侧的叶子时，小幅降低其物理防御力\\n\u3000和魔法防御力。');
insert into unit_enemy_data values (310700, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '');
insert into unit_enemy_data values (310701, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】从破格的创意和扭曲的热情中诞生的\\n钢铁巨人。用异常的理论\\n重建基础者的特性，破坏敌人的语言中枢和精神。\\n\\n·自身受到毒、猛毒、诅咒、烧伤效果后，\\n\u3000会大幅降低自身的物理防御力、魔法防御力，\\n\u3000和行动速度。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n·提升自己的物理攻击力后，\\n\u3000对敌方全体造成物理伤害。\\n·根据最大生命值，对前方3名角色造成魔法比例伤害，\\n\u3000并降低其行动速度。');
insert into unit_enemy_data values (310702, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】从破格的创意和扭曲的热情中诞生的\\n钢铁巨人。用异常的理论\\n重建基础者的特性，破坏敌人的语言中枢和精神。\\n\\n·自身受到毒、猛毒、诅咒、烧伤效果后，\\n\u3000会大幅降低自身的物理防御力、魔法防御力，\\n\u3000和行动速度。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n·提升自己的物理攻击力后，\\n\u3000对敌方全体造成物理伤害。\\n·根据最大生命值，对前方3名角色造成魔法比例伤害，\\n\u3000并降低其行动速度。');
insert into unit_enemy_data values (310703, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【物理】从破格的创意和扭曲的热情中诞生的\\n钢铁巨人。用异常的理论\\n重建基础者的特性，破坏敌人的语言中枢和精神。\\n\\n·自身受到毒、猛毒、诅咒、烧伤效果后，\\n\u3000会大幅降低自身的物理防御力、魔法防御力，\\n\u3000和行动速度。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n·提升自己的物理攻击力后，\\n\u3000对敌方全体造成物理伤害。\\n·根据最大生命值，对前方3名角色造成魔法比例伤害，\\n\u3000并降低其行动速度。\\n·好朋友X自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (310704, '好朋友X', 310700, 0, 16, 270, 3000, 1, 4.2, 0, 0, 0, '【模式1】召唤【墨丘利财团】的\\n暗影。就像在嘲笑自己的错误一样，\\n用影子的姿态愚弄大家。\\n\\n·自身受到毒、猛毒、诅咒、烧伤效果后，\\n\u3000会大幅降低自身的物理防御力、魔法防御力，\\n\u3000和行动速度。\\n·对眼前的1名敌人造成物理伤害。');
insert into unit_enemy_data values (310705, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【模式2】钢铁球体用完美的切噜语\\n低语。「切噜」。这些牢牢抓住人心的\\n洗脑话语，确确实实地引诱着人们进入切噜的世界。\\n\\n·随机对1名敌人造成魔法伤害（中），\\n\u3000并使其陷入沉默和诱惑状态。');
insert into unit_enemy_data values (310706, '好朋友X', 310700, 0, 16, 270, 3000, 1, 1.4, 0, 0, 0, '【模式3】钢铁的装置再次矗立在大地上。\\n解锁双刃剑·决胜模式，\\n将好朋友社的3人逼入绝境。\\n\\n·自身受到毒、猛毒、诅咒、烧伤效果后，\\n\u3000会大幅降低自身的物理防御力、魔法防御力，\\n\u3000和行动速度。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n·提升自己的物理攻击力后，\\n\u3000对敌方全体造成物理伤害。\\n·根据最大生命值，对前方3名角色造成魔法比例伤害，\\n\u3000并降低其行动速度。\\n·战斗开始后，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (310800, '忍者头领半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被恶毒监察官雇佣的忍者头领。\\n失去仁义的忍者，为金钱而堕落。然而，\\n熟练的身手依然健在，阻碍大家的前进。\\n\\n·战斗开始后，监察官登场。监察官受到\\n\u3000伤害时，会大幅降低\\n\u3000忍者头领半藏的物理防御力和\\n\u3000魔法防御力。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·变成大蛤蟆吐出毒液，使敌方全体进入\\n\u3000中毒状态。\\n\u3000此攻击必定命中。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (310801, '忍者头领半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被恶毒监察官雇佣的忍者头领。\\n失去仁义的忍者，为金钱而堕落。然而，\\n熟练的身手依然健在，阻碍大家的前进。\\n\\n·战斗开始后，监察官登场。监察官受到\\n\u3000伤害时，会大幅降低\\n\u3000忍者头领半藏的物理防御力和\\n\u3000魔法防御力。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·变成大蛤蟆吐出毒液，使敌方全体进入\\n\u3000中毒状态。此攻击必定命中。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (310802, '忍者头领半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被恶毒监察官雇佣的忍者头领。\\n失去仁义的忍者，为金钱而堕落。然而，\\n熟练的身手依然健在，阻碍大家的前进。\\n\\n·战斗开始后，监察官登场。监察官受到\\n\u3000伤害时，会大幅降低\\n\u3000忍者头领半藏的物理防御力和\\n\u3000魔法防御力。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·变成大蛤蟆吐出毒液，使敌方全体进入\\n\u3000中毒状态。此攻击必定命中。\\n·对敌方全体造成物理伤害（中）。');
insert into unit_enemy_data values (310803, '忍者头领半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】被恶毒监察官雇佣的忍者头领。\\n失去仁义的忍者，为金钱而堕落。然而，\\n熟练的身手依然健在，阻碍大家的前进。\\n\\n·战斗开始后，监察官登场。监察官受到\\n\u3000伤害后，会特大幅度降低\\n\u3000忍者头领半藏的物理防御力和\\n\u3000魔法防御力。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·变成大蛤蟆吐出毒液，使敌方全体进入\\n\u3000中毒状态。自身的生命值低于40%时，敌方全体\\n\u3000陷入猛毒状态。此攻击必定命中。\\n·对敌方全体造成物理伤害（中）。自身的生命值\\n\u3000低于40%时，使敌方全体\\n\u3000陷入眩晕状态。\\n·忍者头领半藏自身的生命值低于40%时，\\n\u3000技能的效果会发生变化。');
insert into unit_enemy_data values (310804, '忍者头领半藏', 310801, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【模式1】召唤【伊丽莎白牧场】的\\n暗影。用幻术制造出的四农士的幻影\\n再次使大家的归宿陷入困境。\\n\\n·对眼前的1名敌人造成物理伤害。');
insert into unit_enemy_data values (310805, '忍者头领半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【模式2】用秘传的通灵术变身成忍蛙，\\n向周围喷射蛤蟆的猛毒。这种猛毒\\n只要吸一口就会腐蚀全身，慢慢地使身体溃烂。\\n\\n·战斗开始后，监察官登场。监察官受到\\n\u3000伤害后，会特大幅度降低\\n\u3000忍者头领半藏的物理防御力和\\n\u3000魔法防御力。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·变成大蛤蟆吐出猛毒，使敌方全体陷入\\n\u3000猛毒状态。此攻击必定命中。\\n·对敌方全体造成物理伤害（中），\\n\u3000并使其陷入眩晕。');
insert into unit_enemy_data values (310806, '忍者头领半藏', 310800, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【模式3】最后，找回身为忍者的尊严，\\n发挥自己真正的力量。紫电一闪，\\n不等发出惨叫就化作了尸体。\\n\\n·战斗开始后，提升自身的技能威力。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·变成大蛤蟆吐出猛毒，使敌方全体陷入\\n\u3000猛毒状态。此攻击必定命中。\\n·对敌方全体造成物理伤害（中），\\n\u3000并使其陷入眩晕。');
insert into unit_enemy_data values (310900, '袭击兰德索尔各地的神秘飞碟', 310900, 0, 16, 270, 3000, 1, 0.1, 0, 0, 0, '【物理】突袭和平的丰收节的神秘飞行物。\\n突然出现在兰德索尔各地，进行破坏和掠夺。\\n\\n·必杀技能会对敌方全体造成物理伤害（大）。\\n·对前方1名角色造成物理伤害（小）。\\n·对剩余生命值最高的1名角色造成物理伤害（小）。\\n·随机对1名角色造成物理伤害（小）。');
insert into unit_enemy_data values (311000, '城堡树精', 311000, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】因塔的魔力发生变异而化为要塞的巨大魔树。\\n把大地的力量变成炮弹，以坚固的身躯\\n将一切破坏殆尽。\\n\\n·对敌方全体造成物理伤害（大）。\\n·对一定范围内的所有敌人造成持续的魔法伤害，\\n\u3000并展开可以降低物理防御力的领域。\\n·以后方第2名角色为中心，对其小范围内的角色\\n\u3000造成物理伤害（中），并降低其技能值。\\n\u3000之后，回复己方全体的技能值。');
insert into unit_enemy_data values (311100, '黑之王炸脖龙', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】从扭曲世界的狭界中显现的黑之王。\\n身上缠绕着黑暗的瘴气，企图蹂躏不可思议之国。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000使其陷入中毒状态并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方2名角色造成物理伤害（中），\\n\u3000并降低其物理防御力和技能值。');
insert into unit_enemy_data values (311101, '黑之王炸脖龙', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】从扭曲世界的狭界中显现的黑之王。\\n身上缠绕着黑暗的瘴气，企图蹂躏不可思议之国。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000使其陷入中毒状态并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方2名角色造成物理伤害（中），\\n\u3000并降低其物理防御力和技能值。');
insert into unit_enemy_data values (311102, '黑之王炸脖龙', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】从扭曲世界的狭界中显现的黑之王。\\n身上缠绕着黑暗的瘴气，企图蹂躏不可思议之国。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000使其陷入中毒状态并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方2名角色造成物理伤害（中），\\n\u3000并降低其物理防御力和技能值。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并大幅降低其魔法防御力。\\n\u3000角色的生命值低于50%时，\\n\u3000降低其行动速度。');
insert into unit_enemy_data values (311103, '黑之王炸脖龙', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【物理】从扭曲世界的狭界中显现的黑之王。\\n身上缠绕着黑暗的瘴气，企图蹂躏不可思议之国。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000使其陷入中毒状态并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方2名角色造成物理伤害（中），\\n\u3000并降低其物理防御力和技能值。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并大幅降低其魔法防御力。\\n\u3000角色的生命值低于50%时，\\n\u3000降低其行动速度。\\n·黑之王炸脖龙自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311104, '黑之王炸脖龙', 311101, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【模式1】身披瘴气黑幕，黑之王\\n再度降临。聚合了黑暗与混沌的障壁，\\n据说也能承受救世主之光的一击。\\n\\n·展开屏障，完全防御敌人的攻击。\\n\u3000屏障在每次受到伤害时\\n\u3000逐渐失去耐久性，受到6500000伤害后\\n\u3000屏障就会破裂。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000使其陷入中毒状态并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并大幅降低其魔法防御力。');
insert into unit_enemy_data values (311105, '黑之王炸脖龙', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【模式2】召唤璃乃、步美、日和莉的\\n暗影。内心的黑暗具象化，暴露\\n自己的弱点。能找回希望之心吗?现在正被质问。\\n\\n·对眼前的1名敌人造成物理伤害。');
insert into unit_enemy_data values (311106, '黑之王炸脖龙', 311100, 0, 16, 270, 1000, 1, 2.1, 0, 0, 0, '【模式3】黑之王解放了终之力，世界渐渐堕入\\n永久的黑暗。大部分书页都染成了黑色，\\n救世主的故事即将迎来终结。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000使其陷入中毒状态并将其击退。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·对前方2名角色造成物理伤害（中），\\n\u3000并降低其物理防御力和技能值。\\n·对前方范围内的角色造成魔法伤害（中），\\n\u3000并大幅降低其魔法防御力。\\n\u3000角色的生命值低于50%时，\\n\u3000降低其行动速度。\\n·黑之王炸脖龙自身的生命值低于40%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311200, '拟花骑士', 311200, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】拟态成巨大花朵的魔物。\\n在被它的美丽所吸引的粗心猎物面前\\n绽放出绝望的光芒。\\n\\n·对前方3名角色造成物理伤害\\n\u3000（大），并对敌方全体造成物\\n\u3000理伤害（大）。\\n\\n·对前方2名角色造成物理伤害\\n\u3000（小），并中幅提升自身的物\\n\u3000理攻击力。\\n\\n·对最前方的角色造成物理伤害\\n\u3000（中），并中幅降低其物理防\\n\u3000御力。\\n\\n·对前方第2名角色造成物理伤害\\n\u3000（中），并中幅降低其物理防\\n\u3000御力。');
insert into unit_enemy_data values (311201, '拟花骑士', 311200, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】拟态成巨大花朵的魔物。\\n在被它的美丽所吸引的粗心猎物面前\\n绽放出绝望的光芒。\\n\\n·对前方3名角色造成物理伤害（大），\\n\u3000并对敌方全体\\n\u3000造成物理伤害（大）。\\n\\n·对前方2名角色造成物理伤害（小），\\n\u3000并中幅提升自身的\\n\u3000物理攻击力。\\n\\n·对最前方的角色造成物理伤害（中），\\n\u3000并中幅降低其\\n\u3000物理防御力。\\n\\n·对前方第2名角色造成物理伤害（中），\\n\u3000并中幅降低其\\n\u3000物理防御力。');
insert into unit_enemy_data values (311300, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 2.8, 0, 0, 0, '');
insert into unit_enemy_data values (311301, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 2.8, 0, 0, 0, '【魔法】附身在空荡荡的心灵空隙处的\\n星之精灵。用过剩的自我意识和单纯的私心\\n来迷惑对方。\\n\\n·必杀技能会根据外遇星持有的【异心】数量，\\n\u3000对敌方全体造成\\n\u3000魔法比例伤害。\\n\u3000外遇星的剩余生命值低于50%时，\\n\u3000会提升造成的伤害。\\n\u3000造成伤害后，外遇星持有的\\n\u3000【异心】数量会变为0。\\n·以最后方的敌人为中心，对一定范围内的敌人\\n\u3000造成魔法伤害，使其陷入诱惑状态，\\n\u3000提升物理攻击力和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。\\n·对前方范围内的敌人造成魔法伤害，\\n\u3000使其陷入诱惑状态，并提升物理攻击力\\n\u3000和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。');
insert into unit_enemy_data values (311302, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【魔法】附身在空荡荡的心灵空隙处的\\n星之精灵。用过剩的自我意识和单纯的私心\\n来迷惑对方。\\n\\n·必杀技能会根据外遇星持有的【异心】数量，\\n\u3000对敌方全体造成\\n\u3000魔法比例伤害。\\n\u3000外遇星的剩余生命值低于50%时，\\n\u3000会提升造成的伤害。\\n\u3000造成伤害后，外遇星持有的\\n\u3000【异心】数量会变为0。\\n·以最后方的敌人为中心，对一定范围内的敌人\\n\u3000造成魔法伤害，使其陷入诱惑状态，\\n\u3000提升物理攻击力和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。\\n·对前方范围内的敌人造成魔法伤害，\\n\u3000使其陷入诱惑状态，并提升物理攻击力\\n\u3000和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。');
insert into unit_enemy_data values (311303, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【魔法】附身在空荡荡的心灵空隙处的\\n星之精灵。用过剩的自我意识和单纯的私心\\n来迷惑对方。\\n\\n·必杀技能会根据外遇星持有的【异心】数量，\\n\u3000对敌方全体造成\\n\u3000魔法比例伤害。\\n\u3000外遇星的剩余生命值低于50%时，\\n\u3000会提升造成的伤害。\\n\u3000造成伤害后，外遇星持有的\\n\u3000【异心】数量会变为0。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成魔法比例伤害。\\n·以最后方的敌人为中心，对一定范围内的敌人\\n\u3000造成魔法伤害，使其陷入诱惑状态，\\n\u3000提升物理攻击力和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。\\n·对前方范围内的敌人造成魔法伤害，\\n\u3000使其陷入诱惑状态，并提升物理攻击力\\n\u3000和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。');
insert into unit_enemy_data values (311304, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【模式1】为了构筑自己的后宫梦，\\n动不动就强制迷惑\\n少女们。\\n\\n·必杀技能会根据外遇星持有的【异心】数量，\\n\u3000对敌方全体造成\\n\u3000魔法比例伤害。\\n\u3000外遇星的剩余生命值低于50%时，\\n\u3000会提升造成的伤害。\\n\u3000造成伤害后，外遇星持有的\\n\u3000【异心】数量会变为0。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成魔法比例伤害。\\n·无视挑衅，对最后方的1名敌人\\n\u3000造成魔法伤害，并将其拉近。\\n·对前方范围内的敌人造成魔法伤害，\\n\u3000使其陷入诱惑状态，并提升物理攻击力\\n\u3000和魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\u3000根据用该技能攻击对象的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。');
insert into unit_enemy_data values (311305, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【模式2】如果连繁星都变得模糊，就会对自己的\\n光辉表现出自信，而这种盲目的自信和对少女的思念\\n则会席卷银河，迷惑一切。\\n\\n·必杀技能会根据外遇星持有的【异心】数量，\\n\u3000对敌方全体造成\\n\u3000魔法比例伤害。\\n\u3000外遇星的剩余生命值低于50%时，\\n\u3000会提升造成的伤害。\\n\u3000造成伤害后，外遇星持有的\\n\u3000【异心】数量会变为0。\\n·对前方范围内的敌人造成魔法伤害，\\n\u3000使其陷入诱惑状态，并提升物理攻击力\\n\u3000和魔法攻击力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n\u3000根据用该技能攻击对象的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。');
insert into unit_enemy_data values (311306, '觉醒·外遇星', 311300, 0, 16, 270, 3000, 2, 3.0, 0, 0, 0, '【模式3】梦想中的后宫破灭，为了让一切回归虚无\\n而解放了真正的力量。为了让所有星星\\n沉入银河，释放出了所有的私心。\\n\\n·必杀技能会根据外遇星持有的【异心】数量，\\n\u3000对敌方全体造成\\n\u3000魔法比例伤害。\\n\u3000外遇星的剩余生命值低于50%时，\\n\u3000会提升造成的伤害。\\n\u3000造成伤害后，外遇星持有的\\n\u3000【异心】数量会变为0。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成魔法比例伤害。\\n·以最后方的敌人为中心，对一定范围内的敌人\\n\u3000造成魔法伤害，使其陷入诱惑状态，\\n\u3000提升物理攻击力和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。\\n·对前方范围内的敌人造成魔法伤害，\\n\u3000使其陷入诱惑状态，并提升物理攻击力\\n\u3000和魔法攻击力。\\n\u3000根据用该技能造成伤害的敌人的数量，\\n\u3000外遇星在一定时间内增加【异心】的数量。');
insert into unit_enemy_data values (311400, '海滨暴君·鲛吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '');
insert into unit_enemy_data values (311401, '海滨暴君·鲛吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】统治海滩一带的近海的海族暴君。\\n从不逃避对于对方的挑衅，\\n绝对不允许对方在领地撒野。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并降低其物理防御力，提升\\n\u3000物理攻击力。\\n·对前方范围内的所有敌人造成物理伤害（大），\\n\u3000并降低其物理防御力。\\n·击退敌方全体。之后的一段时间内，\\n\u3000身披雷电，极大幅度提升自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000鲛吉陷入中毒、猛毒、诅咒、烧伤的效果时，\\n\u3000提升自身的物理防御力和魔法防御力的时间\\n\u3000会变短。');
insert into unit_enemy_data values (311402, '海滨暴君·鲛吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】统治海滩一带的近海的海族暴君。\\n从不逃避对方的挑衅，\\n绝对不允许对方在领地撒野。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并降低其物理防御力，提升\\n\u3000物理攻击力。\\n·对前方范围内的所有敌人造成物理伤害（大），\\n\u3000并降低其物理防御力。\\n·击退敌方全体。之后的一段时间内，\\n\u3000身披雷电，极大幅度提升自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000鲛吉陷入中毒、猛毒、诅咒、烧伤的效果时，\\n\u3000提升自身的物理防御力和魔法防御力的时间\\n\u3000会变短。\\n·鲛吉自身的生命值低于15%时，根据角色最大\\n\u3000生命值，对敌方全体造成物理比例伤害，\\n\u3000在一定时间内使其处于唯独不可使用\\n\u3000连结爆发的状态，降低其魔法攻击力。\\n\u3000并且会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311403, '海滨暴君·鲛吉', 311400, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【物理】统治海滩一带的近海的海族暴君。\\n从不逃避对于对方的挑衅，\\n绝对不允许对方在领地撒野。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并降低其物理防御力，提升\\n\u3000物理攻击力。\\n·对前方范围内的所有敌人造成物理伤害（大），\\n\u3000并降低其物理防御力。\\n·击退敌方全体。之后的一段时间内，\\n\u3000身披雷电，极大幅度提升自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000鲛吉陷入中毒、猛毒、诅咒、烧伤的效果时，\\n\u3000提升自身的物理防御力和魔法防御力的时间\\n\u3000会变短。\\n·鲛吉自身的生命值低于15%时，根据角色最大\\n\u3000生命值，对敌方全体造成物理比例伤害，\\n\u3000在一定时间内使其处于唯独不可使用\\n\u3000连结爆发的状态，降低其魔法攻击力。\\n\u3000并且会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311404, '海滨暴君·鲛吉', 311404, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【模式1】对于扰乱领地的无礼之徒，\\n历经千百次抗争的钢铁肉体，\\n会使出浑身解数进行阻挡。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并降低其物理防御力，提升\\n\u3000物理攻击力。\\n·对前方范围内的所有敌人造成物理伤害（大），\\n\u3000并降低其物理防御力。\\n·对前方3名角色造成物理伤害（大）。并对自身\\n\u3000造成物理伤害，一段时间内特大幅度降低物理防\\n\u3000御力和魔法防御力。');
insert into unit_enemy_data values (311405, '海滨暴君·鲛吉', 311405, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【模式2】小弟们追随绝对的领袖魅力和绝望的\\n狂暴力量，集结在一起。由海族精锐\\n发起的互殴于此刻拉开帷幕。\\n\\n·鲛吉对眼前的1名敌人进行物理攻击。\\n·对前方3名角色造成物理伤害（大）。并对自身\\n\u3000造成物理伤害，一段时间内特大幅度降低物理防\\n\u3000御力和魔法防御力。');
insert into unit_enemy_data values (311406, '海滨暴君·鲛吉', 311404, 0, 16, 270, 3000, 1, 2.8, 0, 0, 0, '【模式3】伴随着凶猛的吼声，暴君\\n开始追击。倾注而下的拳脚风暴绝不会停止，\\n直到将刀刃相向的人打得体无完肤。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并降低其物理防御力，提升\\n\u3000物理攻击力。\\n·对前方范围内的所有敌人造成物理伤害（大），\\n\u3000并降低其物理防御力。\\n·击退敌方全体。之后的一段时间内，\\n\u3000身披雷电，极大幅度提升自身的\\n\u3000物理防御力和魔法防御力。\\n\u3000鲛吉陷入中毒、猛毒、诅咒、烧伤的效果时，\\n\u3000提升自身的物理防御力和魔法防御力的时间\\n\u3000会变短。\\n·鲛吉自身的生命值低于4%时，根据角色最大生\\n\u3000命值，对敌方全体造成物理比例伤害，\\n\u3000在一定时间内使其处于唯独不可使用\\n\u3000连结爆发的状态，降低其魔法攻击力。\\n\u3000并且会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311500, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '');
insert into unit_enemy_data values (311501, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】由于过大的纯粹愿望而暴走的圣弓。\\n如果被它射出的箭射穿，就会化为无力的天使。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000对天使状态的角色赋予诅咒。\\n\u3000该效果所造成的诅咒伤害，\\n\u3000无法回复技能值。\\n·对生命值最低的3名角色造成魔法比例伤害，\\n\u3000使生命值低于60%的角色在一定时间内\\n\u3000变成天使。\\n\u3000变成天使的角色只能\\n\u3000使用普通攻击，身上的属性值提升效果\\n\u3000被解除。');
insert into unit_enemy_data values (311502, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】由于过大的纯粹愿望而暴走的圣弓。\\n如果被它射出的箭射穿，就会化为无力的天使。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000对天使状态的角色赋予诅咒。\\n\u3000该效果所造成的诅咒伤害，\\n\u3000无法回复技能值。\\n·对生命值最低的3名角色造成魔法比例伤害，\\n\u3000使生命值低于60%的角色在一定时间内\\n\u3000变成天使。\\n\u3000变成天使的角色只能\\n\u3000使用普通攻击，身上的属性值提升效果\\n\u3000被解除。\\n·对生命值最高的2名角色造成魔法伤害（中），\\n\u3000并降低其行动速度。\\n·圣洁之弓自身的生命值低于50%时，\\n\u3000会提升魔法攻击力，并展开\\n\u3000更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311503, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【魔法】由于过大的纯粹愿望而暴走的圣弓。\\n如果被它射出的箭射穿，就会化为无力的天使。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000对天使状态的角色赋予诅咒。\\n\u3000该效果所造成的诅咒伤害，\\n\u3000无法回复技能值。\\n·对生命值最低的3名角色造成魔法比例伤害，\\n\u3000使生命值低于60%的角色在一定时间内\\n\u3000变成天使。\\n\u3000变成天使的角色只能\\n\u3000使用普通攻击，身上的属性值提升效果\\n\u3000被解除。\\n·对生命值最高的2名角色造成魔法伤害（中），\\n\u3000并降低其行动速度。\\n·圣洁之弓自身的生命值低于50%时，\\n\u3000会提升魔法攻击力和技能值，并展开\\n\u3000更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311504, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【模式1】扭曲的愿望变成结晶，让人们\\n疯狂。这结晶将封杀一切进攻。\\n\\n·战斗开始时唤出邪念水晶。\\n·邪念水晶在战斗中存在的期间，\\n\u3000会大幅度提升圣洁之弓的物理防御力\\n\u3000和魔法防御力。\\n·邪念水晶一旦被破坏，\\n\u3000圣洁之弓的物理防御力和魔法防御力\\n\u3000会大幅度降低。\\n·对生命值最高的2名角色造成魔法伤害（中），\\n\u3000并降低其行动速度。');
insert into unit_enemy_data values (311505, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【模式2】召唤依里和茜里的暗影。\\n自己的负面形象，考验着双胞胎之间真正的羁绊。\\n\\n·对生命值最低的3名角色造成魔法比例伤害，\\n\u3000使生命值低于60%的角色在一定时间内\\n\u3000变成天使。\\n\u3000变成天使的角色只能\\n\u3000使用普通攻击，身上的属性值提升效果\\n\u3000被解除。');
insert into unit_enemy_data values (311506, '失控的圣洁之弓', 311500, 0, 16, 270, 3000, 2, 2.4, 0, 0, 0, '【模式3】受困于无法实现的愿望，圣弓的权能\\n达到了极致。解放的力量震撼天地，\\n消灭一切邪念。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害，\\n\u3000对天使状态的角色赋予诅咒。\\n\u3000该效果所造成的诅咒伤害，\\n\u3000无法回复技能值。\\n·对生命值最低的3名角色造成魔法比例伤害，\\n\u3000使生命值低于60%的角色在一定时间内\\n\u3000变成天使。\\n\u3000变成天使的角色只能\\n\u3000使用普通攻击，身上的属性值提升效果\\n\u3000被解除。\\n·对生命值最高的2名角色造成魔法伤害（中），\\n\u3000降低其行动速度，并降低其\\n\u3000魔法防御力。\\n·剩余时间少于35秒时，会提升魔法攻击力\\n\u3000和技能值，并展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311600, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】让人类感到恐惧的鬼怪们的首领。\\n煽动手下，秘密策划扩大领地的规模。\\n\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。');
insert into unit_enemy_data values (311601, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】让人类感到恐惧的鬼怪们的首领。\\n煽动手下，秘密策划扩大领地的规模。\\n\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。');
insert into unit_enemy_data values (311602, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】让人类感到恐惧的鬼怪们的首领。\\n煽动手下，秘密策划扩大领地的规模。\\n\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。\\n·幽灵教父自身的生命值低于20%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311603, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【魔法】让人类感到恐惧的鬼怪们的首领。\\n煽动手下，秘密策划扩大领地的规模。\\n\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。\\n·幽灵教父自身的生命值低于20%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311604, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【模式1】为了寻找美味的灵魂，鬼怪们的首领\\n再次现身。带着残暴的家族，\\n蹂躏着人们，使城市充满了尖锐的悲鸣。\\n\\n·战斗开始时，召唤3只\\n\u3000幽灵手下。\\n·每打倒1只幽灵手下，\\n\u3000剩下的幽灵手下数量就减少1只。\\n\u3000之后会再次召唤幽灵手下。\\n·幽灵手下会减少眼前1名角色的\\n\u3000技能值，并回复幽灵教父的\\n\u3000技能值。\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。');
insert into unit_enemy_data values (311605, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '【模式2】对破坏领地的一切进行制裁。\\n一旦踏入他的领地，就会有魑魅魍魉\\n蛀蚀他的生命，让他遭受人间地狱之苦。\\n\\n·战斗开始时，角色的最大生命值\\n\u3000减少35%。减少的生命值直到战斗结束\\n\u3000都无法恢复。\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。');
insert into unit_enemy_data values (311606, '叫怖的幽灵教父', 311600, 0, 16, 270, 3000, 2, 4.0, 0, 0, 0, '【模式3】将积蓄的力量全部倾吐出来，释放\\n真正的力量。为了统治这个世界，他残暴无道至极，\\n将其渲染成地狱。\\n\\n·必杀技能会根据角色原本的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000且减少敌方全体角色10%的最大生命值。减少的生命值直到战斗结束\\n\u3000都无法恢复。\\n·为自身展开物理/魔法无效化屏障。\\n·幽灵教父自身的生命值低于37.5%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (311700, '幽灵兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '幽灵教父的贴身手下。\\n以自身为盾，保护首领免受一切攻击。');
insert into unit_enemy_data values (311701, '幽灵兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '幽灵教父的贴身手下。\\n用锻炼过的炮弹向城市发起特攻。血气方刚地\\n冲锋陷阵，让四处逃窜的人们陷入恐怖的深渊。\\n\\n·幽灵兄弟不会成为攻击的对象。');
insert into unit_enemy_data values (311702, '幽灵兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '幽灵教父的贴身手下。\\n把和炮弹们收取来的优质精气献给首领。\\n\\n·幽灵教父不会成为攻击的对象。\\n·回复幽灵教父的技能值。\\n\u3000幽灵教父陷入无法行动状态时，\\n\u3000不回复技能值。');
insert into unit_enemy_data values (311703, '幽灵兄弟', 311700, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '终于到了出场的时候，气喘吁吁地登场。\\n气势十足的最强盾牌，挫败了对手的心。');
insert into unit_enemy_data values (311800, '幽灵兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '幽灵教父的贴身手下。\\n将收取的精气交给首领，负责辅佐。\\n\\n·回复幽灵教父的技能值。');
insert into unit_enemy_data values (311801, '幽灵兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '幽灵教父的贴身手下。\\n守护在首领的附近，不露出一丝破绽。在背地里\\n暗中活动，试图将城市中的人逼入绝望之中。\\n\\n·幽灵兄弟不会成为攻击的对象。');
insert into unit_enemy_data values (311802, '幽灵兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '幽灵教父的贴身手下。\\n把和部下收取来的优质精气献给首领。\\n\\n·幽灵教父不会成为攻击的对象。\\n·回复幽灵教父的技能值。\\n\u3000幽灵教父陷入无法行动状态时，\\n\u3000不回复技能值。');
insert into unit_enemy_data values (311803, '幽灵兄弟', 311800, 0, 16, 270, 3000, 2, 999.0, 0, 0, 0, '为了守护家族的危机，冷静地\\n观察战况。作为首领忠实的左膀右臂，直到死前\\n都贯彻辅佐任务。\\n\\n·回复幽灵教父的技能值。');
insert into unit_enemy_data values (311900, '洁白独角兽', 311900, 0, 13, 270, 1000, 1, 2.0, 0, 0, 0, '【物理】吞食雾霭，自身的姿态也如\\n雾霭一般难以捉摸。讨厌人类，\\n会毫不留情地消灭靠近的人。\\n\\n·对敌方全体造成魔法伤害（大）。\\n\u3000此外，提升对烧伤状态的敌人\\n\u3000造成的伤害。\\n\\n·以物理攻击力最高的敌人为中心，\\n\u3000对一定范围内造成魔法伤害\\n\u3000（中），并使其陷入烧伤状态。');
insert into unit_enemy_data values (312000, '黑曜双足飞龙', 312000, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】宿有魔力的黑曜石的结晶龙。据说美丽身躯的光辉\\n是彷徨在冥府的灵魂的哀叹。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于60％时，大幅降低\\n\u3000其技能值。\\n·特大幅度降低敌方全体的吸血生命值吸收，并大幅降低\\n\u3000其物理防御力。\\n·对魔法攻击力最高的1名角色造成\\n\u3000物理伤害（大）。\\n\u3000并以魔法攻击力最高的1名角色为中心，\\n\u3000对一定范围内造成物理伤害（中），\\n\u3000中幅降低其技能值。');
insert into unit_enemy_data values (312100, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】夺走人们梦想的负面魔法生物。\\n阴郁的黑雾笼罩着希望，腐蚀着人们的心灵。');
insert into unit_enemy_data values (312101, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】夺走人们梦想的负面魔法生物。\\n阴郁的黑雾笼罩着希望，腐蚀着人们的心灵。\\n\\n·必杀技能会解除敌方全体的屏障，\\n\u3000对其造成魔法伤害（大）。并大幅降低其物理防御力\\n\u3000和魔法防御力，一定时间内生命值回复量\\n\u3000降低70%。\\n·对前方2名角色造成物理伤害（中）。');
insert into unit_enemy_data values (312102, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】夺走人们梦想的负面魔法生物。\\n阴郁的黑雾笼罩着希望，腐蚀着人们的心灵。\\n\\n·必杀技能会解除敌方全体的屏障，\\n\u3000对其造成魔法伤害（大）。并大幅降低其物理防御力\\n\u3000和魔法防御力，一定时间内生命值回复量\\n\u3000降低70%。\\n·对前方2名角色造成物理伤害（中）。');
insert into unit_enemy_data values (312103, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】夺走人们梦想的负面魔法生物。\\n阴郁的黑雾笼罩着希望，腐蚀着人们的心灵。\\n\\n·必杀技能会解除敌方全体的屏障，\\n\u3000对其造成魔法伤害（大）。并大幅降低其物理防御力\\n\u3000和魔法防御力，一定时间内生命值回复量\\n\u3000降低70%。\\n·对前方2名角色造成物理伤害（中）。\\n·反物质兽 de M自身的生命值低于25%时，\\n\u3000小幅提升自身的技能值，\\n\u3000并展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (312104, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式1】从城市中吸取爱和希望的\\n反物质兽。想要打倒魔法少女们，\\n吸收城市里所有闪耀的力量。\\n\\n·必杀技能会解除敌方全体的屏障，\\n\u3000对其造成魔法伤害（大）。并大幅降低其物理防御力\\n\u3000和魔法防御力，一定时间内生命值回复量\\n\u3000降低70%。\\n·根据最后方的1名敌人的生命值\\n\u3000对其造成物理比例伤害（特大），使其陷入束缚状态，\\n\u3000特大幅度降低其技能值。\\n\u3000并小幅提升反物质兽 de M自身的\\n\u3000技能值。');
insert into unit_enemy_data values (312105, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式2】吸收了魔法少女们的猛攻，\\n反物质兽的欲望变得更加膨胀。甚至，\\n保护人们的勇气也被溶蚀。\\n\\n·必杀技能会解除敌方全体的屏障，\\n\u3000对其造成魔法伤害（大）。并大幅降低其物理防御力\\n\u3000和魔法防御力，一定时间内生命值回复量\\n\u3000降低70%。\\n·解除敌方全体的屏障，根据最大生命值\\n\u3000对其造成魔法比例伤害，并使其陷入中毒状态。');
insert into unit_enemy_data values (312106, '反物质兽 de M', 312100, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式3】负面的情绪达到了极点，扭曲的\\n欲望包围了这一带。挫伤了魔法少女们的信念，\\n想要将没有守护者的城市吸收为自己的一部分。\\n\\n·必杀技能会解除敌方全体的屏障，\\n\u3000对其造成魔法伤害（大）。并大幅降低其物理防御力\\n\u3000和魔法防御力，一定时间内生命值回复量\\n\u3000降低70%。\\n·根据最大生命值，对前方2名角色造成\\n\u3000物理比例伤害。\\n·反物质兽 de M自身的生命值低于8%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (312200, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】胖乎乎的目光锐利的最可怕的雪人。\\n浑身笼罩着狂气，在圣夜的街道上兜兜转转。\\n一年一度的特别夜晚变为黑色圣诞节。');
insert into unit_enemy_data values (312201, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 4.0, 0, 0, 0, '【物理】胖乎乎的目光锐利的最可怕的雪人。\\n浑身笼罩着狂气，在圣夜的街道上兜兜转转。\\n一年一度的特别夜晚变为黑色圣诞节。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其大幅击飞。自身的目标没有被击破时，\\n\u3000中幅提升物理防御力，\\n\u3000小幅提升魔法防御力。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理比例伤害。自身的目标没有被击破时，\\n\u3000追加赋予眩晕效果。\\n·剩余时间少于20秒时，会拿出礼物型炸弹，\\n\u3000过一段时间后，根据角色的最大生命值\\n\u3000对敌方全体造成\\n\u3000物理比例伤害。\\n\u3000并且也会根据至尊雪人自身剩余生命值\\n\u3000对其造成物理比例伤害，\\n\u3000特大幅降低其技能值。\\n·击破头部时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·击破躯体时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n');
insert into unit_enemy_data values (312202, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 3.6, 0, 0, 0, '【物理】胖乎乎的目光锐利的最可怕的雪人。\\n浑身笼罩着狂气，在圣夜的街道上兜兜转转。\\n一年一度的特别夜晚变为黑色圣诞节。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其大幅击飞。自身的目标没有被击破时，\\n\u3000中幅提升物理防御力，\\n\u3000小幅提升魔法防御力。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理比例伤害。自身的目标没有被击破时，\\n\u3000追加赋予眩晕效果。\\n·剩余时间少于20秒时，会拿出礼物型炸弹，\\n\u3000过一段时间后，根据角色的最大生命值\\n\u3000对敌方全体造成\\n\u3000物理比例伤害。\\n\u3000并且也会根据至尊雪人自身剩余生命值\\n\u3000对其造成物理比例伤害，\\n\u3000特大幅降低其技能值。\\n·击破头部时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·击破躯体时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n');
insert into unit_enemy_data values (312203, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】胖乎乎的目光锐利的最可怕的雪人。\\n浑身笼罩着狂气，在圣夜的街道上兜兜转转。\\n一年一度的特别夜晚变为黑色圣诞节。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其大幅击飞。自身的目标没有被击破时，\\n\u3000中幅提升物理防御力，\\n\u3000小幅提升魔法防御力。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理比例伤害。自身的目标没有被击破时，\\n\u3000追加赋予眩晕效果。\\n·剩余时间少于30秒时，会展开更为激烈凶暴的\\n\u3000攻击。\\n·剩余时间少于20秒时，会拿出礼物型炸弹，\\n\u3000过一段时间后，根据角色的最大生命值\\n\u3000对敌方全体造成\\n\u3000物理比例伤害。\\n\u3000并且也会根据至尊雪人自身剩余生命值\\n\u3000对其造成物理比例伤害，\\n\u3000大幅降低其技能值。\\n·击破头部时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·击破躯体时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n');
insert into unit_enemy_data values (312204, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式1】使派对会场陷入混乱的\\n巨大的雪不倒翁。原本是深受人们喜爱的\\n善良的吉祥物。大家的支持是进攻的关键。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其大幅击飞。自身的目标没有被击破时，\\n\u3000中幅提升物理防御力，\\n\u3000小幅提升魔法防御力。\\n·对敌方全体造成魔法伤害（大），\\n\u3000并使其陷入冻结状态。\\n\u3000同时大幅降低其行动速度和\\n\u3000物理防御力。\\n·击破头部时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·击破躯体时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·战斗中，根据对至尊雪人施加的\\n\u3000状态异常效果和\\n\u3000属性值下降效果的数量，受到的\\n\u3000伤害也大幅提升。\\n');
insert into unit_enemy_data values (312205, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 20.0, 0, 0, 0, '【模式2】召唤在圣夜里兴致勃勃的3名女孩的\\n暗影。那是巨大雪不倒翁制作的幻象。\\n为了自己的名誉，现在就站起来吧，少女们！\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，\\n\u3000并将其大幅击飞。自身的目标没有被击破时，\\n\u3000中幅提升物理防御力，\\n\u3000小幅提升魔法防御力。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理比例伤害。自身的目标没有被击破时，\\n\u3000追加赋予眩晕效果。\\n·击破头部时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·击破躯体时，小幅降低其\\n\u3000物理防御力和魔法防御力。');
insert into unit_enemy_data values (312206, '至尊雪人', 312200, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式3】为了将所有的想法碾杀\\n而不断滚动的巨大雪不倒翁。向所有寂寞的人们，\\n温柔地送出爆炎的礼物给你?\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害，并大幅度\\n\u3000将其击飞。自身的目标没有被击破时，\\n\u3000中幅提升物理防御力，\\n\u3000小幅提升魔法防御力。\\n·根据角色的最大生命值，对敌方全体\\n\u3000造成物理比例伤害。自身的目标\\n\u3000没有被击破时，追加赋予\\n\u3000眩晕效果。\\n·剩余时间少于30秒时，会展开更为激烈凶暴的\\n\u3000攻击。\\n·剩余时间少于20秒时，会拿出礼物型炸弹，\\n\u3000过一段时间后，根据角色的最大生命值\\n\u3000对敌方全体造成\\n\u3000物理比例伤害。\\n\u3000并且也会根据至尊雪人自身剩余生命值\\n\u3000对其造成物理比例伤害，\\n\u3000大幅降低其技能值。\\n·击破头部时，小幅降低其\\n\u3000物理防御力和魔法防御力。\\n·击破躯体时，小幅降低其\\n\u3000物理防御力和魔法防御力。');
insert into unit_enemy_data values (312300, '巨大金枪鱼', 312300, 0, 16, 270, 3000, 1, 1.1, 0, 0, 0, '');
insert into unit_enemy_data values (312301, '巨大金枪鱼', 312300, 0, 16, 270, 3000, 1, 4.0, 0, 0, 0, '【物理】自古在大间的渔民之间传诵的梦幻巨鱼。\\n巨大的身躯极速的冲锋，让所有的船只都化为海里的渣滓。\\n但是，它身上的肉似乎是世间罕见的极品。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000并将其击退。');
insert into unit_enemy_data values (312302, '巨大金枪鱼', 312302, 0, 16, 270, 3000, 1, 3.3, 0, 0, 0, '【物理】自古在大间的渔民之间传诵的梦幻巨鱼。\\n巨大的身躯极速的冲锋，让所有的船只都化为海里的渣滓。\\n但是，它身上的肉似乎是世间罕见的极品。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000并将其击退。\\n·剩余时间少于35秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312303, '巨大金枪鱼', 312302, 0, 16, 270, 3000, 1, 1.1, 0, 0, 0, '【物理】自古在大间的渔民之间传诵的梦幻巨鱼。\\n巨大的身躯极速的冲锋，让所有的船只都化为海里的渣滓。\\n但是，它身上的肉似乎是世间罕见的极品。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000并将其击退。\\n·剩余时间少于35秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312304, '巨大金枪鱼', 312302, 0, 16, 270, 3000, 1, 0.0, 0, 0, 0, '【模式1】让无数渔民沉入波浪的海上之王。\\n金光闪闪的鱼鳍可以压断大渔船的龙骨。\\n那样子就像大海的解体秀一样\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000并将其击退。\\n·对前方范围内的所有敌人造成物理伤害（大），\\n\u3000并对后方2名角色造成\\n\u3000物理伤害（中）。同时提升自身的物理攻击力。');
insert into unit_enemy_data values (312305, '巨大金枪鱼', 312305, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '【模式2】在海里疾驰的怪鱼力量更大了。\\n游一下就像是在鼓舞自己一样，掀起巨大的旋涡，\\n化为分割大海的巨大炮弹猛攻敌人。\\n\\n·必杀技能会对前方3名角色造成\\n\u3000物理攻击（特大），\\n\u3000并将其击退。\\n·提升自身的物理攻击力、行动速度\\n\u3000和技能值。');
insert into unit_enemy_data values (312306, '巨大金枪鱼', 312302, 0, 16, 270, 3000, 1, 1.0, 0, 0, 0, '【模式3】即使无数次尝试用鱼叉叉住那黑色的巨大身体，\\n也无法阻挡传说中的巨鱼的猛冲。\\n与长久以来在海上奋斗的男儿们的决胜时刻到了。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n\u3000并将其击退。\\n·提升自身的物理攻击力、行动速度\\n\u3000和技能值。\\n·剩余时间少于35秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312400, '寒冰格里芬', 312400, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】展开冰翼，威吓冒险者的\\n大鹫。闯入地盘的人，\\n会被无情地冻住，成为孩子们的\\n祭品。\\n\\n·必杀技能会对前方小范围内\\n\u3000造成物理伤害（大），\\n\u3000并大幅度将其击飞，\\n\u3000使其陷入冻结状态。');
insert into unit_enemy_data values (312401, '寒冰格里芬', 312400, 0, 11, 270, 1000, 1, 1.6, 0, 0, 0, '【物理】展开冰翼，威吓冒险者的\\n大鹫。闯入地盘的人，\\n会被无情地冻住，成为孩子们的\\n祭品。\\n\\n·必杀技能会对前方小范围内\\n\u3000造成物理伤害（大），\\n\u3000并大幅度将其击飞，\\n\u3000使其陷入冻结状态。');
insert into unit_enemy_data values (312500, '厄勒克特拉夫人', 312500, 0, 6, 270, 1000, 2, 1.6, 0, 0, 0, '【魔法】积蓄塔的魔力转化为雷电释放的怪鸟。\\n与雷云一起出现，用天灾般的雷葬送敌人。\\n\\n·对敌方全体造成魔法伤害（大），并小幅提升\\n\u3000自身的魔法攻击力和行动速度。\\n\u3000对于进行物理攻击的敌人追加伤害。\\n·对前方范围内的所有敌人造成魔法伤害（中），\\n\u3000并中幅降低其物理防御力和魔法防御力。\\n·对物理攻击力最高的1名敌人造成\\n\u3000魔法伤害（大），使其长时间陷入麻痹状态。\\n\u3000自身的生命值低于85%时，对魔法攻击力\\n\u3000最高的敌人也进行此攻击。');
insert into unit_enemy_data values (312600, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '');
insert into unit_enemy_data values (312601, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】拥有漂亮麋角的大型魔物。用可以轻松粉碎大岩石的大角\\n把冒险者一扫而尽。\\n\\n·普通攻击时，以前方1名角色为中心，对一定范围内的角色造成\\n\u3000物理伤害（小）。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000并中幅降低自身的物理和\\n\u3000魔法防御力。\\n·对前方范围内造成物理伤害（中），使其\\n\u3000陷入眩晕。并大幅降低自身的\\n\u3000物理、魔法防御力。');
insert into unit_enemy_data values (312602, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】拥有漂亮麋角的大型魔物。用可以轻松粉碎大岩石的大角\\n把冒险者一扫而尽。\\n\\n·普通攻击时，以前方1名角色为中心，对一定范围内的角色造成\\n\u3000物理伤害（小）。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000并中幅降低自身的物理和\\n\u3000魔法防御力。\\n·对前方范围内造成物理伤害（中），使其\\n\u3000陷入眩晕。并大幅降低自身的\\n\u3000物理、魔法防御力。\\n·剩余时间少于25秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312603, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【物理】拥有漂亮麋角的大型魔物。用可以轻松粉碎大岩石的大角\\n把冒险者一扫而尽。\\n\\n·普通攻击时，以前方1名角色为中心，对一定范围内的角色造成\\n\u3000物理伤害（小）。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000并中幅降低自身的物理和\\n\u3000魔法防御力。\\n·对前方范围内造成物理伤害（中），使其\\n\u3000陷入眩晕。并大幅降低自身的\\n\u3000物理、魔法防御力。\\n·剩余时间少于25秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312604, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式1】首领的叫声使雄鹿们\\n成群涌来。能阻挡住奋不顾身的\\n冲锋吗？\\n\\n·战斗开始时，召唤3只野性角鹿，\\n\u3000并将其击退。\\n·每打倒1只野性角鹿，\\n\u3000剩下的野性角鹿数量就减少1只。\\n\u3000之后再次召唤野性角鹿，\\n\u3000并将其击退。\\n·普通攻击时，以前方1名角色为中心，对一定范围内的角色造成\\n\u3000物理伤害（小）。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000并中幅降低自身的物理和\\n\u3000魔法防御力。');
insert into unit_enemy_data values (312605, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式2】带着朽木魔物，\\n追击冒险者。一旦失去了共生的朽木，其身体也会\\n一同走向毁灭。消灭朽木是进攻的关键。\\n\\n·战斗开始时，召唤2只树精，\\n\u3000并将其击退。\\n·前方的树精的生命值变为0时，小幅降低碎岩角鹿的\\n\u3000物理、魔法防御力。\\n·后方的树精的生命值变为0时，\\n\u3000极大幅度降低碎岩角鹿的\\n\u3000物理、魔法防御力。\\n·普通攻击时，以前方1名角色为中心，对一定范围内的角色造成\\n\u3000物理伤害（小）。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000并中幅降低自身的物理和\\n\u3000魔法防御力。\\n·对前方范围内造成物理伤害（中），使其\\n\u3000陷入眩晕。并大幅降低自身的\\n\u3000物理、魔法防御力。');
insert into unit_enemy_data values (312606, '碎岩角鹿', 312600, 0, 16, 270, 3000, 1, 2.7, 0, 0, 0, '【模式3】受伤的角兽拼尽全力。\\n赌上性命的冲锋使身体变成闪电，如一道闪光\\n瓦解身经百战的冒险者一行人。\\n\\n·普通攻击时，以前方1名角色为中心，对一定范围内的角色造成\\n\u3000物理伤害（小）。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000并中幅降低自身的物理和\\n\u3000魔法防御力。\\n·对前方范围内造成物理伤害（中），使其\\n\u3000陷入眩晕。并大幅降低自身的\\n\u3000物理、魔法防御力。\\n·剩余时间少于25秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312700, '黑风的精灵', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '');
insert into unit_enemy_data values (312701, '黑风的精灵', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】测试使役者的真正力量的黑风精灵。\\n它没有恶意，纯粹是在考验隐藏在对方内心的\\n想法和羁绊。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。同时，\\n\u3000对剩余生命值最低的1名角色赋予倒计时，\\n\u30005秒后对其造成最大生命值80%的\\n\u3000魔法比例伤害。');
insert into unit_enemy_data values (312702, '黑风的精灵', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】测试使役者的真正力量的黑风精灵。\\n它没有恶意，纯粹是在考验隐藏在对方内心的\\n想法和羁绊。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。同时，\\n\u3000对剩余生命值最低的1名角色赋予倒计时，\\n\u30005秒后对其造成最大生命值80%的\\n\u3000魔法比例伤害。\\n·使敌方全体陷入猛毒状态，并大幅降低其\\n\u3000物理、魔法攻击力。\\n·剩余时间少于25秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312703, '黑风的精灵', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【魔法】测试使役者的真正力量的黑风精灵。\\n它没有恶意，纯粹是在考验隐藏在对方内心的\\n想法和羁绊。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。同时，\\n\u3000对剩余生命值最低的1名角色赋予倒计时，\\n\u30005秒后对其造成最大生命值80%的\\n\u3000魔法比例伤害。\\n·使敌方全体陷入猛毒状态，并大幅降低其\\n\u3000物理、魔法攻击力。\\n·剩余时间少于25秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312704, '黑风的精灵', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【模式1】第一试炼。只要能看清黑风精灵暴风的缝隙，\\n就能自然而然地开拓出\\n自己前进的道路。\\n\\n·对敌方全体造成物理伤害，使其眩晕\\n\u3000并将其击退。\\n\u3000黑风的精灵沉睡时，会大幅降低\\n\u3000自身的物理防御力，如果在此期间对其造成\\n\u3000100000以上的伤害，可延长其防御力降低的时间，\\n\u3000并降低其行动速度。');
insert into unit_enemy_data values (312705, '黑风的精灵', 312705, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【模式2】第二试炼。与自己软弱的内心\\n对峙吧。答案总是在自己心中。暂且相信同伴的力量，\\n去面对吧。\\n\\n·对前方2名角色造成物理伤害（小），\\n\u3000将其击退的同时使其眩晕。');
insert into unit_enemy_data values (312706, '黑风的精灵', 312700, 0, 16, 270, 3000, 2, 2.7, 0, 0, 0, '【模式3】第三试炼。最后的试炼，向赌上\\n一切的黑风的精灵展现真正的情感和羁绊，\\n确认自己的感情吧。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。同时，\\n\u3000对剩余生命值最低的1名角色赋予倒计时，\\n\u30005秒后对其造成最大生命值80%的\\n\u3000魔法比例伤害。\\n·使敌方全体陷入猛毒状态，并大幅降低其\\n\u3000物理、魔法攻击力。\\n·剩余时间少于25秒时，会展开更为激烈凶暴的\\n\u3000攻击。');
insert into unit_enemy_data values (312800, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '');
insert into unit_enemy_data values (312801, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】坐在边境城堡里的，孤高的魔物公主。\\n满怀悲哀的爱慕，击溃挑衅自己的人。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对前方2名角色造成物理比例伤害。\\n\u3000蓄力成功时，会提高伤害，\\n\u3000使敌方全体陷入畏惧状态。\\n\u3000陷入畏惧状态的角色，在一定时间内，\\n\u3000攻击及生命值回复的连结爆发\\n\u3000和技能效果降低。\\n·大幅降低物理防御力和魔法防御力后，\\n\u3000在一定时间内积蓄力量。\\n\u3000力量蓄满时，特大幅度回复技能值。\\n\u3000在蓄力期间，如果魔物公主受到\\n\u30007000以上的伤害，则蓄力失败，\\n\u3000技能值大幅降低。\\n·对眼前的1名敌人造成物理伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·根据最大生命值，对前方3名角色造成\\n\u3000物理比例伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。');
insert into unit_enemy_data values (312802, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】坐在边境城堡里的，孤高的魔物公主。\\n满怀悲哀的爱慕，击溃挑衅自己的人。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对前方2名角色造成物理比例伤害。\\n\u3000蓄力成功时，会提高伤害，\\n\u3000使敌方全体陷入畏惧状态。\\n\u3000陷入畏惧状态的角色，在一定时间内，\\n\u3000攻击及生命值回复的连结爆发\\n\u3000和技能效果降低。\\n·大幅降低物理防御力和魔法防御力后，\\n\u3000在一定时间内积蓄力量。\\n\u3000力量蓄满时，特大幅度回复技能值。\\n\u3000在蓄力期间，如果魔物公主受到\\n\u300021000以上的伤害，则蓄力失败，\\n\u3000技能值大幅降低。\\n·对眼前的1名敌人造成物理伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·根据最大生命值，对前方3名角色造成\\n\u3000物理比例伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。');
insert into unit_enemy_data values (312803, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【物理】坐在边境城堡里的，孤高的魔物公主。\\n满怀悲哀的爱慕，击溃挑衅自己的人。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对前方2名角色造成物理比例伤害。\\n\u3000蓄力成功时，会提高伤害，\\n\u3000使敌方全体陷入畏惧状态。\\n\u3000陷入畏惧状态的角色，在一定时间内，\\n\u3000攻击及生命值回复的连结爆发\\n\u3000和技能效果降低。\\n·大幅降低物理防御力和魔法防御力后，\\n\u3000在一定时间内积蓄力量。\\n\u3000力量蓄满时，特大幅度回复技能值。\\n\u3000在蓄力期间，如果魔物公主受到\\n\u3000260000以上的伤害，则蓄力失败，\\n\u3000技能值大幅降低。\\n·对眼前的1名敌人造成物理伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·根据最大生命值，对前方3名角色造成\\n\u3000物理比例伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n魔物公主自身的生命值低于25%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (312804, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式1】高洁的公主带领士兵\\n对抗敌人。仿佛在掩饰内心的叹息。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对前方2名角色造成物理比例伤害。\\n·对眼前的1名敌人造成物理伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·根据最大生命值，对前方3名角色造成\\n\u3000物理比例伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。');
insert into unit_enemy_data values (312805, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式2】公主释放出更大的力量。\\n用扭曲的强烈爱慕，拒绝一切，屠杀一切。\\n\\n·对来自敌人的攻击造成的麻痹、眩晕、束缚、冻结、\\n\u3000时间停止、行动速度降低效果\\n\u3000失去抗性。\\n·必杀技能会根据角色的最大生命值，\\n\u3000对前方2名角色造成物理比例伤害。\\n·对眼前的1名敌人造成物理伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·根据最大生命值，对前方3名角色造成\\n\u3000物理比例伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·短时间内变为无敌状态，解除敌方全体的属性值提升\\n\u3000效果后，在一定时间内展开\\n\u3000战斗领域。\\n\\n【战斗领域效果】\\n·敌方全体的物理攻击力和魔法攻击力降低100%后，\\n\u3000特大幅度提升\\n\u3000物理攻击力和魔法攻击力。\\n·特大幅度提升魔物公主的物理攻击力。');
insert into unit_enemy_data values (312806, '魔物公主', 312800, 0, 16, 270, 3000, 1, 1.8, 0, 0, 0, '【模式3】与莫大的悲哀相呼应，公主的进攻\\n极其猛烈。以少女的热情，\\n无法拯救那悲伤。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对前方2名角色造成物理比例伤害。\\n\u3000蓄力成功时，会提高伤害，\\n\u3000使敌方全体陷入畏惧状态。\\n\u3000陷入畏惧状态的角色，在一定时间内，\\n\u3000攻击及生命值回复的连结爆发\\n\u3000和技能效果降低。\\n·大幅降低物理防御力和魔法防御力后，\\n\u3000在一定时间内积蓄力量。\\n\u3000力量蓄满时，特大幅度回复技能值。\\n\u3000在蓄力期间，如果魔物公主受到\\n\u30001500000以上的伤害，则蓄力失败，\\n\u3000技能值大幅降低。\\n·对眼前的1名敌人造成物理伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n·根据最大生命值，对前方3名角色造成\\n\u3000物理比例伤害。\\n\u3000此攻击容易受到物理攻击力\\n\u3000提升或下降的影响。\\n魔物公主自身的生命值低于25%时，\\n\u3000会展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (312900, '黑月的守护石像', 312900, 0, 16, 270, 3000, 1, 2.5, 0, 0, 0, '【物理】守护天上圣域，被黑月祝福的雕像。\\n将闯入圣域的冒险者埋葬在黄泉的黑暗中。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成物理比例伤害。\\n·对敌方全体造成物理伤害（大），\\n\u3000并解除属性值提升效果。在伤害免疫的情况下，\\n\u3000该技能也会生效。\\n·大幅提升自身物理攻击力和\\n\u3000魔法攻击力。白阳的守护石像被讨伐时，\\n\u3000使用此技能。\\n·黑月的守护石像的生命值低于50%时，\\n\u3000大幅提升其物理攻击力，中幅提升其\\n\u3000物理防御力。\\n·黑月的守护石像被击破时，\\n\u3000小幅降低其物理防御力\\n\u3000和魔法防御力。\\n·白阳的守护石像被讨伐时，\\n\u3000战斗开始后，或是在黑月的守护石像进行\\n\u3000普通攻击时，改变黑月的守护石像的\\n\u3000攻击行动。');
insert into unit_enemy_data values (313000, '白阳的守护石像', 313000, 0, 16, 270, 3000, 2, 2.5, 0, 0, 0, '【物理】守护天上圣域，被白阳祝福的雕像。\\n用净化一切的白雷，审判冒险者。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n·对敌方全体造成魔法伤害（大），\\n\u3000并解除属性值提升效果。白阳的守护石像\\n\u3000大幅提升魔法攻击力。在伤害免疫的情况下，\\n\u3000该技能也会生效。黑月的\\n\u3000守护石像被讨伐时，使用\\n\u3000此技能。\\n·中幅提升我方全体的物理防御力和魔法\\n\u3000防御力。\\n·白阳的守护石像的生命值低于50%时，\\n\u3000特大幅度提升其魔法攻击力，小幅提升其\\n\u3000魔法防御力。\\n·白阳的守护石像被击破时，\\n\u3000小幅降低其物理防御力和魔法防御力。\\n·黑月的守护石像被讨伐时，\\n\u3000战斗开始后，或是在白阳的守护石像进行\\n\u3000普通攻击时，改变白阳的守护石像的\\n\u3000攻击行动。');
insert into unit_enemy_data values (313100, '爆裂·时间天秤', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '');
insert into unit_enemy_data values (313101, '爆裂·时间天秤', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】帆稀收藏的魔法道具，超越临界点\\n暴走时的样子。忘记了原本的任务，化身为引领冒险者\\n进入混沌的领航人。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并中幅降低其行动速度、\\n\u3000魔法防御力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅提升自身的魔法攻击力，大幅提升\\n\u3000行动速度。\\n·左侧目标处于击破状态时，\\n\u3000物理/魔法防御力中幅降低。\\n·中央下方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·中央上方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·右侧目标处于击破状态时，\\n\u3000物理/魔法防御力特大幅度降低。');
insert into unit_enemy_data values (313102, '爆裂·时间天秤', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】帆稀收藏的魔法道具，超越临界点\\n暴走时的样子。忘记了原本的任务，化身为引领冒险者\\n进入混沌的领航人。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并中幅降低其行动速度、\\n\u3000魔法防御力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅提升自身的魔法攻击力，大幅提升\\n\u3000行动速度。\\n·左侧目标处于击破状态时，\\n\u3000物理/魔法防御力中幅降低。\\n·中央下方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·中央上方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·右侧目标处于击破状态时，\\n\u3000物理/魔法防御力特大幅度降低。');
insert into unit_enemy_data values (313103, '爆裂·时间天秤', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【魔法】帆稀收藏的魔法道具，超越临界点\\n暴走时的样子。忘记了原本的任务，化身为引领冒险者\\n进入混沌的领航人。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并中幅降低其行动速度、\\n\u3000魔法防御力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅提升自身的魔法攻击力，大幅提升\\n\u3000行动速度。\\n·剩余时间少于25秒时，会大幅提升自身的技能值，\\n\u3000 并展开更为激烈凶暴的攻击。\\n·左侧目标处于击破状态时，\\n\u3000物理/魔法防御力中幅降低。\\n·中央下方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·中央上方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·右侧目标处于击破状态时，\\n\u3000物理/魔法防御力特大幅度降低。');
insert into unit_enemy_data values (313104, '爆裂·时间天秤', 313104, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【模式1】暴走的魔法道具想把所有的东西\\n留在自己的领域。不屈服于重重障碍，\\n相信自己，开拓未来。\\n\\n·此战斗中，所有目标\\n\u3000击破无效。\\n·展开屏障，完全防御敌人的攻击。\\n\u3000屏障在每次受到伤害时逐渐失去耐久性，\\n\u3000受到一定程度的伤害后\\n\u3000屏障就会破裂。\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并中幅降低其行动速度、\\n\u3000魔法防御力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅提升自身的魔法攻击力，大幅提升\\n\u3000行动速度。');
insert into unit_enemy_data values (313105, '爆裂·时间天秤', 313100, 0, 16, 270, 3000, 2, 1.4, 0, 0, 0, '【模式2】召唤祈梨和嘉夜的暗影。\\n从自己的「如果」的身影中，两个人看到了什么。\\n打破虚构，证明自己道路正确性的时候到了。\\n\\n·此战斗中，所有目标\\n\u3000击破无效。\\n·中幅提升自身的魔法攻击力，大幅提升\\n\u3000行动速度。');
insert into unit_enemy_data values (313106, '爆裂·时间天秤', 313100, 0, 16, 270, 3000, 2, 0.8, 0, 0, 0, '【模式3】失去了主人的魔法道具失去了控制，\\n持续暴走。只要坚持抵抗不断降临的绝望，\\n就会开辟出一条希望的光明之路。\\n\\n·必杀技能会对敌方全体造成魔法伤害（大），\\n\u3000并中幅降低其行动速度、\\n\u3000魔法防御力。\\n\u3000这个技能的异常状态在伤害免疫的情况下\\n\u3000也会成功赋予。\\n·中幅提升自身的魔法攻击力，大幅提升\\n\u3000行动速度。\\n·剩余时间少于25秒时，会大幅提升自身的技能值，\\n\u3000 并展开更为激烈凶暴的攻击。\\n·左侧目标处于击破状态时，\\n\u3000物理/魔法防御力中幅降低。\\n·中央下方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·中央上方目标处于击破状态时，\\n\u3000物理/魔法防御力大幅降低。\\n·右侧目标处于击破状态时，\\n\u3000物理/魔法防御力特大幅度降低。');
insert into unit_enemy_data values (313200, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '');
insert into unit_enemy_data values (313201, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】表现出了制作者的深渊？异形艺术作品的\\n魔物。据制作者称，以常人的尺度是无法理解\\n其风采的，懂的人才懂。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于50%时，\\n\u3000会使其陷入烧伤状态。\\n\u3000此技能赋予的烧伤伤害，\\n\u3000不会提升技能值。\\n·以前方第3名角色为中心，\\n\u3000根据最大生命值对一定范围内的角色造成物理比例伤害。\\n\u3000·必杀技能会根据最大生命值对陷入烧伤状态的角色\\n\u3000追加物理比例伤害。');
insert into unit_enemy_data values (313202, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】表现出了制作者的深渊？异形艺术作品的\\n魔物。据制作者称，以常人的尺度是无法理解\\n其风采的，懂的人才懂。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于50%时，\\n\u3000会使其陷入烧伤状态。\\n\u3000此技能赋予的烧伤伤害，\\n\u3000不会提升技能值。\\n·以前方第3名角色为中心，\\n\u3000根据最大生命值对一定范围内的角色造成物理比例伤害。\\n\u3000·必杀技能会根据最大生命值对陷入烧伤状态的角色\\n\u3000追加物理比例伤害。');
insert into unit_enemy_data values (313203, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【物理】表现出了制作者的深渊？异形艺术作品的\\n魔物。据制作者称，以常人的尺度是无法理解\\n其风采的，懂的人才懂。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于50%时，\\n\u3000会使其陷入烧伤状态。\\n\u3000此技能赋予的烧伤伤害，\\n\u3000不会提升技能值。\\n·以前方第3名角色为中心，\\n\u3000根据最大生命值对一定范围内的角色造成物理比例伤害。\\n\u3000·必杀技能会根据最大生命值对陷入烧伤状态的角色\\n\u3000追加物理比例伤害。\\n·剩余时间少于30秒时，会小幅提升自身的技能值，\\n\u3000 并展开更为激烈凶暴的攻击。');
insert into unit_enemy_data values (313204, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【模式1】拥有生命的黏土人偶不会停止。\\n释放出内在的异形魔力，\\n少女们和受过打击的校园能够承受住发出的光线吗？\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于50%时，\\n\u3000会使其陷入烧伤状态。\\n\u3000此技能赋予的烧伤伤害，\\n\u3000不会提升技能值。\\n·解除前方范围内敌人的屏障，根据最大生命值\\n\u3000对其造成魔法比例伤害。\\n\u3000并使其陷入束缚状态。\\n\u3000不过，无名艺术受到中毒、猛毒、诅咒、烧伤效果时，\\n\u3000不会对其赋予束缚效果。\\n·自身受到中毒、猛毒、诅咒、烧伤效果时，\\n\u3000特大幅度降低自己的物理、魔法防御力。');
insert into unit_enemy_data values (313205, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【模式2】黏土人偶所描绘的是\\n设计独到的魔法阵。不要被它的外表所欺骗，\\n稍不留神就会被瞬间压扁。\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于50%时，\\n\u3000会使其陷入烧伤状态。\\n\u3000此技能赋予的烧伤伤害，\\n\u3000不会提升技能值。\\n·普通攻击时，会对前方1名角色造成\\n\u3000物理伤害（中）。\\n\u3000无名艺术持有的【扇子】数越多，\\n\u3000造成的伤害就越高。\\n·以前方第3名角色为中心，\\n\u3000对一定范围的角色造成物理伤害（中）。\\n\u3000无名艺术持有的【扇子】数越多，\\n\u3000造成的伤害就越高。\\n·战斗开始时，展开魔法阵。\\n\\n【魔法阵效果】\\n·无名艺术每秒追加5个【扇子】。\\n·无名艺术每次受到伤害时，\\n\u3000无名艺术的【扇子】都会减少1个。');
insert into unit_enemy_data values (313206, '无名艺术', 313200, 0, 16, 270, 3000, 1, 2.0, 0, 0, 0, '【模式3】黏土人偶使出最后的力气，\\n散播最后的疯狂。她们光鲜亮丽的学生生活\\n能保住吗。站起来吧，好朋友社！\\n\\n·必杀技能会根据角色的最大生命值，\\n\u3000对敌方全体造成魔法比例伤害。\\n\u3000角色的生命值低于50%时，\\n\u3000会使其陷入烧伤状态。\\n\u3000此技能赋予的烧伤伤害，\\n\u3000不会提升技能值。\\n·以前方第3名角色为中心，\\n\u3000根据最大生命值对一定范围内的角色造成物理比例伤害。\\n\u3000·必杀技能会根据最大生命值对陷入烧伤状态的角色\\n\u3000追加物理比例伤害。\\n·剩余时间少于30秒时，会大幅度提升自身的技能值，\\n\u3000 并展开更为激烈凶暴的攻击。');
